window.KJV1769_STRONG_BOOKS["Prov"] = {"osis":"Prov","book":"잠언","verses":{"1:1":{"text":"The proverbs of Solomon the son of David, king of Israel;","words":[["H4912","The proverbs",0,12],["H8010","of Solomon",13,23],["H1121","the son",24,31],["H1732","of David",32,40],["H4428","king",42,46],["H3478","of Israel",47,56]]},"1:2":{"text":"To know wisdom and instruction; to perceive the words of understanding;","words":[["H3045","To know",0,7],["H2451","wisdom",8,14],["H4148","and instruction",15,30],["H0995","to perceive",32,43],["H0561","the words",44,53],["H0998","of understanding",54,70]]},"1:3":{"text":"To receive the instruction of wisdom, justice, and judgment, and equity;","words":[["H3947","To receive",0,10],["H4148","the instruction",11,26],["H7919","of wisdom",27,36],["H6664","justice",38,45],["H4941","and judgment",47,59],["H4339","and equity",61,71]]},"1:4":{"text":"To give subtilty to the simple, to the young man knowledge and discretion.","words":[["H5414","To give",0,7],["H6195","subtilty",8,16],["H6612","to the simple",17,30],["H5288","to the young man",32,48],["H1847","knowledge",49,58],["H4209","and discretion",59,73]]},"1:5":{"text":"A wise man will hear, and will increase learning; and a man of understanding shall attain unto wise counsels:","words":[["H2450","A wise",0,6],["H8085","man will hear",7,20],["H3254","and will increase",22,39],["H3948","learning",40,48],["H0995","and a man of understanding",50,76],["H7069","shall attain",77,89],["H8458","unto wise counsels",90,108]]},"1:6":{"text":"To understand a proverb, and the interpretation; the words of the wise, and their dark sayings.","words":[["H0995","To understand",0,13],["H4912","a proverb",14,23],["H4426","and the interpretation",25,47],["H1697","the words",49,58],["H2450","of the wise",59,70],["H2420","and their dark sayings",72,94]]},"1:7":{"text":"The fear of the LORD is the beginning of knowledge: but fools despise wisdom and instruction.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H7225","is the beginning",21,37],["H1847","of knowledge",38,50],["H0191","but fools",52,61],["H0936","despise",62,69],["H2451","wisdom",70,76],["H4148","and instruction",77,92]]},"1:8":{"text":"My son, hear the instruction of thy father, and forsake not the law of thy mother:","words":[["H1121","My son",0,6],["H8085","hear",8,12],["H4148","the instruction",13,28],["H0001","of thy father",29,42],["H5203","and forsake",44,55],["H8451","not the law",56,67],["H0517","of thy mother",68,81]]},"1:9":{"text":"For they shall be an ornament of grace unto thy head, and chains about thy neck.","words":[["H3880","For they shall be an ornament",0,29],["H2580","of grace",30,38],["H7218","unto thy head",39,52],["H6060","and chains",54,64],["H1621","about thy neck",65,79]]},"1:10":{"text":"My son, if sinners entice thee, consent thou not.","words":[["H1121","My son",0,6],["H2400","if sinners",8,18],["H6601","entice",19,25],["H0014","thee, consent",26,39]]},"1:11":{"text":"If they say, Come with us, let us lay wait for blood, let us lurk privily for the innocent without cause:","words":[["H0559","If they say",0,11],["H3212","Come",13,17],["H0693","with us, let us lay wait",18,42],["H1818","for blood",43,52],["H6845","let us lurk",54,65],["H5355","privily for the innocent",66,90],["H2600","without cause",91,104]]},"1:12":{"text":"Let us swallow them up alive as the grave; and whole, as those that go down into the pit:","words":[["H1104","Let us swallow them up",0,22],["H2416","alive",23,28],["H7585","as the grave",29,41],["H8549","and whole",43,52],["H3381","as those that go down",54,75],["H0953","into the pit",76,88]]},"1:13":{"text":"We shall find all precious substance, we shall fill our houses with spoil:","words":[["H4672","We shall find",0,13],["H3368","all precious",14,26],["H1952","substance",27,36],["H4390","we shall fill",38,51],["H1004","our houses",52,62],["H7998","with spoil",63,73]]},"1:14":{"text":"Cast in thy lot among us; let us all have one purse:","words":[["H5307","Cast",0,4],["H1486","in thy lot",5,15],["H8432","among",16,21],["H0259","us; let us all have one",22,45],["H3599","purse",46,51]]},"1:15":{"text":"My son, walk not thou in the way with them; refrain thy foot from their path:","words":[["H1121","My son",0,6],["H3212","walk",8,12],["H1870","not thou in the way",13,32],["H4513","with them; refrain",33,51],["H7272","thy foot",52,60],["H5410","from their path",61,76]]},"1:16":{"text":"For their feet run to evil, and make haste to shed blood.","words":[["H7272","For their feet",0,14],["H7323","run",15,18],["H7451","to evil",19,26],["H4116","and make haste",28,42],["H8210","to shed",43,50],["H1818","blood",51,56]]},"1:17":{"text":"Surely in vain the net is spread in the sight of any bird.","words":[["H2600","Surely in vain",0,14],["H7568","the net",15,22],["H2219","is spread",23,32],["H5869","in the sight",33,45],["H1167","of any bird",46,57],["H3671","of any bird",46,57]]},"1:18":{"text":"And they lay wait for their own blood; they lurk privily for their own lives.","words":[["H0693","And they lay wait",0,17],["H1818","for their own blood",18,37],["H6845","they lurk privily",39,56],["H5315","for their own lives",57,76]]},"1:19":{"text":"So are the ways of every one that is greedy of gain; which taketh away the life of the owners thereof.","words":[["H0734","So are the ways",0,15],["H1214","of every one that is greedy",16,43],["H1215","of gain",44,51],["H3947","which taketh away",53,70],["H5315","the life",71,79],["H1167","of the owners",80,93]]},"1:20":{"text":"Wisdom crieth without; she uttereth her voice in the streets:","words":[["H2454","Wisdom",0,6],["H7442","crieth",7,13],["H2351","without",14,21],["H5414","she uttereth",23,35],["H6963","her voice",36,45],["H7339","in the streets",46,60]]},"1:21":{"text":"She crieth in the chief place of concourse, in the openings of the gates: in the city she uttereth her words, saying,","words":[["H7121","She crieth",0,10],["H7218","in the chief place",11,29],["H1993","of concourse",30,42],["H6607","in the openings",44,59],["H8179","of the gates",60,72],["H5892","in the city",74,85],["H0559","she uttereth",86,98],["H0561","her words",99,108]]},"1:22":{"text":"How long, ye simple ones, will ye love simplicity? and the scorners delight in their scorning, and fools hate knowledge?","words":[["H6612","How long, ye simple ones",0,24],["H0157","will ye love",26,38],["H6612","simplicity",39,49],["H3887","and the scorners",51,67],["H2530","delight",68,75],["H3944","in their scorning",76,93],["H3684","and fools",95,104],["H8130","hate",105,109],["H1847","knowledge",110,119]]},"1:23":{"text":"Turn you at my reproof: behold, I will pour out my spirit unto you, I will make known my words unto you.","words":[["H7725","Turn",0,4],["H8433","you at my reproof",5,22],["H5042","behold, I will pour out",24,47],["H7307","my spirit",48,57],["H3045","unto you, I will make known",58,85],["H1697","my words",86,94]]},"1:24":{"text":"Because I have called, and ye refused; I have stretched out my hand, and no man regarded;","words":[["H7121","Because I have called",0,21],["H3985","and ye refused",23,37],["H5186","I have stretched out",39,59],["H3027","my hand",60,67],["H7181","and no man regarded",69,88]]},"1:25":{"text":"But ye have set at nought all my counsel, and would none of my reproof:","words":[["H6544","But ye have set at nought",0,25],["H6098","all my counsel",26,40],["H0014","and would",42,51],["H8433","none of my reproof",52,70]]},"1:26":{"text":"I also will laugh at your calamity; I will mock when your fear cometh;","words":[["H7832","I also will laugh",0,17],["H0343","at your calamity",18,34],["H3932","I will mock",36,47],["H6343","when your fear",48,62],["H0935","cometh",63,69]]},"1:27":{"text":"When your fear cometh as desolation, and your destruction cometh as a whirlwind; when distress and anguish cometh upon you.","words":[["H6343","When your fear",0,14],["H0935","cometh",15,21],["H7722","as desolation",22,35],["H7584","as desolation",22,35],["H0343","and your destruction",37,57],["H0857","cometh",58,64],["H5492","as a whirlwind",65,79],["H6869","when distress",81,94],["H6695","and anguish",95,106],["H0935","cometh",107,113]]},"1:28":{"text":"Then shall they call upon me, but I will not answer; they shall seek me early, but they shall not find me:","words":[["H7121","Then shall they call",0,20],["H6030","upon me, but I will not answer",21,51],["H7836","they shall seek me early",53,77],["H4672","but they shall not find",79,102]]},"1:29":{"text":"For that they hated knowledge, and did not choose the fear of the LORD:","words":[["H8130","For that they hated",0,19],["H1847","knowledge",20,29],["H0977","and did not choose",31,49],["H3374","the fear",50,58],["H3068","of the LORD",59,70]]},"1:30":{"text":"They would none of my counsel: they despised all my reproof.","words":[["H0014","They would",0,10],["H6098","none of my counsel",11,29],["H5006","they despised",31,44],["H8433","all my reproof",45,59]]},"1:31":{"text":"Therefore shall they eat of the fruit of their own way, and be filled with their own devices.","words":[["H0398","Therefore shall they eat",0,24],["H6529","of the fruit",25,37],["H1870","of their own way",38,54],["H7646","and be filled",56,69],["H4156","with their own devices",70,92]]},"1:32":{"text":"For the turning away of the simple shall slay them, and the prosperity of fools shall destroy them.","words":[["H4878","For the turning away",0,20],["H6612","of the simple",21,34],["H2026","shall slay",35,45],["H7962","them, and the prosperity",46,70],["H3684","of fools",71,79],["H0006","shall destroy",80,93]]},"1:33":{"text":"But whoso hearkeneth unto me shall dwell safely, and shall be quiet from fear of evil.","words":[["H8085","But whoso hearkeneth",0,20],["H7931","unto me shall dwell",21,40],["H0983","safely",41,47],["H7599","and shall be quiet",49,67],["H6343","from fear",68,77],["H7451","of evil",78,85]]},"2:1":{"text":"My son, if thou wilt receive my words, and hide my commandments with thee;","words":[["H1121","My son",0,6],["H3947","if thou wilt receive",8,28],["H0561","my words",29,37],["H6845","and hide",39,47],["H4687","my commandments",48,63]]},"2:2":{"text":"So that thou incline thine ear unto wisdom, and apply thine heart to understanding;","words":[["H7181","So that thou incline",0,20],["H0241","thine ear",21,30],["H2451","unto wisdom",31,42],["H5186","and apply",44,53],["H3820","thine heart",54,65],["H8394","to understanding",66,82]]},"2:3":{"text":"Yea, if thou criest after knowledge, and liftest up thy voice for understanding;","words":[["H7121","Yea, if thou criest",0,19],["H0998","after knowledge",20,35],["H5414","and liftest up",37,51],["H6963","thy voice",52,61],["H8394","for understanding",62,79]]},"2:4":{"text":"If thou seekest her as silver, and searchest for her as for hid treasures;","words":[["H1245","If thou seekest",0,15],["H3701","her as silver",16,29],["H2664","and searchest",31,44],["H4301","for her as for hid treasures",45,73]]},"2:5":{"text":"Then shalt thou understand the fear of the LORD, and find the knowledge of God.","words":[["H0995","Then shalt thou understand",0,26],["H3374","the fear",27,35],["H3068","of the LORD",36,47],["H4672","and find",49,57],["H1847","the knowledge",58,71],["H0430","of God",72,78]]},"2:6":{"text":"For the LORD giveth wisdom: out of his mouth cometh knowledge and understanding.","words":[["H3068","For the LORD",0,12],["H5414","giveth",13,19],["H2451","wisdom",20,26],["H6310","out of his mouth",28,44],["H1847","cometh knowledge",45,61],["H8394","and understanding",62,79]]},"2:7":{"text":"He layeth up sound wisdom for the righteous: he is a buckler to them that walk uprightly.","words":[["H6845","He layeth up",0,12],["H6845","He layeth up",0,12],["H8454","sound wisdom",13,25],["H3477","for the righteous",26,43],["H4043","he is a buckler",45,60],["H1980","to them that walk",61,78],["H8537","uprightly",79,88]]},"2:8":{"text":"He keepeth the paths of judgment, and preserveth the way of his saints.","words":[["H5341","He keepeth",0,10],["H0734","the paths",11,20],["H4941","of judgment",21,32],["H8104","and preserveth",34,48],["H1870","the way",49,56],["H2623","of his saints",57,70]]},"2:9":{"text":"Then shalt thou understand righteousness, and judgment, and equity; yea, every good path.","words":[["H0995","Then shalt thou understand",0,26],["H6664","righteousness",27,40],["H4941","and judgment",42,54],["H4339","and equity",56,66],["H2896","yea, every good",68,83],["H4570","path",84,88]]},"2:10":{"text":"When wisdom entereth into thine heart, and knowledge is pleasant unto thy soul;","words":[["H2451","When wisdom",0,11],["H0935","entereth",12,20],["H3820","into thine heart",21,37],["H1847","and knowledge",39,52],["H5276","is pleasant",53,64],["H5315","unto thy soul",65,78]]},"2:11":{"text":"Discretion shall preserve thee, understanding shall keep thee:","words":[["H4209","Discretion",0,10],["H8104","shall preserve",11,25],["H8394","thee, understanding",26,45],["H5341","shall keep",46,56]]},"2:12":{"text":"To deliver thee from the way of the evil man, from the man that speaketh froward things;","words":[["H5337","To deliver",0,10],["H1870","thee from the way",11,28],["H7451","of the evil",29,40],["H0376","man, from the man",41,58],["H1696","that speaketh",59,72],["H8419","froward things",73,87]]},"2:13":{"text":"Who leave the paths of uprightness, to walk in the ways of darkness;","words":[["H5800","Who leave",0,9],["H0734","the paths",10,19],["H3476","of uprightness",20,34],["H3212","to walk",36,43],["H1870","in the ways",44,55],["H2822","of darkness",56,67]]},"2:14":{"text":"Who rejoice to do evil, and delight in the frowardness of the wicked;","words":[["H8056","Who rejoice",0,11],["H6213","to do",12,17],["H7451","evil",18,22],["H1523","and delight",24,35],["H8419","in the frowardness",36,54],["H7451","of the wicked",55,68]]},"2:15":{"text":"Whose ways are crooked, and they froward in their paths:","words":[["H0734","Whose ways",0,10],["H6141","are crooked",11,22],["H3868","and they froward",24,40],["H4570","in their paths",41,55]]},"2:16":{"text":"To deliver thee from the strange woman, even from the stranger which flattereth with her words;","words":[["H5337","To deliver",0,10],["H2114","thee from the strange",11,32],["H0802","woman",33,38],["H5237","even from the stranger",40,62],["H2505","which flattereth",63,79],["H0561","with her words",80,94]]},"2:17":{"text":"Which forsaketh the guide of her youth, and forgetteth the covenant of her God.","words":[["H5800","Which forsaketh",0,15],["H0441","the guide",16,25],["H5271","of her youth",26,38],["H7911","and forgetteth",40,54],["H1285","the covenant",55,67],["H0430","of her God",68,78]]},"2:18":{"text":"For her house inclineth unto death, and her paths unto the dead.","words":[["H1004","For her house",0,13],["H7743","inclineth",14,23],["H4194","unto death",24,34],["H4570","and her paths",36,49],["H7496","unto the dead",50,63]]},"2:19":{"text":"None that go unto her return again, neither take they hold of the paths of life.","words":[["H0935","None that go",0,12],["H7725","unto her return again",13,34],["H5381","neither take they hold",36,58],["H0734","of the paths",59,71],["H2416","of life",72,79]]},"2:20":{"text":"That thou mayest walk in the way of good men, and keep the paths of the righteous.","words":[["H3212","That thou mayest walk",0,21],["H1870","in the way",22,32],["H2896","of good",33,40],["H8104","men, and keep",41,54],["H0734","the paths",55,64],["H6662","of the righteous",65,81]]},"2:21":{"text":"For the upright shall dwell in the land, and the perfect shall remain in it.","words":[["H3477","For the upright",0,15],["H7931","shall dwell",16,27],["H0776","in the land",28,39],["H8549","and the perfect",41,56],["H3498","shall remain",57,69]]},"2:22":{"text":"But the wicked shall be cut off from the earth, and the transgressors shall be rooted out of it.","words":[["H7563","But the wicked",0,14],["H3772","shall be cut off",15,31],["H0776","from the earth",32,46],["H0898","and the transgressors",48,69],["H5255","shall be rooted out",70,89]]},"3:1":{"text":"My son, forget not my law; but let thine heart keep my commandments:","words":[["H1121","My son",0,6],["H7911","forget",8,14],["H8451","not my law",15,25],["H3820","but let thine heart",27,46],["H5341","keep",47,51],["H4687","my commandments",52,67]]},"3:2":{"text":"For length of days, and long life, and peace, shall they add to thee.","words":[["H0753","For length",0,10],["H3117","of days",11,18],["H8141","and long",20,28],["H2416","life",29,33],["H7965","and peace",35,44],["H3254","shall they add",46,60]]},"3:3":{"text":"Let not mercy and truth forsake thee: bind them about thy neck; write them upon the table of thine heart:","words":[["H2617","Let not mercy",0,13],["H0571","and truth",14,23],["H5800","forsake",24,31],["H7194","thee: bind",32,42],["H1621","them about thy neck",43,62],["H3789","write",64,69],["H3871","them upon the table",70,89],["H3820","of thine heart",90,104]]},"3:4":{"text":"So shalt thou find favour and good understanding in the sight of God and man.","words":[["H4672","So shalt thou find",0,18],["H2580","favour",19,25],["H2896","and good",26,34],["H7922","understanding",35,48],["H5869","in the sight",49,61],["H0430","of God",62,68],["H0120","and man",69,76]]},"3:5":{"text":"Trust in the LORD with all thine heart; and lean not unto thine own understanding.","words":[["H0982","Trust",0,5],["H3068","in the LORD",6,17],["H3820","with all thine heart",18,38],["H8172","and lean",40,48],["H0998","not unto thine own understanding",49,81]]},"3:6":{"text":"In all thy ways acknowledge him, and he shall direct thy paths.","words":[["H1870","In all thy ways",0,15],["H3045","acknowledge",16,27],["H3474","him, and he shall direct",28,52],["H0734","thy paths",53,62]]},"3:7":{"text":"Be not wise in thine own eyes: fear the LORD, and depart from evil.","words":[["H2450","Be not wise",0,11],["H5869","in thine own eyes",12,29],["H3372","fear",31,35],["H3068","the LORD",36,44],["H5493","and depart",46,56],["H7451","from evil",57,66]]},"3:8":{"text":"It shall be health to thy navel, and marrow to thy bones.","words":[["H7500","It shall be health",0,18],["H8270","to thy navel",19,31],["H8250","and marrow",33,43],["H6106","to thy bones",44,56]]},"3:9":{"text":"Honour the LORD with thy substance, and with the firstfruits of all thine increase:","words":[["H3513","Honour",0,6],["H3068","the LORD",7,15],["H1952","with thy substance",16,34],["H7225","and with the firstfruits",36,60],["H8393","of all thine increase",61,82]]},"3:10":{"text":"So shall thy barns be filled with plenty, and thy presses shall burst out with new wine.","words":[["H0618","So shall thy barns",0,18],["H4390","be filled",19,28],["H7647","with plenty",29,40],["H3342","and thy presses",42,57],["H6555","shall burst out",58,73],["H8492","with new wine",74,87]]},"3:11":{"text":"My son, despise not the chastening of the LORD; neither be weary of his correction:","words":[["H1121","My son",0,6],["H3988","despise",8,15],["H4148","not the chastening",16,34],["H3068","of the LORD",35,46],["H6973","neither be weary",48,64],["H8433","of his correction",65,82]]},"3:12":{"text":"For whom the LORD loveth he correcteth; even as a father the son in whom he delighteth.","words":[["H3068","For whom the LORD",0,17],["H0157","loveth",18,24],["H3198","he correcteth",25,38],["H0001","even as a father",40,56],["H1121","the son",57,64],["H7521","in whom he delighteth",65,86]]},"3:13":{"text":"Happy is the man that findeth wisdom, and the man that getteth understanding.","words":[["H0835","Happy",0,5],["H0120","is the man",6,16],["H4672","that findeth",17,29],["H2451","wisdom",30,36],["H0120","and the man",38,49],["H6329","that getteth",50,62],["H8394","understanding",63,76]]},"3:14":{"text":"For the merchandise of it is better than the merchandise of silver, and the gain thereof than fine gold.","words":[["H5504","For the merchandise",0,19],["H2896","of it is better",20,35],["H5505","than the merchandise",36,56],["H3701","of silver",57,66],["H8393","and the gain",68,80],["H2742","thereof than fine gold",81,103]]},"3:15":{"text":"She is more precious than rubies: and all the things thou canst desire are not to be compared unto her.","words":[["H3368","She is more precious",0,20],["H6443","than rubies",21,32],["H2656","and all the things thou canst desire",34,70],["H7737","are not to be compared",71,93]]},"3:16":{"text":"Length of days is in her right hand; and in her left hand riches and honour.","words":[["H0753","Length",0,6],["H3117","of days",7,14],["H3225","is in her right hand",15,35],["H8040","and in her left hand",37,57],["H6239","riches",58,64],["H3519","and honour",65,75]]},"3:17":{"text":"Her ways are ways of pleasantness, and all her paths are peace.","words":[["H1870","Her ways",0,8],["H1870","are ways",9,17],["H5278","of pleasantness",18,33],["H5410","and all her paths",35,52],["H7965","are peace",53,62]]},"3:18":{"text":"She is a tree of life to them that lay hold upon her: and happy is every one that retaineth her.","words":[["H6086","She is a tree",0,13],["H2416","of life",14,21],["H2388","to them that lay hold",22,43],["H0833","upon her: and happy",44,63],["H8551","is every one that retaineth",64,91]]},"3:19":{"text":"The LORD by wisdom hath founded the earth; by understanding hath he established the heavens.","words":[["H3068","The LORD",0,8],["H2451","by wisdom",9,18],["H3245","hath founded",19,31],["H0776","the earth",32,41],["H8394","by understanding",43,59],["H3559","hath he established",60,79],["H8064","the heavens",80,91]]},"3:20":{"text":"By his knowledge the depths are broken up, and the clouds drop down the dew.","words":[["H1847","By his knowledge",0,16],["H8415","the depths",17,27],["H1234","are broken up",28,41],["H7834","and the clouds",43,57],["H7491","drop down",58,67],["H2919","the dew",68,75]]},"3:21":{"text":"My son, let not them depart from thine eyes: keep sound wisdom and discretion:","words":[["H1121","My son",0,6],["H3868","let not them depart",8,27],["H5869","from thine eyes",28,43],["H5341","keep",45,49],["H8454","sound wisdom",50,62],["H4209","and discretion",63,77]]},"3:22":{"text":"So shall they be life unto thy soul, and grace to thy neck.","words":[["H2416","So shall they be life",0,21],["H5315","unto thy soul",22,35],["H2580","and grace",37,46],["H1621","to thy neck",47,58]]},"3:23":{"text":"Then shalt thou walk in thy way safely, and thy foot shall not stumble.","words":[["H3212","Then shalt thou walk",0,20],["H1870","in thy way",21,31],["H0983","safely",32,38],["H7272","and thy foot",40,52],["H5062","shall not stumble",53,70]]},"3:24":{"text":"When thou liest down, thou shalt not be afraid: yea, thou shalt lie down, and thy sleep shall be sweet.","words":[["H7901","When thou liest down",0,20],["H6342","thou shalt not be afraid",22,46],["H7901","yea, thou shalt lie down",48,72],["H8142","and thy sleep",74,87],["H6149","shall be sweet",88,102]]},"3:25":{"text":"Be not afraid of sudden fear, neither of the desolation of the wicked, when it cometh.","words":[["H3372","Be not afraid",0,13],["H6597","of sudden",14,23],["H6343","fear",24,28],["H7722","neither of the desolation",30,55],["H7563","of the wicked",56,69],["H0935","when it cometh",71,85]]},"3:26":{"text":"For the LORD shall be thy confidence, and shall keep thy foot from being taken.","words":[["H3068","For the LORD",0,12],["H3689","shall be thy confidence",13,36],["H8104","and shall keep",38,52],["H7272","thy foot",53,61],["H3921","from being taken",62,78]]},"3:27":{"text":"Withhold not good from them to whom it is due, when it is in the power of thine hand to do it.","words":[["H4513","Withhold",0,8],["H2896","not good",9,17],["H1167","from them to whom it is due",18,45],["H0410","when it is in the power",47,70],["H3027","of thine hand",71,84],["H6213","to do",85,90]]},"3:28":{"text":"Say not unto thy neighbour, Go, and come again, and to morrow I will give; when thou hast it by thee.","words":[["H0559","Say",0,3],["H7453","not unto thy neighbour",4,26],["H3212","Go",28,30],["H7725","and come again",32,46],["H4279","and to morrow",48,61],["H5414","I will give",62,73],["H3426","when thou hast",75,89]]},"3:29":{"text":"Devise not evil against thy neighbour, seeing he dwelleth securely by thee.","words":[["H2790","Devise",0,6],["H7451","not evil",7,15],["H7453","against thy neighbour",16,37],["H3427","seeing he dwelleth",39,57],["H0983","securely",58,66]]},"3:30":{"text":"Strive not with a man without cause, if he have done thee no harm.","words":[["H7378","Strive",0,6],["H0120","not with a man",7,21],["H2600","without cause",22,35],["H1580","if he have done",37,52],["H7451","thee no harm",53,65]]},"3:31":{"text":"Envy thou not the oppressor, and choose none of his ways.","words":[["H7065","Envy",0,4],["H0376","thou not the oppressor",5,27],["H2555","thou not the oppressor",5,27],["H0977","and choose",29,39],["H1870","none of his ways",40,56]]},"3:32":{"text":"For the froward is abomination to the LORD: but his secret is with the righteous.","words":[["H3868","For the froward",0,15],["H8441","is abomination",16,30],["H3068","to the LORD",31,42],["H5475","but his secret",44,58],["H3477","is with the righteous",59,80]]},"3:33":{"text":"The curse of the LORD is in the house of the wicked: but he blesseth the habitation of the just.","words":[["H3994","The curse",0,9],["H3068","of the LORD",10,21],["H1004","is in the house",22,37],["H7563","of the wicked",38,51],["H1288","but he blesseth",53,68],["H5116","the habitation",69,83],["H6662","of the just",84,95]]},"3:34":{"text":"Surely he scorneth the scorners: but he giveth grace unto the lowly.","words":[["H3887","Surely he scorneth",0,18],["H3887","the scorners",19,31],["H5414","but he giveth",33,46],["H2580","grace",47,52],["H6035","unto the lowly",53,67],["H6041","unto the lowly",53,67]]},"3:35":{"text":"The wise shall inherit glory: but shame shall be the promotion of fools.","words":[["H2450","The wise",0,8],["H5157","shall inherit",9,22],["H3519","glory",23,28],["H7036","but shame",30,39],["H7311","shall be the promotion",40,62],["H3684","of fools",63,71]]},"4:1":{"text":"Hear, ye children, the instruction of a father, and attend to know understanding.","words":[["H8085","Hear",0,4],["H1121","ye children",6,17],["H4148","the instruction",19,34],["H0001","of a father",35,46],["H7181","and attend",48,58],["H3045","to know",59,66],["H0998","understanding",67,80]]},"4:2":{"text":"For I give you good doctrine, forsake ye not my law.","words":[["H5414","For I give",0,10],["H2896","you good",11,19],["H3948","doctrine",20,28],["H5800","forsake",30,37],["H8451","ye not my law",38,51]]},"4:3":{"text":"For I was my father's son, tender and only beloved in the sight of my mother.","words":[["H0001","For I was my father's",0,21],["H1121","son",22,25],["H7390","tender",27,33],["H3173","and only",34,42],["H6440","beloved in the sight",43,63],["H0517","of my mother",64,76]]},"4:4":{"text":"He taught me also, and said unto me, Let thine heart retain my words: keep my commandments, and live.","words":[["H3384","He taught",0,9],["H0559","me also, and said",10,27],["H3820","unto me, Let thine heart",28,52],["H8551","retain",53,59],["H1697","my words",60,68],["H8104","keep",70,74],["H4687","my commandments",75,90],["H2421","and live",92,100]]},"4:5":{"text":"Get wisdom, get understanding: forget it not; neither decline from the words of my mouth.","words":[["H7069","Get",0,3],["H2451","wisdom",4,10],["H7069","get",12,15],["H0998","understanding",16,29],["H7911","forget",31,37],["H5186","it not; neither decline",38,61],["H0561","from the words",62,76],["H6310","of my mouth",77,88]]},"4:6":{"text":"Forsake her not, and she shall preserve thee: love her, and she shall keep thee.","words":[["H5800","Forsake",0,7],["H8104","her not, and she shall preserve",8,39],["H0157","thee: love",40,50],["H5341","her, and she shall keep",51,74]]},"4:7":{"text":"Wisdom is the principal thing; therefore get wisdom: and with all thy getting get understanding.","words":[["H2451","Wisdom",0,6],["H7225","is the principal thing",7,29],["H7069","therefore get",31,44],["H2451","wisdom",45,51],["H7075","and with all thy getting",53,77],["H0998","get understanding",78,95]]},"4:8":{"text":"Exalt her, and she shall promote thee: she shall bring thee to honour, when thou dost embrace her.","words":[["H5549","Exalt",0,5],["H7311","her, and she shall promote",6,32],["H3513","thee: she shall bring thee to honour",33,69],["H2263","when thou dost embrace",71,93]]},"4:9":{"text":"She shall give to thine head an ornament of grace: a crown of glory shall she deliver to thee.","words":[["H5414","She shall give",0,14],["H7218","to thine head",15,28],["H3880","an ornament",29,40],["H2580","of grace",41,49],["H5850","a crown",51,58],["H8597","of glory",59,67],["H4042","shall she deliver",68,85]]},"4:10":{"text":"Hear, O my son, and receive my sayings; and the years of thy life shall be many.","words":[["H8085","Hear",0,4],["H1121","O my son",6,14],["H3947","and receive",16,27],["H0561","my sayings",28,38],["H8141","and the years",40,53],["H2416","of thy life",54,65],["H7235","shall be many",66,79]]},"4:11":{"text":"I have taught thee in the way of wisdom; I have led thee in right paths.","words":[["H3384","I have taught",0,13],["H1870","thee in the way",14,29],["H2451","of wisdom",30,39],["H1869","I have led",41,51],["H3476","thee in right",52,65],["H4570","paths",66,71]]},"4:12":{"text":"When thou goest, thy steps shall not be straitened; and when thou runnest, thou shalt not stumble.","words":[["H3212","When thou goest",0,15],["H6806","thy steps",17,26],["H3334","shall not be straitened",27,50],["H7323","and when thou runnest",52,73],["H3782","thou shalt not stumble",75,97]]},"4:13":{"text":"Take fast hold of instruction; let her not go: keep her; for she is thy life.","words":[["H2388","Take fast hold",0,14],["H4148","of instruction",15,29],["H7503","let her not go",31,45],["H5341","keep",47,51],["H2416","her; for she is thy life",52,76]]},"4:14":{"text":"Enter not into the path of the wicked, and go not in the way of evil men.","words":[["H0935","Enter",0,5],["H0734","not into the path",6,23],["H7563","of the wicked",24,37],["H0833","and go",39,45],["H1870","not in the way",46,60],["H7451","of evil",61,68]]},"4:15":{"text":"Avoid it, pass not by it, turn from it, and pass away.","words":[["H6544","Avoid",0,5],["H5674","it, pass",6,14],["H7847","not by it, turn",15,30],["H5674","from it, and pass away",31,53]]},"4:16":{"text":"For they sleep not, except they have done mischief; and their sleep is taken away, unless they cause some to fall.","words":[["H3462","For they sleep",0,14],["H7489","not, except they have done mischief",15,50],["H8142","and their sleep",52,67],["H1497","is taken away",68,81],["H3782","unless they cause some to fall",83,113],["H3782","unless they cause some to fall",83,113]]},"4:17":{"text":"For they eat the bread of wickedness, and drink the wine of violence.","words":[["H3898","For they eat",0,12],["H3899","the bread",13,22],["H7562","of wickedness",23,36],["H8354","and drink",38,47],["H3196","the wine",48,56],["H2555","of violence",57,68]]},"4:18":{"text":"But the path of the just is as the shining light, that shineth more and more unto the perfect day.","words":[["H0734","But the path",0,12],["H6662","of the just",13,24],["H5051","is as the shining",25,42],["H0216","light",43,48],["H0215","that shineth",50,62],["H1980","more",63,67],["H3559","and more unto the perfect",68,93],["H3117","day",94,97]]},"4:19":{"text":"The way of the wicked is as darkness: they know not at what they stumble.","words":[["H1870","The way",0,7],["H7563","of the wicked",8,21],["H0653","is as darkness",22,36],["H3045","they know",38,47],["H3782","not at what they stumble",48,72]]},"4:20":{"text":"My son, attend to my words; incline thine ear unto my sayings.","words":[["H1121","My son",0,6],["H7181","attend",8,14],["H1697","to my words",15,26],["H5186","incline",28,35],["H0241","thine ear",36,45],["H0561","unto my sayings",46,61]]},"4:21":{"text":"Let them not depart from thine eyes; keep them in the midst of thine heart.","words":[["H3868","Let them not depart",0,19],["H5869","from thine eyes",20,35],["H8104","keep",37,41],["H8432","them in the midst",42,59],["H3824","of thine heart",60,74]]},"4:22":{"text":"For they are life unto those that find them, and health to all their flesh.","words":[["H2416","For they are life",0,17],["H4672","unto those that find",18,38],["H4832","them, and health",39,55],["H1320","to all their flesh",56,74]]},"4:23":{"text":"Keep thy heart with all diligence; for out of it are the issues of life.","words":[["H5341","Keep",0,4],["H3820","thy heart",5,14],["H4929","with all diligence",15,33],["H8444","for out of it are the issues",35,63],["H2416","of life",64,71]]},"4:24":{"text":"Put away from thee a froward mouth, and perverse lips put far from thee.","words":[["H5493","Put away",0,8],["H6143","from thee a froward",9,28],["H6310","mouth",29,34],["H3891","and perverse",36,48],["H8193","lips",49,53],["H7368","put far",54,61]]},"4:25":{"text":"Let thine eyes look right on, and let thine eyelids look straight before thee.","words":[["H5869","Let thine eyes",0,14],["H5027","look",15,19],["H5227","right on",20,28],["H6079","and let thine eyelids",30,51],["H3474","look straight",52,65]]},"4:26":{"text":"Ponder the path of thy feet, and let all thy ways be established.","words":[["H6424","Ponder",0,6],["H4570","the path",7,15],["H7272","of thy feet",16,27],["H1870","and let all thy ways",29,49],["H3559","be established",50,64]]},"4:27":{"text":"Turn not to the right hand nor to the left: remove thy foot from evil.","words":[["H5186","Turn",0,4],["H3225","not to the right hand",5,26],["H8040","nor to the left",27,42],["H5493","remove",44,50],["H7272","thy foot",51,59],["H7451","from evil",60,69]]},"5:1":{"text":"My son, attend unto my wisdom, and bow thine ear to my understanding:","words":[["H1121","My son",0,6],["H7181","attend",8,14],["H2451","unto my wisdom",15,29],["H5186","and bow",31,38],["H0241","thine ear",39,48],["H8394","to my understanding",49,68]]},"5:2":{"text":"That thou mayest regard discretion, and that thy lips may keep knowledge.","words":[["H8104","That thou mayest regard",0,23],["H4209","discretion",24,34],["H8193","and that thy lips",36,53],["H5341","may keep",54,62],["H1847","knowledge",63,72]]},"5:3":{"text":"For the lips of a strange woman drop as an honeycomb, and her mouth is smoother than oil:","words":[["H8193","For the lips",0,12],["H2114","of a strange woman",13,31],["H5197","drop",32,36],["H5317","as an honeycomb",37,52],["H2441","and her mouth",54,67],["H2509","is smoother",68,79],["H8081","than oil",80,88]]},"5:4":{"text":"But her end is bitter as wormwood, sharp as a twoedged sword.","words":[["H0319","But her end",0,11],["H4751","is bitter",12,21],["H3939","as wormwood",22,33],["H2299","sharp",35,40],["H6310","as a twoedged",41,54],["H2719","sword",55,60]]},"5:5":{"text":"Her feet go down to death; her steps take hold on hell.","words":[["H7272","Her feet",0,8],["H3381","go down",9,16],["H4194","to death",17,25],["H6806","her steps",27,36],["H8551","take hold",37,46],["H7585","on hell",47,54]]},"5:6":{"text":"Lest thou shouldest ponder the path of life, her ways are moveable, that thou canst not know them.","words":[["H6424","Lest thou shouldest ponder",0,26],["H0734","the path",27,35],["H2416","of life",36,43],["H4570","her ways",45,53],["H5128","are moveable",54,66],["H3045","that thou canst not know",68,92]]},"5:7":{"text":"Hear me now therefore, O ye children, and depart not from the words of my mouth.","words":[["H8085","Hear",0,4],["H1121","me now therefore, O ye children",5,36],["H5493","and depart",38,48],["H0561","not from the words",49,67],["H6310","of my mouth",68,79]]},"5:8":{"text":"Remove thy way far from her, and come not nigh the door of her house:","words":[["H7368","Remove",0,6],["H1870","thy way",7,14],["H7368","far",15,18],["H7126","from her, and come not nigh",19,46],["H6607","the door",47,55],["H1004","of her house",56,68]]},"5:9":{"text":"Lest thou give thine honour unto others, and thy years unto the cruel:","words":[["H5414","Lest thou give",0,14],["H1935","thine honour",15,27],["H0312","unto others",28,39],["H8141","and thy years",41,54],["H0394","unto the cruel",55,69]]},"5:10":{"text":"Lest strangers be filled with thy wealth; and thy labours be in the house of a stranger;","words":[["H2114","Lest strangers",0,14],["H7646","be filled",15,24],["H3581","with thy wealth",25,40],["H6089","and thy labours",42,57],["H1004","be in the house",58,73],["H5237","of a stranger",74,87]]},"5:11":{"text":"And thou mourn at the last, when thy flesh and thy body are consumed,","words":[["H5098","And thou mourn",0,14],["H0319","at the last",15,26],["H1320","when thy flesh",28,42],["H7607","and thy body",43,55],["H3615","are consumed",56,68]]},"5:12":{"text":"And say, How have I hated instruction, and my heart despised reproof;","words":[["H0559","And say",0,7],["H8130","How have I hated",9,25],["H4148","instruction",26,37],["H3820","and my heart",39,51],["H5006","despised",52,60],["H8433","reproof",61,68]]},"5:13":{"text":"And have not obeyed the voice of my teachers, nor inclined mine ear to them that instructed me!","words":[["H8085","And have not obeyed",0,19],["H6963","the voice",20,29],["H3384","of my teachers",30,44],["H5186","nor inclined",46,58],["H0241","mine ear",59,67],["H3925","to them that instructed",68,91]]},"5:14":{"text":"I was almost in all evil in the midst of the congregation and assembly.","words":[["H4592","I was almost",0,12],["H7451","in all evil",13,24],["H8432","in the midst",25,37],["H6951","of the congregation",38,57],["H5712","and assembly",58,70]]},"5:15":{"text":"Drink waters out of thine own cistern, and running waters out of thine own well.","words":[["H8354","Drink",0,5],["H4325","waters",6,12],["H0953","out of thine own cistern",13,37],["H5140","and running waters",39,57],["H8432","out of",58,64],["H0875","thine own well",65,79]]},"5:16":{"text":"Let thy fountains be dispersed abroad, and rivers of waters in the streets.","words":[["H4599","Let thy fountains",0,17],["H6327","be dispersed",18,30],["H2351","abroad",31,37],["H6388","and rivers",39,49],["H4325","of waters",50,59],["H7339","in the streets",60,74]]},"5:17":{"text":"Let them be only thine own, and not strangers' with thee.","words":[["H2114","Let them be only thine own, and not strangers'",0,46]]},"5:18":{"text":"Let thy fountain be blessed: and rejoice with the wife of thy youth.","words":[["H4726","Let thy fountain",0,16],["H1288","be blessed",17,27],["H8055","and rejoice",29,40],["H0802","with the wife",41,54],["H5271","of thy youth",55,67]]},"5:19":{"text":"Let her be as the loving hind and pleasant roe; let her breasts satisfy thee at all times; and be thou ravished always with her love.","words":[["H0158","Let her be as the loving",0,24],["H0365","hind",25,29],["H2580","and pleasant",30,42],["H3280","roe",43,46],["H1717","let her breasts",48,63],["H7301","satisfy",64,71],["H6256","thee at all times",72,89],["H7686","and be thou ravished",91,111],["H8548","always",112,118],["H0160","with her love",119,132]]},"5:20":{"text":"And why wilt thou, my son, be ravished with a strange woman, and embrace the bosom of a stranger?","words":[["H1121","And why wilt thou, my son",0,25],["H7686","be ravished",27,38],["H2114","with a strange woman",39,59],["H2263","and embrace",61,72],["H2436","the bosom",73,82],["H5237","of a stranger",83,96]]},"5:21":{"text":"For the ways of man are before the eyes of the LORD, and he pondereth all his goings.","words":[["H1870","For the ways",0,12],["H0376","of man",13,19],["H5227","are before",20,30],["H5869","the eyes",31,39],["H3068","of the LORD",40,51],["H6424","and he pondereth",53,69],["H4570","all his goings",70,84]]},"5:22":{"text":"His own iniquities shall take the wicked himself, and he shall be holden with the cords of his sins.","words":[["H5771","His own iniquities",0,18],["H3920","shall take",19,29],["H7563","the wicked",30,40],["H8551","himself, and he shall be holden",41,72],["H2256","with the cords",73,87],["H2403","of his sins",88,99]]},"5:23":{"text":"He shall die without instruction; and in the greatness of his folly he shall go astray.","words":[["H4191","He shall die",0,12],["H4148","without instruction",13,32],["H7230","and in the greatness",34,54],["H0200","of his folly",55,67],["H7686","he shall go astray",68,86]]},"6:1":{"text":"My son, if thou be surety for thy friend, if thou hast stricken thy hand with a stranger,","words":[["H1121","My son",0,6],["H6148","if thou be surety",8,25],["H7453","for thy friend",26,40],["H8628","if thou hast stricken",42,63],["H3709","thy hand",64,72],["H2114","with a stranger",73,88]]},"6:2":{"text":"Thou art snared with the words of thy mouth, thou art taken with the words of thy mouth.","words":[["H3369","Thou art snared",0,15],["H0561","with the words",16,30],["H6310","of thy mouth",31,43],["H3920","thou art taken",45,59],["H0561","with the words",60,74],["H6310","of thy mouth",75,87]]},"6:3":{"text":"Do this now, my son, and deliver thyself, when thou art come into the hand of thy friend; go, humble thyself, and make sure thy friend.","words":[["H6213","Do",0,2],["H0645","this now",3,11],["H1121","my son",13,19],["H5337","and deliver",21,32],["H0935","thyself, when thou art come",33,60],["H3709","into the hand",61,74],["H7453","of thy friend",75,88],["H3212","go",90,92],["H7511","humble",94,100],["H7292","thyself, and make sure",101,123],["H7453","thy friend",124,134]]},"6:4":{"text":"Give not sleep to thine eyes, nor slumber to thine eyelids.","words":[["H5414","Give",0,4],["H8142","not sleep",5,14],["H5869","to thine eyes",15,28],["H8572","nor slumber",30,41],["H6079","to thine eyelids",42,58]]},"6:5":{"text":"Deliver thyself as a roe from the hand of the hunter, and as a bird from the hand of the fowler.","words":[["H5337","Deliver",0,7],["H6643","thyself as a roe",8,24],["H3027","from the hand",25,38],["H6833","of the hunter, and as a bird",39,67],["H3027","from the hand",68,81],["H3353","of the fowler",82,95]]},"6:6":{"text":"Go to the ant, thou sluggard; consider her ways, and be wise:","words":[["H3212","Go",0,2],["H5244","to the ant",3,13],["H6102","thou sluggard",15,28],["H7200","consider",30,38],["H1870","her ways",39,47],["H2449","and be wise",49,60]]},"6:7":{"text":"Which having no guide, overseer, or ruler,","words":[["H7101","Which having no guide",0,21],["H7860","overseer",23,31],["H4910","or ruler",33,41]]},"6:8":{"text":"Provideth her meat in the summer, and gathereth her food in the harvest.","words":[["H3559","Provideth",0,9],["H3899","her meat",10,18],["H7019","in the summer",19,32],["H0103","and gathereth",34,47],["H3978","her food",48,56],["H7105","in the harvest",57,71]]},"6:9":{"text":"How long wilt thou sleep, O sluggard? when wilt thou arise out of thy sleep?","words":[["H7901","How long wilt thou sleep",0,24],["H6102","O sluggard",26,36],["H6965","when wilt thou arise",38,58],["H8142","out of thy sleep",59,75]]},"6:10":{"text":"Yet a little sleep, a little slumber, a little folding of the hands to sleep:","words":[["H4592","Yet a little",0,12],["H8142","sleep",13,18],["H4592","a little",20,28],["H8572","slumber",29,36],["H4592","a little",38,46],["H2264","folding",47,54],["H3027","of the hands",55,67],["H7901","to sleep",68,76]]},"6:11":{"text":"So shall thy poverty come as one that travelleth, and thy want as an armed man.","words":[["H7389","So shall thy poverty",0,20],["H0935","come",21,25],["H1980","as one that travelleth",26,48],["H4270","and thy want",50,62],["H4043","as an armed",63,74],["H0376","man",75,78]]},"6:12":{"text":"A naughty person, a wicked man, walketh with a froward mouth.","words":[["H1100","A naughty",0,9],["H0120","person",10,16],["H0205","a wicked",18,26],["H0376","man",27,30],["H1980","walketh",32,39],["H6143","with a froward",40,54],["H6310","mouth",55,60]]},"6:13":{"text":"He winketh with his eyes, he speaketh with his feet, he teacheth with his fingers;","words":[["H7169","He winketh",0,10],["H5869","with his eyes",11,24],["H4448","he speaketh",26,37],["H7272","with his feet",38,51],["H3384","he teacheth",53,64],["H0676","with his fingers",65,81]]},"6:14":{"text":"Frowardness is in his heart, he deviseth mischief continually; he soweth discord.","words":[["H8419","Frowardness",0,11],["H3820","is in his heart",12,27],["H2790","he deviseth",29,40],["H7451","mischief",41,49],["H6256","continually",50,61],["H7971","he soweth",63,72],["H4066","discord",73,80],["H4090","discord",73,80]]},"6:15":{"text":"Therefore shall his calamity come suddenly; suddenly shall he be broken without remedy.","words":[["H0343","Therefore shall his calamity",0,28],["H0935","come",29,33],["H6597","suddenly",34,42],["H6621","suddenly",44,52],["H7665","shall he be broken",53,71],["H4832","without remedy",72,86]]},"6:16":{"text":"These six things doth the LORD hate: yea, seven are an abomination unto him:","words":[["H8337","These six",0,9],["H3068","things doth the LORD",10,30],["H8130","hate",31,35],["H7651","yea, seven",37,47],["H8441","are an abomination",48,66],["H5315","unto him",67,75]]},"6:17":{"text":"A proud look, a lying tongue, and hands that shed innocent blood,","words":[["H7311","A proud",0,7],["H5869","look",8,12],["H8267","a lying",14,21],["H3956","tongue",22,28],["H3027","and hands",30,39],["H8210","that shed",40,49],["H5355","innocent",50,58],["H1818","blood",59,64]]},"6:18":{"text":"An heart that deviseth wicked imaginations, feet that be swift in running to mischief,","words":[["H3820","An heart",0,8],["H2790","that deviseth",9,22],["H0205","wicked",23,29],["H4284","imaginations",30,42],["H7272","feet",44,48],["H4116","that be swift",49,62],["H7323","in running",63,73],["H7451","to mischief",74,85]]},"6:19":{"text":"A false witness that speaketh lies, and he that soweth discord among brethren.","words":[["H8267","A false",0,7],["H5707","witness",8,15],["H6315","that speaketh",16,29],["H3577","lies",30,34],["H7971","and he that soweth",36,54],["H4090","discord",55,62],["H0251","among brethren",63,77]]},"6:20":{"text":"My son, keep thy father's commandment, and forsake not the law of thy mother:","words":[["H1121","My son",0,6],["H5341","keep",8,12],["H0001","thy father's",13,25],["H4687","commandment",26,37],["H5203","and forsake",39,50],["H8451","not the law",51,62],["H0517","of thy mother",63,76]]},"6:21":{"text":"Bind them continually upon thine heart, and tie them about thy neck.","words":[["H7194","Bind",0,4],["H8548","them continually",5,21],["H3820","upon thine heart",22,38],["H6029","and tie",40,47],["H1621","them about thy neck",48,67]]},"6:22":{"text":"When thou goest, it shall lead thee; when thou sleepest, it shall keep thee; and when thou awakest, it shall talk with thee.","words":[["H1980","When thou goest",0,15],["H5148","it shall lead",17,30],["H7901","thee; when thou sleepest",31,55],["H8104","it shall keep",57,70],["H6974","thee; and when thou awakest",71,98],["H7878","it shall talk",100,113]]},"6:23":{"text":"For the commandment is a lamp; and the law is light; and reproofs of instruction are the way of life:","words":[["H4687","For the commandment",0,19],["H5216","is a lamp",20,29],["H8451","and the law",31,42],["H0216","is light",43,51],["H8433","and reproofs",53,65],["H4148","of instruction",66,80],["H1870","are the way",81,92],["H2416","of life",93,100]]},"6:24":{"text":"To keep thee from the evil woman, from the flattery of the tongue of a strange woman.","words":[["H8104","To keep",0,7],["H7451","thee from the evil",8,26],["H0802","woman",27,32],["H2513","from the flattery",34,51],["H3956","of the tongue",52,65],["H5237","of a strange woman",66,84]]},"6:25":{"text":"Lust not after her beauty in thine heart; neither let her take thee with her eyelids.","words":[["H2530","Lust",0,4],["H3308","not after her beauty",5,25],["H3824","in thine heart",26,40],["H3947","neither let her take",42,62],["H6079","thee with her eyelids",63,84]]},"6:26":{"text":"For by means of a whorish woman a man is brought to a piece of bread: and the adulteress will hunt for the precious life.","words":[["H1157","For by means of",0,15],["H2181","a whorish",16,25],["H0802","woman",26,31],["H3603","a man is brought to a piece",32,59],["H3899","of bread",60,68],["H0802","and the adulteress",70,88],["H0376","and the adulteress",70,88],["H6679","will hunt",89,98],["H3368","for the precious",99,115],["H5315","life",116,120]]},"6:27":{"text":"Can a man take fire in his bosom, and his clothes not be burned?","words":[["H0376","Can a man",0,9],["H2846","take",10,14],["H0784","fire",15,19],["H2436","in his bosom",20,32],["H0899","and his clothes",34,49],["H8313","not be burned",50,63]]},"6:28":{"text":"Can one go upon hot coals, and his feet not be burned?","words":[["H0376","Can one",0,7],["H1980","go",8,10],["H1513","upon hot coals",11,25],["H7272","and his feet",27,39],["H3554","not be burned",40,53]]},"6:29":{"text":"So he that goeth in to his neighbour's wife; whosoever toucheth her shall not be innocent.","words":[["H0935","So he that goeth in",0,19],["H7453","to his neighbour's",20,38],["H0802","wife",39,43],["H5060","whosoever toucheth",45,63],["H5352","her shall not be innocent",64,89]]},"6:30":{"text":"Men do not despise a thief, if he steal to satisfy his soul when he is hungry;","words":[["H0936","Men do not despise",0,18],["H1590","a thief",19,26],["H1589","if he steal",28,39],["H4390","to satisfy",40,50],["H5315","his soul",51,59],["H7456","when he is hungry",60,77]]},"6:31":{"text":"But if he be found, he shall restore sevenfold; he shall give all the substance of his house.","words":[["H4672","But if he be found",0,18],["H7999","he shall restore",20,36],["H7659","sevenfold",37,46],["H5414","he shall give",48,61],["H1952","all the substance",62,79],["H1004","of his house",80,92]]},"6:32":{"text":"But whoso committeth adultery with a woman lacketh understanding: he that doeth it destroyeth his own soul.","words":[["H5003","But whoso committeth adultery",0,29],["H0802","with a woman",30,42],["H2638","lacketh",43,50],["H3820","understanding",51,64],["H6213","he that doeth",66,79],["H7843","it destroyeth",80,93],["H5315","his own soul",94,106]]},"6:33":{"text":"A wound and dishonour shall he get; and his reproach shall not be wiped away.","words":[["H5061","A wound",0,7],["H7036","and dishonour",8,21],["H4672","shall he get",22,34],["H2781","and his reproach",36,52],["H4229","shall not be wiped away",53,76]]},"6:34":{"text":"For jealousy is the rage of a man: therefore he will not spare in the day of vengeance.","words":[["H7068","For jealousy",0,12],["H2534","is the rage",13,24],["H1397","of a man",25,33],["H2550","therefore he will not spare",35,62],["H3117","in the day",63,73],["H5359","of vengeance",74,86]]},"6:35":{"text":"He will not regard any ransom; neither will he rest content, though thou givest many gifts.","words":[["H5375","He will not regard",0,18],["H6440","He will not regard",0,18],["H3724","any ransom",19,29],["H0014","neither will he rest content",31,59],["H7235","though thou givest many",61,84],["H7810","gifts",85,90]]},"7:1":{"text":"My son, keep my words, and lay up my commandments with thee.","words":[["H1121","My son",0,6],["H8104","keep",8,12],["H0561","my words",13,21],["H6845","and lay up",23,33],["H4687","my commandments",34,49]]},"7:2":{"text":"Keep my commandments, and live; and my law as the apple of thine eye.","words":[["H8104","Keep",0,4],["H4687","my commandments",5,20],["H2421","and live",22,30],["H8451","and my law",32,42],["H0380","as the apple",43,55],["H5869","of thine eye",56,68]]},"7:3":{"text":"Bind them upon thy fingers, write them upon the table of thine heart.","words":[["H7194","Bind",0,4],["H0676","them upon thy fingers",5,26],["H3789","write",28,33],["H3871","them upon the table",34,53],["H3820","of thine heart",54,68]]},"7:4":{"text":"Say unto wisdom, Thou art my sister; and call understanding thy kinswoman:","words":[["H0559","Say",0,3],["H2451","unto wisdom",4,15],["H0269","Thou art my sister",17,35],["H7121","and call",37,45],["H0998","understanding",46,59],["H4129","thy kinswoman",60,73]]},"7:5":{"text":"That they may keep thee from the strange woman, from the stranger which flattereth with her words.","words":[["H8104","That they may keep",0,18],["H2114","thee from the strange",19,40],["H0802","woman",41,46],["H5237","from the stranger",48,65],["H2505","which flattereth",66,82],["H0561","with her words",83,97]]},"7:6":{"text":"For at the window of my house I looked through my casement,","words":[["H2474","For at the window",0,17],["H1004","of my house",18,29],["H8259","I looked",30,38],["H0822","through my casement",39,58]]},"7:7":{"text":"And beheld among the simple ones, I discerned among the youths, a young man void of understanding,","words":[["H7200","And beheld",0,10],["H6612","among the simple ones",11,32],["H0995","I discerned",34,45],["H1121","among the youths",46,62],["H5288","a young man",64,75],["H2638","void",76,80],["H3820","of understanding",81,97]]},"7:8":{"text":"Passing through the street near her corner; and he went the way to her house,","words":[["H5674","Passing through",0,15],["H7784","the street",16,26],["H0681","near",27,31],["H6434","her corner",32,42],["H6805","and he went",44,55],["H1870","the way",56,63],["H1004","to her house",64,76]]},"7:9":{"text":"In the twilight, in the evening, in the black and dark night:","words":[["H5399","In the twilight",0,15],["H3117","in the evening",17,31],["H6153","in the evening",17,31],["H0380","in the black",33,45],["H0653","and dark",46,54],["H3915","night",55,60]]},"7:10":{"text":"And, behold, there met him a woman with the attire of an harlot, and subtil of heart.","words":[["H7125","And, behold, there met",0,22],["H0802","him a woman",23,34],["H7897","with the attire",35,50],["H2181","of an harlot",51,63],["H5341","and subtil",65,75],["H3820","of heart",76,84]]},"7:11":{"text":"(She is loud and stubborn; her feet abide not in her house:","words":[["H1993","(She is loud",0,12],["H5637","and stubborn",13,25],["H7272","her feet",27,35],["H7931","abide",36,41],["H1004","not in her house",42,58]]},"7:12":{"text":"Now is she without, now in the streets, and lieth in wait at every corner.)","words":[["H6471","Now",0,3],["H2351","is she without",4,18],["H6471","now",20,23],["H7339","in the streets",24,38],["H0693","and lieth in wait",40,57],["H0681","at",58,60],["H6438","every corner",61,73]]},"7:13":{"text":"So she caught him, and kissed him, and with an impudent face said unto him,","words":[["H2388","So she caught",0,13],["H5401","him, and kissed",14,29],["H5810","him, and with an impudent",30,55],["H6440","face",56,60],["H0559","said",61,65]]},"7:14":{"text":"I have peace offerings with me; this day have I payed my vows.","words":[["H8002","I have peace",0,12],["H2077","offerings",13,22],["H3117","with me; this day",23,40],["H7999","have I payed",41,53],["H5088","my vows",54,61]]},"7:15":{"text":"Therefore came I forth to meet thee, diligently to seek thy face, and I have found thee.","words":[["H3318","Therefore came I forth",0,22],["H7125","to meet",23,30],["H7836","thee, diligently to seek",31,55],["H6440","thy face",56,64],["H4672","and I have found",66,82]]},"7:16":{"text":"I have decked my bed with coverings of tapestry, with carved works, with fine linen of Egypt.","words":[["H7234","I have decked",0,13],["H6210","my bed",14,20],["H4765","with coverings",21,35],["H2405","of tapestry, with carved",36,60],["H0330","works, with fine linen",61,83],["H4714","of Egypt",84,92]]},"7:17":{"text":"I have perfumed my bed with myrrh, aloes, and cinnamon.","words":[["H5130","I have perfumed",0,15],["H4904","my bed",16,22],["H4753","with myrrh",23,33],["H0174","aloes",35,40],["H7076","and cinnamon",42,54]]},"7:18":{"text":"Come, let us take our fill of love until the morning: let us solace ourselves with loves.","words":[["H3212","Come",0,4],["H7301","let us take our fill",6,26],["H1730","of love",27,34],["H1242","until the morning",35,52],["H5965","let us solace",54,67],["H0159","ourselves with loves",68,88]]},"7:19":{"text":"For the goodman is not at home, he is gone a long journey:","words":[["H0376","For the goodman",0,15],["H1004","is not at home",16,30],["H1980","he is gone",32,42],["H7350","a long",43,49],["H1870","journey",50,57]]},"7:20":{"text":"He hath taken a bag of money with him, and will come home at the day appointed.","words":[["H3947","He hath taken",0,13],["H6872","a bag",14,19],["H3701","of money",20,28],["H3027","with him",29,37],["H0935","and will come",39,52],["H1004","home",53,57],["H3117","at the day",58,68],["H3677","appointed",69,78]]},"7:21":{"text":"With her much fair speech she caused him to yield, with the flattering of her lips she forced him.","words":[["H7230","With her much",0,13],["H3948","fair speech",14,25],["H5186","she caused him to yield",26,49],["H2506","with the flattering",51,70],["H8193","of her lips",71,82],["H5080","she forced",83,93]]},"7:22":{"text":"He goeth after her straightway, as an ox goeth to the slaughter, or as a fool to the correction of the stocks;","words":[["H1980","He goeth",0,8],["H0310","after",9,14],["H6597","her straightway",15,30],["H7794","as an ox",32,40],["H0935","goeth",41,46],["H2874","to the slaughter",47,63],["H0191","or as a fool",65,77],["H4148","to the correction",78,95],["H5914","of the stocks",96,109]]},"7:23":{"text":"Till a dart strike through his liver; as a bird hasteth to the snare, and knoweth not that it is for his life.","words":[["H2671","Till a dart",0,11],["H6398","strike",12,18],["H3516","through his liver",19,36],["H6833","as a bird",38,47],["H4116","hasteth",48,55],["H6341","to the snare",56,68],["H3045","and knoweth",70,81],["H5315","not that it is for his life",82,109]]},"7:24":{"text":"Hearken unto me now therefore, O ye children, and attend to the words of my mouth.","words":[["H8085","Hearken",0,7],["H1121","unto me now therefore, O ye children",8,44],["H7181","and attend",46,56],["H0561","to the words",57,69],["H6310","of my mouth",70,81]]},"7:25":{"text":"Let not thine heart decline to her ways, go not astray in her paths.","words":[["H3820","Let not thine heart",0,19],["H7847","decline",20,27],["H1870","to her ways",28,39],["H8582","go not astray",41,54],["H5410","in her paths",55,67]]},"7:26":{"text":"For she hath cast down many wounded: yea, many strong men have been slain by her.","words":[["H5307","For she hath cast down",0,22],["H7227","many",23,27],["H2491","wounded",28,35],["H6099","yea, many strong",37,53],["H2026","men have been slain",54,73]]},"7:27":{"text":"Her house is the way to hell, going down to the chambers of death.","words":[["H1004","Her house",0,9],["H1870","is the way",10,20],["H7585","to hell",21,28],["H3381","going down",30,40],["H2315","to the chambers",41,56],["H4194","of death",57,65]]},"8:1":{"text":"Doth not wisdom cry? and understanding put forth her voice?","words":[["H2451","Doth not wisdom",0,15],["H7121","cry",16,19],["H8394","and understanding",21,38],["H5414","put forth",39,48],["H6963","her voice",49,58]]},"8:2":{"text":"She standeth in the top of high places, by the way in the places of the paths.","words":[["H5324","She standeth",0,12],["H7218","in the top",13,23],["H4791","of high places",24,38],["H1870","by the way",40,50],["H1004","in the places",51,64],["H5410","of the paths",65,77]]},"8:3":{"text":"She crieth at the gates, at the entry of the city, at the coming in at the doors.","words":[["H7442","She crieth",0,10],["H3027","at",11,13],["H8179","the gates",14,23],["H6310","at the entry",25,37],["H7176","of the city",38,49],["H3996","at the coming",51,64],["H6607","in at the doors",65,80]]},"8:4":{"text":"Unto you, O men, I call; and my voice is to the sons of man.","words":[["H0376","Unto you, O men",0,15],["H7121","I call",17,23],["H6963","and my voice",25,37],["H1121","is to the sons",38,52],["H0120","of man",53,59]]},"8:5":{"text":"O ye simple, understand wisdom: and, ye fools, be ye of an understanding heart.","words":[["H6612","O ye simple",0,11],["H0995","understand",13,23],["H6195","wisdom",24,30],["H3684","and, ye fools",32,45],["H0995","be ye of an understanding",47,72],["H3820","heart",73,78]]},"8:6":{"text":"Hear; for I will speak of excellent things; and the opening of my lips shall be right things.","words":[["H8085","Hear",0,4],["H1696","for I will speak",6,22],["H5057","of excellent things",23,42],["H4669","and the opening",44,59],["H8193","of my lips",60,70],["H4339","shall be right things",71,92]]},"8:7":{"text":"For my mouth shall speak truth; and wickedness is an abomination to my lips.","words":[["H2441","For my mouth",0,12],["H1897","shall speak",13,24],["H0571","truth",25,30],["H7562","and wickedness",32,46],["H8441","is an abomination",47,64],["H8193","to my lips",65,75]]},"8:8":{"text":"All the words of my mouth are in righteousness; there is nothing froward or perverse in them.","words":[["H0561","All the words",0,13],["H6310","of my mouth",14,25],["H6664","are in righteousness",26,46],["H6617","there is nothing froward",48,72],["H6141","or perverse",73,84]]},"8:9":{"text":"They are all plain to him that understandeth, and right to them that find knowledge.","words":[["H5228","They are all plain",0,18],["H0995","to him that understandeth",19,44],["H3477","and right",46,55],["H4672","to them that find",56,73],["H1847","knowledge",74,83]]},"8:10":{"text":"Receive my instruction, and not silver; and knowledge rather than choice gold.","words":[["H3947","Receive",0,7],["H4148","my instruction",8,22],["H3701","and not silver",24,38],["H1847","and knowledge",40,53],["H0977","rather than choice",54,72],["H2742","gold",73,77]]},"8:11":{"text":"For wisdom is better than rubies; and all the things that may be desired are not to be compared to it.","words":[["H2451","For wisdom",0,10],["H2896","is better",11,20],["H6443","than rubies",21,32],["H2656","and all the things that may be desired",34,72],["H7737","are not to be compared",73,95]]},"8:12":{"text":"I wisdom dwell with prudence, and find out knowledge of witty inventions.","words":[["H2451","I wisdom",0,8],["H7931","dwell",9,14],["H6195","with prudence",15,28],["H4672","and find out",30,42],["H1847","knowledge",43,52],["H4209","of witty inventions",53,72]]},"8:13":{"text":"The fear of the LORD is to hate evil: pride, and arrogancy, and the evil way, and the froward mouth, do I hate.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H8130","is to hate",21,31],["H7451","evil",32,36],["H1344","pride",38,43],["H1347","and arrogancy",45,58],["H7451","and the evil",60,72],["H1870","way",73,76],["H8419","and the froward",78,93],["H6310","mouth",94,99],["H8130","do I hate",101,110]]},"8:14":{"text":"Counsel is mine, and sound wisdom: I am understanding; I have strength.","words":[["H6098","Counsel",0,7],["H8454","is mine, and sound wisdom",8,33],["H0998","I am understanding",35,53],["H1369","I have strength",55,70]]},"8:15":{"text":"By me kings reign, and princes decree justice.","words":[["H4428","By me kings",0,11],["H4427","reign",12,17],["H7336","and princes",19,30],["H2710","decree",31,37],["H6664","justice",38,45]]},"8:16":{"text":"By me princes rule, and nobles, even all the judges of the earth.","words":[["H8269","By me princes",0,13],["H8323","rule",14,18],["H5081","and nobles",20,30],["H8199","even all the judges",32,51],["H0776","of the earth",52,64]]},"8:17":{"text":"I love them that love me; and those that seek me early shall find me.","words":[["H0157","I love",0,6],["H0157","them that love",7,21],["H7836","me; and those that seek me early",22,54],["H4672","shall find",55,65]]},"8:18":{"text":"Riches and honour are with me; yea, durable riches and righteousness.","words":[["H6239","Riches",0,6],["H3519","and honour",7,17],["H6276","are with me; yea, durable",18,43],["H1952","riches",44,50],["H6666","and righteousness",51,68]]},"8:19":{"text":"My fruit is better than gold, yea, than fine gold; and my revenue than choice silver.","words":[["H6529","My fruit",0,8],["H2896","is better",9,18],["H2742","than gold",19,28],["H6337","yea, than fine gold",30,49],["H8393","and my revenue",51,65],["H0977","than choice",66,77],["H3701","silver",78,84]]},"8:20":{"text":"I lead in the way of righteousness, in the midst of the paths of judgment:","words":[["H1980","I lead",0,6],["H0734","in the way",7,17],["H6666","of righteousness",18,34],["H8432","in the midst",36,48],["H5410","of the paths",49,61],["H4941","of judgment",62,73]]},"8:21":{"text":"That I may cause those that love me to inherit substance; and I will fill their treasures.","words":[["H0157","That I may cause those that love",0,32],["H5157","me to inherit",33,46],["H3426","substance",47,56],["H4390","and I will fill",58,73],["H0214","their treasures",74,89]]},"8:22":{"text":"The LORD possessed me in the beginning of his way, before his works of old.","words":[["H3068","The LORD",0,8],["H7069","possessed",9,18],["H7225","me in the beginning",19,38],["H1870","of his way",39,49],["H6924","before",51,57],["H4659","his works",58,67]]},"8:23":{"text":"I was set up from everlasting, from the beginning, or ever the earth was.","words":[["H5258","I was set up",0,12],["H5769","from everlasting",13,29],["H7218","from the beginning",31,49],["H6924","or ever",51,58],["H0776","the earth",59,68]]},"8:24":{"text":"When there were no depths, I was brought forth; when there were no fountains abounding with water.","words":[["H8415","When there were no depths",0,25],["H2342","I was brought forth",27,46],["H4599","when there were no fountains",48,76],["H3513","abounding",77,86],["H4325","with water",87,97]]},"8:25":{"text":"Before the mountains were settled, before the hills was I brought forth:","words":[["H2022","Before the mountains",0,20],["H2883","were settled",21,33],["H6440","before",35,41],["H1389","the hills",42,51],["H2342","was I brought forth",52,71]]},"8:26":{"text":"While as yet he had not made the earth, nor the fields, nor the highest part of the dust of the world.","words":[["H6213","While as yet he had not made",0,28],["H0776","the earth",29,38],["H2351","nor the fields",40,54],["H7218","nor the highest part",56,76],["H6083","of the dust",77,88],["H8398","of the world",89,101]]},"8:27":{"text":"When he prepared the heavens, I was there: when he set a compass upon the face of the depth:","words":[["H3559","When he prepared",0,16],["H8064","the heavens",17,28],["H2710","I was there: when he set",30,54],["H2329","a compass",55,64],["H6440","upon the face",65,78],["H8415","of the depth",79,91]]},"8:28":{"text":"When he established the clouds above: when he strengthened the fountains of the deep:","words":[["H0553","When he established",0,19],["H7834","the clouds",20,30],["H4605","above",31,36],["H5810","when he strengthened",38,58],["H5869","the fountains",59,72],["H8415","of the deep",73,84]]},"8:29":{"text":"When he gave to the sea his decree, that the waters should not pass his commandment: when he appointed the foundations of the earth:","words":[["H7760","When he gave",0,12],["H3220","to the sea",13,23],["H2706","his decree",24,34],["H4325","that the waters",36,51],["H5674","should not pass",52,67],["H6310","his commandment",68,83],["H2710","when he appointed",85,102],["H4144","the foundations",103,118],["H0776","of the earth",119,131]]},"8:30":{"text":"Then I was by him, as one brought up with him: and I was daily his delight, rejoicing always before him;","words":[["H0681","Then I was by him",0,17],["H0525","as one brought up",19,36],["H3117","with him: and I was daily",37,62],["H3117","with him: and I was daily",37,62],["H8191","his delight",63,74],["H7832","rejoicing",76,85],["H6256","always",86,92],["H6440","before",93,99]]},"8:31":{"text":"Rejoicing in the habitable part of his earth; and my delights were with the sons of men.","words":[["H7832","Rejoicing",0,9],["H8398","in the habitable part",10,31],["H0776","of his earth",32,44],["H8191","and my delights",46,61],["H1121","were with the sons",62,80],["H0120","of men",81,87]]},"8:32":{"text":"Now therefore hearken unto me, O ye children: for blessed are they that keep my ways.","words":[["H8085","Now therefore hearken",0,21],["H1121","unto me, O ye children",22,44],["H0835","for blessed",46,57],["H8104","are they that keep",58,76],["H1870","my ways",77,84]]},"8:33":{"text":"Hear instruction, and be wise, and refuse it not.","words":[["H8085","Hear",0,4],["H4148","instruction",5,16],["H2449","and be wise",18,29],["H6544","and refuse",31,41]]},"8:34":{"text":"Blessed is the man that heareth me, watching daily at my gates, waiting at the posts of my doors.","words":[["H0835","Blessed",0,7],["H0120","is the man",8,18],["H8085","that heareth",19,31],["H8245","me, watching",32,44],["H3117","daily",45,50],["H3117","daily",45,50],["H1817","at my gates",51,62],["H8104","waiting",64,71],["H4201","at the posts",72,84],["H6607","of my doors",85,96]]},"8:35":{"text":"For whoso findeth me findeth life, and shall obtain favour of the LORD.","words":[["H4672","For whoso findeth",0,17],["H4672","me findeth",18,28],["H4672","me findeth",18,28],["H2416","life",29,33],["H6329","and shall obtain",35,51],["H7522","favour",52,58],["H3068","of the LORD",59,70]]},"8:36":{"text":"But he that sinneth against me wrongeth his own soul: all they that hate me love death.","words":[["H2398","But he that sinneth",0,19],["H2554","against me wrongeth",20,39],["H5315","his own soul",40,52],["H8130","all they that hate",54,72],["H0157","me love",73,80],["H4194","death",81,86]]},"9:1":{"text":"Wisdom hath builded her house, she hath hewn out her seven pillars:","words":[["H2454","Wisdom",0,6],["H1129","hath builded",7,19],["H1004","her house",20,29],["H2672","she hath hewn out",31,48],["H7651","her seven",49,58],["H5982","pillars",59,66]]},"9:2":{"text":"She hath killed her beasts; she hath mingled her wine; she hath also furnished her table.","words":[["H2873","She hath killed",0,15],["H2874","her beasts",16,26],["H4537","she hath mingled",28,44],["H3196","her wine",45,53],["H6186","she hath also furnished",55,78],["H7979","her table",79,88]]},"9:3":{"text":"She hath sent forth her maidens: she crieth upon the highest places of the city,","words":[["H7971","She hath sent forth",0,19],["H5291","her maidens",20,31],["H7121","she crieth",33,43],["H1610","upon",44,48],["H4791","the highest places",49,67],["H7176","of the city",68,79]]},"9:4":{"text":"Whoso is simple, let him turn in hither: as for him that wanteth understanding, she saith to him,","words":[["H6612","Whoso is simple",0,15],["H5493","let him turn in",17,32],["H2638","hither: as for him that wanteth",33,64],["H3820","understanding",65,78],["H0559","she saith",80,89]]},"9:5":{"text":"Come, eat of my bread, and drink of the wine which I have mingled.","words":[["H3212","Come",0,4],["H3898","eat",6,9],["H3899","of my bread",10,21],["H8354","and drink",23,32],["H3196","of the wine",33,44],["H4537","which I have mingled",45,65]]},"9:6":{"text":"Forsake the foolish, and live; and go in the way of understanding.","words":[["H5800","Forsake",0,7],["H6612","the foolish",8,19],["H2421","and live",21,29],["H0833","and go",31,37],["H1870","in the way",38,48],["H0998","of understanding",49,65]]},"9:7":{"text":"He that reproveth a scorner getteth to himself shame: and he that rebuketh a wicked man getteth himself a blot.","words":[["H3256","He that reproveth",0,17],["H3887","a scorner",18,27],["H3947","getteth",28,35],["H7036","to himself shame",36,52],["H3198","and he that rebuketh",54,74],["H7563","a wicked",75,83],["H3971","man getteth himself a blot",84,110]]},"9:8":{"text":"Reprove not a scorner, lest he hate thee: rebuke a wise man, and he will love thee.","words":[["H3198","Reprove",0,7],["H3887","not a scorner",8,21],["H8130","lest he hate",23,35],["H3198","thee: rebuke",36,48],["H2450","a wise man",49,59],["H0157","and he will love",61,77]]},"9:9":{"text":"Give instruction to a wise man, and he will be yet wiser: teach a just man, and he will increase in learning.","words":[["H5414","Give",0,4],["H2450","instruction to a wise",5,26],["H2449","man, and he will be yet wiser",27,56],["H3045","teach",58,63],["H6662","a just",64,70],["H3254","man, and he will increase",71,96],["H3948","in learning",97,108]]},"9:10":{"text":"The fear of the LORD is the beginning of wisdom: and the knowledge of the holy is understanding.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H8462","is the beginning",21,37],["H2451","of wisdom",38,47],["H1847","and the knowledge",49,66],["H6918","of the holy",67,78],["H0998","is understanding",79,95]]},"9:11":{"text":"For by me thy days shall be multiplied, and the years of thy life shall be increased.","words":[["H3117","For by me thy days",0,18],["H7235","shall be multiplied",19,38],["H8141","and the years",40,53],["H2416","of thy life",54,65],["H3254","shall be increased",66,84]]},"9:12":{"text":"If thou be wise, thou shalt be wise for thyself: but if thou scornest, thou alone shalt bear it.","words":[["H2449","If thou be wise",0,15],["H2449","thou shalt be wise",17,35],["H3887","for thyself: but if thou scornest",36,69],["H5375","thou alone shalt bear",71,92]]},"9:13":{"text":"A foolish woman is clamorous: she is simple, and knoweth nothing.","words":[["H3687","A foolish",0,9],["H0802","woman",10,15],["H1993","is clamorous",16,28],["H6615","she is simple",30,43],["H1077","and",45,48],["H3045","knoweth",49,56],["H4100","nothing",57,64]]},"9:14":{"text":"For she sitteth at the door of her house, on a seat in the high places of the city,","words":[["H3427","For she sitteth",0,15],["H6607","at the door",16,27],["H1004","of her house",28,40],["H3678","on a seat",42,51],["H4791","in the high places",52,70],["H7176","of the city",71,82]]},"9:15":{"text":"To call passengers who go right on their ways:","words":[["H7121","To call",0,7],["H5674","passengers",8,18],["H1870","passengers",8,18],["H3474","who go right",19,31],["H0734","on their ways",32,45]]},"9:16":{"text":"Whoso is simple, let him turn in hither: and as for him that wanteth understanding, she saith to him,","words":[["H6612","Whoso is simple",0,15],["H5493","let him turn in",17,32],["H2638","hither: and as for him that wanteth",33,68],["H3820","understanding",69,82],["H0559","she saith",84,93]]},"9:17":{"text":"Stolen waters are sweet, and bread eaten in secret is pleasant.","words":[["H1589","Stolen",0,6],["H4325","waters",7,13],["H4985","are sweet",14,23],["H3899","and bread",25,34],["H5643","eaten in secret",35,50],["H5276","is pleasant",51,62]]},"9:18":{"text":"But he knoweth not that the dead are there; and that her guests are in the depths of hell.","words":[["H3045","But he knoweth",0,14],["H7496","not that the dead",15,32],["H7121","are there; and that her guests",33,63],["H6012","are in the depths",64,81],["H7585","of hell",82,89]]},"10:1":{"text":"The proverbs of Solomon. A wise son maketh a glad father: but a foolish son is the heaviness of his mother.","words":[["H4912","The proverbs",0,12],["H8010","of Solomon",13,23],["H2450","A wise",25,31],["H1121","son",32,35],["H8055","maketh a glad",36,49],["H0001","father",50,56],["H3684","but a foolish",58,71],["H1121","son",72,75],["H8424","is the heaviness",76,92],["H0517","of his mother",93,106]]},"10:2":{"text":"Treasures of wickedness profit nothing: but righteousness delivereth from death.","words":[["H0214","Treasures",0,9],["H7562","of wickedness",10,23],["H3276","profit",24,30],["H6666","nothing: but righteousness",31,57],["H5337","delivereth",58,68],["H4194","from death",69,79]]},"10:3":{"text":"The LORD will not suffer the soul of the righteous to famish: but he casteth away the substance of the wicked.","words":[["H3068","The LORD",0,8],["H7456","will not suffer",9,24],["H5315","the soul",25,33],["H6662","of the righteous",34,50],["H7456","to famish",51,60],["H1920","but he casteth away",62,81],["H1942","the substance",82,95],["H7563","of the wicked",96,109]]},"10:4":{"text":"He becometh poor that dealeth with a slack hand: but the hand of the diligent maketh rich.","words":[["H7326","He becometh poor",0,16],["H6213","that dealeth",17,29],["H7423","with a slack",30,42],["H3709","hand",43,47],["H3027","but the hand",49,61],["H2742","of the diligent",62,77],["H6238","maketh rich",78,89]]},"10:5":{"text":"He that gathereth in summer is a wise son: but he that sleepeth in harvest is a son that causeth shame.","words":[["H0103","He that gathereth",0,17],["H7019","in summer",18,27],["H7919","is a wise",28,37],["H1121","son",38,41],["H7290","but he that sleepeth",43,63],["H7105","in harvest",64,74],["H1121","is a son",75,83],["H0954","that causeth shame",84,102]]},"10:6":{"text":"Blessings are upon the head of the just: but violence covereth the mouth of the wicked.","words":[["H1293","Blessings",0,9],["H7218","are upon the head",10,27],["H6662","of the just",28,39],["H2555","but violence",41,53],["H3680","covereth",54,62],["H6310","the mouth",63,72],["H7563","of the wicked",73,86]]},"10:7":{"text":"The memory of the just is blessed: but the name of the wicked shall rot.","words":[["H2143","The memory",0,10],["H6662","of the just",11,22],["H1293","is blessed",23,33],["H8034","but the name",35,47],["H7563","of the wicked",48,61],["H7537","shall rot",62,71]]},"10:8":{"text":"The wise in heart will receive commandments: but a prating fool shall fall.","words":[["H2450","The wise",0,8],["H3820","in heart",9,17],["H3947","will receive",18,30],["H4687","commandments",31,43],["H8193","but a prating",45,58],["H0191","fool",59,63],["H3832","shall fall",64,74]]},"10:9":{"text":"He that walketh uprightly walketh surely: but he that perverteth his ways shall be known.","words":[["H3212","He that walketh",0,15],["H8537","uprightly",16,25],["H1980","walketh",26,33],["H0983","surely",34,40],["H6140","but he that perverteth",42,64],["H1870","his ways",65,73],["H3045","shall be known",74,88]]},"10:10":{"text":"He that winketh with the eye causeth sorrow: but a prating fool shall fall.","words":[["H7169","He that winketh",0,15],["H5869","with the eye",16,28],["H5414","causeth",29,36],["H6094","sorrow",37,43],["H8193","but a prating",45,58],["H0191","fool",59,63],["H3832","shall fall",64,74]]},"10:11":{"text":"The mouth of a righteous man is a well of life: but violence covereth the mouth of the wicked.","words":[["H6310","The mouth",0,9],["H6662","of a righteous",10,24],["H4726","man is a well",25,38],["H2416","of life",39,46],["H2555","but violence",48,60],["H3680","covereth",61,69],["H6310","the mouth",70,79],["H7563","of the wicked",80,93]]},"10:12":{"text":"Hatred stirreth up strifes: but love covereth all sins.","words":[["H8135","Hatred",0,6],["H5782","stirreth up",7,18],["H4090","strifes",19,26],["H0160","but love",28,36],["H3680","covereth",37,45],["H6588","all sins",46,54]]},"10:13":{"text":"In the lips of him that hath understanding wisdom is found: but a rod is for the back of him that is void of understanding.","words":[["H8193","In the lips",0,11],["H0995","of him that hath understanding",12,42],["H2451","wisdom",43,49],["H4672","is found",50,58],["H7626","but a rod",60,69],["H1460","is for the back",70,85],["H2638","of him that is void",86,105],["H3820","of understanding",106,122]]},"10:14":{"text":"Wise men lay up knowledge: but the mouth of the foolish is near destruction.","words":[["H2450","Wise",0,4],["H6845","men lay up",5,15],["H1847","knowledge",16,25],["H6310","but the mouth",27,40],["H0191","of the foolish",41,55],["H7138","is near",56,63],["H4288","destruction",64,75]]},"10:15":{"text":"The rich man's wealth is his strong city: the destruction of the poor is their poverty.","words":[["H6223","The rich man's",0,14],["H1952","wealth",15,21],["H5797","is his strong",22,35],["H7151","city",36,40],["H4288","the destruction",42,57],["H1800","of the poor",58,69],["H7389","is their poverty",70,86]]},"10:16":{"text":"The labour of the righteous tendeth to life: the fruit of the wicked to sin.","words":[["H6468","The labour",0,10],["H6662","of the righteous",11,27],["H2416","tendeth to life",28,43],["H8393","the fruit",45,54],["H7563","of the wicked",55,68],["H2403","to sin",69,75]]},"10:17":{"text":"He is in the way of life that keepeth instruction: but he that refuseth reproof erreth.","words":[["H0734","He is in the way",0,16],["H2416","of life",17,24],["H8104","that keepeth",25,37],["H4148","instruction",38,49],["H5800","but he that refuseth",51,71],["H8433","reproof",72,79],["H8582","erreth",80,86]]},"10:18":{"text":"He that hideth hatred with lying lips, and he that uttereth a slander, is a fool.","words":[["H3680","He that hideth",0,14],["H8135","hatred",15,21],["H8267","with lying",22,32],["H8193","lips",33,37],["H3318","and he that uttereth",39,59],["H1681","a slander",60,69],["H3684","is a fool",71,80]]},"10:19":{"text":"In the multitude of words there wanteth not sin: but he that refraineth his lips is wise.","words":[["H7230","In the multitude",0,16],["H1697","of words",17,25],["H2308","there wanteth",26,39],["H6588","not sin",40,47],["H2820","but he that refraineth",49,71],["H8193","his lips",72,80],["H7919","is wise",81,88]]},"10:20":{"text":"The tongue of the just is as choice silver: the heart of the wicked is little worth.","words":[["H3956","The tongue",0,10],["H6662","of the just",11,22],["H0977","is as choice",23,35],["H3701","silver",36,42],["H3820","the heart",44,53],["H7563","of the wicked",54,67],["H4592","is little worth",68,83]]},"10:21":{"text":"The lips of the righteous feed many: but fools die for want of wisdom.","words":[["H8193","The lips",0,8],["H6662","of the righteous",9,25],["H7462","feed",26,30],["H7227","many",31,35],["H0191","but fools",37,46],["H4191","die",47,50],["H2638","for want",51,59],["H3820","of wisdom",60,69]]},"10:22":{"text":"The blessing of the LORD, it maketh rich, and he addeth no sorrow with it.","words":[["H1293","The blessing",0,12],["H3068","of the LORD",13,24],["H6238","it maketh rich",26,40],["H3254","and he addeth",42,55],["H6089","no sorrow",56,65]]},"10:23":{"text":"It is as sport to a fool to do mischief: but a man of understanding hath wisdom.","words":[["H7814","It is as sport",0,14],["H3684","to a fool",15,24],["H6213","to do",25,30],["H2154","mischief",31,39],["H0376","but a man",41,50],["H8394","of understanding",51,67],["H2451","hath wisdom",68,79]]},"10:24":{"text":"The fear of the wicked, it shall come upon him: but the desire of the righteous shall be granted.","words":[["H4034","The fear",0,8],["H7563","of the wicked",9,22],["H0935","it shall come",24,37],["H8378","upon him: but the desire",38,62],["H6662","of the righteous",63,79],["H5414","shall be granted",80,96]]},"10:25":{"text":"As the whirlwind passeth, so is the wicked no more: but the righteous is an everlasting foundation.","words":[["H5492","As the whirlwind",0,16],["H5674","passeth",17,24],["H7563","so is the wicked",26,42],["H6662","no more: but the righteous",43,69],["H5769","is an everlasting",70,87],["H3247","foundation",88,98]]},"10:26":{"text":"As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to them that send him.","words":[["H2558","As vinegar",0,10],["H8127","to the teeth",11,23],["H6227","and as smoke",25,37],["H5869","to the eyes",38,49],["H6102","so is the sluggard",51,69],["H7971","to them that send",70,87]]},"10:27":{"text":"The fear of the LORD prolongeth days: but the years of the wicked shall be shortened.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H3254","prolongeth",21,31],["H3117","days",32,36],["H8141","but the years",38,51],["H7563","of the wicked",52,65],["H7114","shall be shortened",66,84]]},"10:28":{"text":"The hope of the righteous shall be gladness: but the expectation of the wicked shall perish.","words":[["H8431","The hope",0,8],["H6662","of the righteous",9,25],["H8057","shall be gladness",26,43],["H8615","but the expectation",45,64],["H7563","of the wicked",65,78],["H0006","shall perish",79,91]]},"10:29":{"text":"The way of the LORD is strength to the upright: but destruction shall be to the workers of iniquity.","words":[["H1870","The way",0,7],["H3068","of the LORD",8,19],["H4581","is strength",20,31],["H8537","to the upright",32,46],["H4288","but destruction",48,63],["H6466","shall be to the workers",64,87],["H0205","of iniquity",88,99]]},"10:30":{"text":"The righteous shall never be removed: but the wicked shall not inhabit the earth.","words":[["H6662","The righteous",0,13],["H5769","shall never",14,25],["H4131","be removed",26,36],["H7563","but the wicked",38,52],["H7931","shall not inhabit",53,70],["H0776","the earth",71,80]]},"10:31":{"text":"The mouth of the just bringeth forth wisdom: but the froward tongue shall be cut out.","words":[["H6310","The mouth",0,9],["H6662","of the just",10,21],["H5107","bringeth forth",22,36],["H2451","wisdom",37,43],["H8419","but the froward",45,60],["H3956","tongue",61,67],["H3772","shall be cut out",68,84]]},"10:32":{"text":"The lips of the righteous know what is acceptable: but the mouth of the wicked speaketh frowardness.","words":[["H8193","The lips",0,8],["H6662","of the righteous",9,25],["H3045","know",26,30],["H7522","what is acceptable",31,49],["H6310","but the mouth",51,64],["H7563","of the wicked",65,78],["H8419","speaketh frowardness",79,99]]},"11:1":{"text":"A false balance is abomination to the LORD: but a just weight is his delight.","words":[["H4820","A false",0,7],["H3976","balance",8,15],["H8441","is abomination",16,30],["H3068","to the LORD",31,42],["H8003","but a just",44,54],["H0068","weight",55,61],["H7522","is his delight",62,76]]},"11:2":{"text":"When pride cometh, then cometh shame: but with the lowly is wisdom.","words":[["H2087","When pride",0,10],["H0935","cometh",11,17],["H0935","then cometh",19,30],["H7036","shame",31,36],["H6800","but with the lowly",38,56],["H2451","is wisdom",57,66]]},"11:3":{"text":"The integrity of the upright shall guide them: but the perverseness of transgressors shall destroy them.","words":[["H8538","The integrity",0,13],["H3477","of the upright",14,28],["H5148","shall guide",29,40],["H5558","them: but the perverseness",41,67],["H0898","of transgressors",68,84],["H7703","shall destroy",85,98],["H7703","shall destroy",85,98]]},"11:4":{"text":"Riches profit not in the day of wrath: but righteousness delivereth from death.","words":[["H1952","Riches",0,6],["H3276","profit",7,13],["H3117","not in the day",14,28],["H5678","of wrath",29,37],["H6666","but righteousness",39,56],["H5337","delivereth",57,67],["H4194","from death",68,78]]},"11:5":{"text":"The righteousness of the perfect shall direct his way: but the wicked shall fall by his own wickedness.","words":[["H6666","The righteousness",0,17],["H8549","of the perfect",18,32],["H3474","shall direct",33,45],["H1870","his way",46,53],["H7563","but the wicked",55,69],["H5307","shall fall",70,80],["H7564","by his own wickedness",81,102]]},"11:6":{"text":"The righteousness of the upright shall deliver them: but transgressors shall be taken in their own naughtiness.","words":[["H6666","The righteousness",0,17],["H3477","of the upright",18,32],["H5337","shall deliver",33,46],["H0898","them: but transgressors",47,70],["H3920","shall be taken",71,85],["H1942","in their own naughtiness",86,110]]},"11:7":{"text":"When a wicked man dieth, his expectation shall perish: and the hope of unjust men perisheth.","words":[["H7563","When a wicked",0,13],["H0120","man",14,17],["H4194","dieth",18,23],["H8615","his expectation",25,40],["H0006","shall perish",41,53],["H8431","and the hope",55,67],["H0205","of unjust",68,77],["H0006","men perisheth",78,91]]},"11:8":{"text":"The righteous is delivered out of trouble, and the wicked cometh in his stead.","words":[["H6662","The righteous",0,13],["H2502","is delivered out",14,30],["H6869","of trouble",31,41],["H7563","and the wicked",43,57],["H0935","cometh",58,64]]},"11:9":{"text":"An hypocrite with his mouth destroyeth his neighbour: but through knowledge shall the just be delivered.","words":[["H2611","An hypocrite",0,12],["H6310","with his mouth",13,27],["H7843","destroyeth",28,38],["H7453","his neighbour",39,52],["H1847","but through knowledge",54,75],["H6662","shall the just",76,90],["H2502","be delivered",91,103]]},"11:10":{"text":"When it goeth well with the righteous, the city rejoiceth: and when the wicked perish, there is shouting.","words":[["H2898","When it goeth well",0,18],["H6662","with the righteous",19,37],["H7151","the city",39,47],["H5970","rejoiceth",48,57],["H7563","and when the wicked",59,78],["H0006","perish",79,85],["H7440","there is shouting",87,104]]},"11:11":{"text":"By the blessing of the upright the city is exalted: but it is overthrown by the mouth of the wicked.","words":[["H1293","By the blessing",0,15],["H3477","of the upright",16,30],["H7176","the city",31,39],["H7311","is exalted",40,50],["H2040","but it is overthrown",52,72],["H6310","by the mouth",73,85],["H7563","of the wicked",86,99]]},"11:12":{"text":"He that is void of wisdom despiseth his neighbour: but a man of understanding holdeth his peace.","words":[["H2638","He that is void",0,15],["H3820","of wisdom",16,25],["H0936","despiseth",26,35],["H7453","his neighbour",36,49],["H0376","but a man",51,60],["H8394","of understanding",61,77],["H2790","holdeth his peace",78,95]]},"11:13":{"text":"A talebearer revealeth secrets: but he that is of a faithful spirit concealeth the matter.","words":[["H1980","A talebearer",0,12],["H7400","A talebearer",0,12],["H1540","revealeth",13,22],["H5475","secrets",23,30],["H0539","but he that is of a faithful",32,60],["H7307","spirit",61,67],["H3680","concealeth",68,78],["H1697","the matter",79,89]]},"11:14":{"text":"Where no counsel is, the people fall: but in the multitude of counsellors there is safety.","words":[["H8458","Where no counsel",0,16],["H5971","is, the people",17,31],["H5307","fall",32,36],["H7230","but in the multitude",38,58],["H3289","of counsellors",59,73],["H8668","there is safety",74,89]]},"11:15":{"text":"He that is surety for a stranger shall smart for it: and he that hateth suretiship is sure.","words":[["H6148","He that is surety",0,17],["H2114","for a stranger",18,32],["H7321","shall smart",33,44],["H7451","shall smart",33,44],["H8130","for it: and he that hateth",45,71],["H8628","suretiship",72,82],["H0982","is sure",83,90]]},"11:16":{"text":"A gracious woman retaineth honour: and strong men retain riches.","words":[["H2580","A gracious",0,10],["H0802","woman",11,16],["H8551","retaineth",17,26],["H3519","honour",27,33],["H6184","and strong",35,45],["H8551","men retain",46,56],["H6239","riches",57,63]]},"11:17":{"text":"The merciful man doeth good to his own soul: but he that is cruel troubleth his own flesh.","words":[["H2617","The merciful",0,12],["H0376","man",13,16],["H1580","doeth good",17,27],["H5315","to his own soul",28,43],["H0394","but he that is cruel",45,65],["H5916","troubleth",66,75],["H7607","his own flesh",76,89]]},"11:18":{"text":"The wicked worketh a deceitful work: but to him that soweth righteousness shall be a sure reward.","words":[["H7563","The wicked",0,10],["H6213","worketh",11,18],["H8267","a deceitful",19,30],["H6468","work",31,35],["H2232","but to him that soweth",37,59],["H6666","righteousness",60,73],["H0571","shall be a sure",74,89],["H7938","reward",90,96]]},"11:19":{"text":"As righteousness tendeth to life: so he that pursueth evil pursueth it to his own death.","words":[["H6666","As righteousness",0,16],["H2416","tendeth to life",17,32],["H7291","so he that pursueth",34,53],["H7451","evil",54,58],["H4194","pursueth it to his own death",59,87]]},"11:20":{"text":"They that are of a froward heart are abomination to the LORD: but such as are upright in their way are his delight.","words":[["H6141","They that are of a froward",0,26],["H3820","heart",27,32],["H8441","are abomination",33,48],["H3068","to the LORD",49,60],["H8549","but such as are upright",62,85],["H1870","in their way",86,98],["H7522","are his delight",99,114]]},"11:21":{"text":"Though hand join in hand, the wicked shall not be unpunished: but the seed of the righteous shall be delivered.","words":[["H3027","Though hand",0,11],["H3027","join in hand",12,24],["H7451","the wicked",26,36],["H5352","shall not be unpunished",37,60],["H2233","but the seed",62,74],["H6662","of the righteous",75,91],["H4422","shall be delivered",92,110]]},"11:22":{"text":"As a jewel of gold in a swine's snout, so is a fair woman which is without discretion.","words":[["H5141","As a jewel",0,10],["H2091","of gold",11,18],["H2386","in a swine's",19,31],["H0639","snout",32,37],["H3303","so is a fair",39,51],["H0802","woman",52,57],["H5493","which is without",58,74],["H2940","discretion",75,85]]},"11:23":{"text":"The desire of the righteous is only good: but the expectation of the wicked is wrath.","words":[["H8378","The desire",0,10],["H6662","of the righteous",11,27],["H2896","is only good",28,40],["H8615","but the expectation",42,61],["H7563","of the wicked",62,75],["H5678","is wrath",76,84]]},"11:24":{"text":"There is that scattereth, and yet increaseth; and there is that withholdeth more than is meet, but it tendeth to poverty.","words":[["H3426","There is",0,8],["H6340","that scattereth",9,24],["H3254","and yet increaseth",26,44],["H2820","and there is that withholdeth",46,75],["H3476","more than is meet",76,93],["H4270","but it tendeth to poverty",95,120]]},"11:25":{"text":"The liberal soul shall be made fat: and he that watereth shall be watered also himself.","words":[["H1293","The liberal",0,11],["H5315","soul",12,16],["H1878","shall be made fat",17,34],["H7301","and he that watereth",36,56],["H3384","shall be watered",57,73]]},"11:26":{"text":"He that withholdeth corn, the people shall curse him: but blessing shall be upon the head of him that selleth it.","words":[["H4513","He that withholdeth",0,19],["H1250","corn",20,24],["H3816","the people",26,36],["H5344","shall curse",37,48],["H1293","him: but blessing",49,66],["H7218","shall be upon the head",67,89],["H7666","of him that selleth",90,109]]},"11:27":{"text":"He that diligently seeketh good procureth favour: but he that seeketh mischief, it shall come unto him.","words":[["H7836","He that diligently seeketh",0,26],["H2896","good",27,31],["H1245","procureth",32,41],["H7522","favour",42,48],["H1875","but he that seeketh",50,69],["H7451","mischief",70,78],["H0935","it shall come",80,93]]},"11:28":{"text":"He that trusteth in his riches shall fall: but the righteous shall flourish as a branch.","words":[["H0982","He that trusteth",0,16],["H6239","in his riches",17,30],["H5307","shall fall",31,41],["H6662","but the righteous",43,60],["H6524","shall flourish",61,75],["H5929","as a branch",76,87]]},"11:29":{"text":"He that troubleth his own house shall inherit the wind: and the fool shall be servant to the wise of heart.","words":[["H5916","He that troubleth",0,17],["H1004","his own house",18,31],["H5157","shall inherit",32,45],["H7307","the wind",46,54],["H0191","and the fool",56,68],["H5650","shall be servant",69,85],["H2450","to the wise",86,97],["H3820","of heart",98,106]]},"11:30":{"text":"The fruit of the righteous is a tree of life; and he that winneth souls is wise.","words":[["H6529","The fruit",0,9],["H6662","of the righteous",10,26],["H6086","is a tree",27,36],["H2416","of life",37,44],["H3947","and he that winneth",46,65],["H5315","souls",66,71],["H2450","is wise",72,79]]},"11:31":{"text":"Behold, the righteous shall be recompensed in the earth: much more the wicked and the sinner.","words":[["H6662","Behold, the righteous",0,21],["H7999","shall be recompensed",22,42],["H0776","in the earth",43,55],["H7563","much more the wicked",57,77],["H2398","and the sinner",78,92]]},"12:1":{"text":"Whoso loveth instruction loveth knowledge: but he that hateth reproof is brutish.","words":[["H0157","Whoso loveth",0,12],["H4148","instruction",13,24],["H0157","loveth",25,31],["H1847","knowledge",32,41],["H8130","but he that hateth",43,61],["H8433","reproof",62,69],["H1198","is brutish",70,80]]},"12:2":{"text":"A good man obtaineth favour of the LORD: but a man of wicked devices will he condemn.","words":[["H2896","A good",0,6],["H6329","man obtaineth",7,20],["H7522","favour",21,27],["H3068","of the LORD",28,39],["H0376","but a man",41,50],["H4209","of wicked devices",51,68],["H7561","will he condemn",69,84]]},"12:3":{"text":"A man shall not be established by wickedness: but the root of the righteous shall not be moved.","words":[["H0120","A man",0,5],["H3559","shall not be established",6,30],["H7562","by wickedness",31,44],["H8328","but the root",46,58],["H6662","of the righteous",59,75],["H4131","shall not be moved",76,94]]},"12:4":{"text":"A virtuous woman is a crown to her husband: but she that maketh ashamed is as rottenness in his bones.","words":[["H2428","A virtuous",0,10],["H0802","woman",11,16],["H5850","is a crown",17,27],["H1167","to her husband",28,42],["H0954","but she that maketh ashamed",44,71],["H7538","is as rottenness",72,88],["H6106","in his bones",89,101]]},"12:5":{"text":"The thoughts of the righteous are right: but the counsels of the wicked are deceit.","words":[["H4284","The thoughts",0,12],["H6662","of the righteous",13,29],["H4941","are right",30,39],["H8458","but the counsels",41,57],["H7563","of the wicked",58,71],["H4820","are deceit",72,82]]},"12:6":{"text":"The words of the wicked are to lie in wait for blood: but the mouth of the upright shall deliver them.","words":[["H1697","The words",0,9],["H7563","of the wicked",10,23],["H0693","are to lie in wait",24,42],["H1818","for blood",43,52],["H6310","but the mouth",54,67],["H3477","of the upright",68,82],["H5337","shall deliver",83,96]]},"12:7":{"text":"The wicked are overthrown, and are not: but the house of the righteous shall stand.","words":[["H7563","The wicked",0,10],["H2015","are overthrown",11,25],["H1004","and are not: but the house",27,53],["H6662","of the righteous",54,70],["H5975","shall stand",71,82]]},"12:8":{"text":"A man shall be commended according to his wisdom: but he that is of a perverse heart shall be despised.","words":[["H0376","A man",0,5],["H1984","shall be commended",6,24],["H6310","according",25,34],["H7922","to his wisdom",35,48],["H5753","but he that is of a perverse",50,78],["H3820","heart",79,84],["H0937","shall be despised",85,102]]},"12:9":{"text":"He that is despised, and hath a servant, is better than he that honoureth himself, and lacketh bread.","words":[["H7034","He that is despised",0,19],["H5650","and hath a servant",21,39],["H2896","is better",41,50],["H3513","than he that honoureth",51,73],["H2638","himself, and lacketh",74,94],["H3899","bread",95,100]]},"12:10":{"text":"A righteous man regardeth the life of his beast: but the tender mercies of the wicked are cruel.","words":[["H6662","A righteous",0,11],["H3045","man regardeth",12,25],["H5315","the life",26,34],["H0929","of his beast",35,47],["H7356","but the tender mercies",49,71],["H7563","of the wicked",72,85],["H0394","are cruel",86,95]]},"12:11":{"text":"He that tilleth his land shall be satisfied with bread: but he that followeth vain persons is void of understanding.","words":[["H5647","He that tilleth",0,15],["H0127","his land",16,24],["H7646","shall be satisfied",25,43],["H3899","with bread",44,54],["H7291","but he that followeth",56,77],["H7386","vain",78,82],["H2638","persons is void",83,98],["H3820","of understanding",99,115]]},"12:12":{"text":"The wicked desireth the net of evil men: but the root of the righteous yieldeth fruit.","words":[["H7563","The wicked",0,10],["H2530","desireth",11,19],["H4685","the net",20,27],["H7451","of evil",28,35],["H8328","men: but the root",36,53],["H6662","of the righteous",54,70],["H5414","yieldeth",71,79]]},"12:13":{"text":"The wicked is snared by the transgression of his lips: but the just shall come out of trouble.","words":[["H7451","The wicked",0,10],["H4170","is snared",11,20],["H6588","by the transgression",21,41],["H8193","of his lips",42,53],["H6662","but the just",55,67],["H3318","shall come out",68,82],["H6869","of trouble",83,93]]},"12:14":{"text":"A man shall be satisfied with good by the fruit of his mouth: and the recompence of a man's hands shall be rendered unto him.","words":[["H0376","A man",0,5],["H7646","shall be satisfied",6,24],["H2896","with good",25,34],["H6529","by the fruit",35,47],["H6310","of his mouth",48,60],["H1576","and the recompence",62,80],["H0120","of a man's",81,91],["H3027","hands",92,97],["H7725","shall be rendered",98,115],["H7725","shall be rendered",98,115]]},"12:15":{"text":"The way of a fool is right in his own eyes: but he that hearkeneth unto counsel is wise.","words":[["H1870","The way",0,7],["H0191","of a fool",8,17],["H3477","is right",18,26],["H5869","in his own eyes",27,42],["H8085","but he that hearkeneth",44,66],["H6098","unto counsel",67,79],["H2450","is wise",80,87]]},"12:16":{"text":"A fool's wrath is presently known: but a prudent man covereth shame.","words":[["H0191","A fool's",0,8],["H3708","wrath",9,14],["H3117","is presently",15,27],["H3045","known",28,33],["H6175","but a prudent",35,48],["H3680","man covereth",49,61],["H7036","shame",62,67]]},"12:17":{"text":"He that speaketh truth sheweth forth righteousness: but a false witness deceit.","words":[["H6315","He that speaketh",0,16],["H0530","truth",17,22],["H5046","sheweth forth",23,36],["H6664","righteousness",37,50],["H8267","but a false",52,63],["H5707","witness",64,71],["H4820","deceit",72,78]]},"12:18":{"text":"There is that speaketh like the piercings of a sword: but the tongue of the wise is health.","words":[["H3426","There is",0,8],["H0981","that speaketh",9,22],["H4094","like the piercings",23,41],["H2719","of a sword",42,52],["H3956","but the tongue",54,68],["H2450","of the wise",69,80],["H4832","is health",81,90]]},"12:19":{"text":"The lip of truth shall be established for ever: but a lying tongue is but for a moment.","words":[["H8193","The lip",0,7],["H0571","of truth",8,16],["H3559","shall be established",17,37],["H5703","for ever",38,46],["H8267","but a lying",48,59],["H3956","tongue",60,66],["H7280","is but for a moment",67,86]]},"12:20":{"text":"Deceit is in the heart of them that imagine evil: but to the counsellors of peace is joy.","words":[["H4820","Deceit",0,6],["H3820","is in the heart",7,22],["H2790","of them that imagine",23,43],["H7451","evil",44,48],["H3289","but to the counsellors",50,72],["H7965","of peace",73,81],["H8057","is joy",82,88]]},"12:21":{"text":"There shall no evil happen to the just: but the wicked shall be filled with mischief.","words":[["H0205","There shall no evil",0,19],["H0579","happen",20,26],["H6662","to the just",27,38],["H7563","but the wicked",40,54],["H4390","shall be filled",55,70],["H7451","with mischief",71,84]]},"12:22":{"text":"Lying lips are abomination to the LORD: but they that deal truly are his delight.","words":[["H8267","Lying",0,5],["H8193","lips",6,10],["H8441","are abomination",11,26],["H3068","to the LORD",27,38],["H6213","but they that deal",40,58],["H0530","truly",59,64],["H7522","are his delight",65,80]]},"12:23":{"text":"A prudent man concealeth knowledge: but the heart of fools proclaimeth foolishness.","words":[["H6175","A prudent",0,9],["H0120","man",10,13],["H3680","concealeth",14,24],["H1847","knowledge",25,34],["H3820","but the heart",36,49],["H3684","of fools",50,58],["H7121","proclaimeth",59,70],["H0200","foolishness",71,82]]},"12:24":{"text":"The hand of the diligent shall bear rule: but the slothful shall be under tribute.","words":[["H3027","The hand",0,8],["H2742","of the diligent",9,24],["H4910","shall bear rule",25,40],["H7423","but the slothful",42,58],["H4522","shall be under tribute",59,81]]},"12:25":{"text":"Heaviness in the heart of man maketh it stoop: but a good word maketh it glad.","words":[["H1674","Heaviness",0,9],["H3820","in the heart",10,22],["H0376","of man",23,29],["H7812","maketh it stoop",30,45],["H2896","but a good",47,57],["H1697","word",58,62],["H8055","maketh it glad",63,77]]},"12:26":{"text":"The righteous is more excellent than his neighbour: but the way of the wicked seduceth them.","words":[["H6662","The righteous",0,13],["H8446","is more excellent",14,31],["H7453","than his neighbour",32,50],["H1870","but the way",52,63],["H7563","of the wicked",64,77],["H8582","seduceth",78,86]]},"12:27":{"text":"The slothful man roasteth not that which he took in hunting: but the substance of a diligent man is precious.","words":[["H7423","The slothful",0,12],["H2760","man roasteth",13,25],["H6718","not that which he took in hunting",26,59],["H1952","but the substance",61,78],["H2742","of a diligent",79,92],["H0120","man",93,96],["H3368","is precious",97,108]]},"12:28":{"text":"In the way of righteousness is life; and in the pathway thereof there is no death.","words":[["H0734","In the way",0,10],["H6666","of righteousness",11,27],["H2416","is life",28,35],["H5410","and in the pathway",37,55],["H1870","and in the pathway",37,55],["H4194","thereof there is no death",56,81]]},"13:1":{"text":"A wise son heareth his father's instruction: but a scorner heareth not rebuke.","words":[["H2450","A wise",0,6],["H1121","son",7,10],["H0001","heareth his father's",11,31],["H4148","instruction",32,43],["H3887","but a scorner",45,58],["H8085","heareth",59,66],["H1606","not rebuke",67,77]]},"13:2":{"text":"A man shall eat good by the fruit of his mouth: but the soul of the transgressors shall eat violence.","words":[["H0376","A man",0,5],["H0398","shall eat",6,15],["H2896","good",16,20],["H6529","by the fruit",21,33],["H6310","of his mouth",34,46],["H5315","but the soul",48,60],["H0898","of the transgressors",61,81],["H2555","shall eat violence",82,100]]},"13:3":{"text":"He that keepeth his mouth keepeth his life: but he that openeth wide his lips shall have destruction.","words":[["H5341","He that keepeth",0,15],["H6310","his mouth",16,25],["H8104","keepeth",26,33],["H5315","his life",34,42],["H6589","but he that openeth wide",44,68],["H8193","his lips",69,77],["H4288","shall have destruction",78,100]]},"13:4":{"text":"The soul of the sluggard desireth, and hath nothing: but the soul of the diligent shall be made fat.","words":[["H5315","The soul",0,8],["H6102","of the sluggard",9,24],["H0183","desireth",25,33],["H5315","and hath nothing: but the soul",35,65],["H2742","of the diligent",66,81],["H1878","shall be made fat",82,99]]},"13:5":{"text":"A righteous man hateth lying: but a wicked man is loathsome, and cometh to shame.","words":[["H6662","A righteous",0,11],["H8130","man hateth",12,22],["H1697","lying",23,28],["H8267","lying",23,28],["H7563","but a wicked",30,42],["H0887","man is loathsome",43,59],["H2659","and cometh to shame",61,80]]},"13:6":{"text":"Righteousness keepeth him that is upright in the way: but wickedness overthroweth the sinner.","words":[["H6666","Righteousness",0,13],["H5341","keepeth",14,21],["H8537","him that is upright",22,41],["H1870","in the way",42,52],["H7564","but wickedness",54,68],["H5557","overthroweth",69,81],["H2403","the sinner",82,92]]},"13:7":{"text":"There is that maketh himself rich, yet hath nothing: there is that maketh himself poor, yet hath great riches.","words":[["H3426","There is",0,8],["H6238","that maketh himself rich",9,33],["H7326","yet hath nothing: there is that maketh himself poor",35,86],["H3605","yet",88,91],["H7227","hath great",92,102],["H1952","riches",103,109]]},"13:8":{"text":"The ransom of a man's life are his riches: but the poor heareth not rebuke.","words":[["H3724","The ransom",0,10],["H0376","of a man's",11,21],["H5315","life",22,26],["H6239","are his riches",27,41],["H7326","but the poor",43,55],["H8085","heareth",56,63],["H1606","not rebuke",64,74]]},"13:9":{"text":"The light of the righteous rejoiceth: but the lamp of the wicked shall be put out.","words":[["H0216","The light",0,9],["H6662","of the righteous",10,26],["H8055","rejoiceth",27,36],["H5216","but the lamp",38,50],["H7563","of the wicked",51,64],["H1846","shall be put out",65,81]]},"13:10":{"text":"Only by pride cometh contention: but with the well advised is wisdom.","words":[["H2087","Only by pride",0,13],["H5414","cometh",14,20],["H4683","contention",21,31],["H3289","but with the well advised",33,58],["H2451","is wisdom",59,68]]},"13:11":{"text":"Wealth gotten by vanity shall be diminished: but he that gathereth by labour shall increase.","words":[["H1952","Wealth",0,6],["H1892","gotten by vanity",7,23],["H4591","shall be diminished",24,43],["H6908","but he that gathereth",45,66],["H3027","by labour",67,76],["H7235","shall increase",77,91]]},"13:12":{"text":"Hope deferred maketh the heart sick: but when the desire cometh, it is a tree of life.","words":[["H8431","Hope",0,4],["H4900","deferred",5,13],["H3820","maketh the heart",14,30],["H2470","sick",31,35],["H8378","but when the desire",37,56],["H0935","cometh",57,63],["H6086","it is a tree",65,77],["H2416","of life",78,85]]},"13:13":{"text":"Whoso despiseth the word shall be destroyed: but he that feareth the commandment shall be rewarded.","words":[["H0936","Whoso despiseth",0,15],["H1697","the word",16,24],["H2254","shall be destroyed",25,43],["H3373","but he that feareth",45,64],["H4687","the commandment",65,80],["H7999","shall be rewarded",81,98]]},"13:14":{"text":"The law of the wise is a fountain of life, to depart from the snares of death.","words":[["H8451","The law",0,7],["H2450","of the wise",8,19],["H4726","is a fountain",20,33],["H2416","of life",34,41],["H5493","to depart",43,52],["H4170","from the snares",53,68],["H4194","of death",69,77]]},"13:15":{"text":"Good understanding giveth favour: but the way of transgressors is hard.","words":[["H2896","Good",0,4],["H7922","understanding",5,18],["H5414","giveth",19,25],["H2580","favour",26,32],["H1870","but the way",34,45],["H0898","of transgressors",46,62],["H0386","is hard",63,70]]},"13:16":{"text":"Every prudent man dealeth with knowledge: but a fool layeth open his folly.","words":[["H6175","Every prudent",0,13],["H6213","man dealeth",14,25],["H1847","with knowledge",26,40],["H3684","but a fool",42,52],["H6566","layeth open",53,64],["H0200","his folly",65,74]]},"13:17":{"text":"A wicked messenger falleth into mischief: but a faithful ambassador is health.","words":[["H7563","A wicked",0,8],["H4397","messenger",9,18],["H5307","falleth",19,26],["H7451","into mischief",27,40],["H0529","but a faithful",42,56],["H6735","ambassador",57,67],["H4832","is health",68,77]]},"13:18":{"text":"Poverty and shame shall be to him that refuseth instruction: but he that regardeth reproof shall be honoured.","words":[["H7389","Poverty",0,7],["H7036","and shame",8,17],["H6544","shall be to him that refuseth",18,47],["H4148","instruction",48,59],["H8104","but he that regardeth",61,82],["H8433","reproof",83,90],["H3513","shall be honoured",91,108]]},"13:19":{"text":"The desire accomplished is sweet to the soul: but it is abomination to fools to depart from evil.","words":[["H8378","The desire",0,10],["H1961","accomplished",11,23],["H6149","is sweet",24,32],["H5315","to the soul",33,44],["H8441","but it is abomination",46,67],["H3684","to fools",68,76],["H5493","to depart",77,86],["H7451","from evil",87,96]]},"13:20":{"text":"He that walketh with wise men shall be wise: but a companion of fools shall be destroyed.","words":[["H1980","He that walketh",0,15],["H2450","with wise",16,25],["H2449","men shall be wise",26,43],["H7462","but a companion",45,60],["H3684","of fools",61,69],["H7321","shall be destroyed",70,88]]},"13:21":{"text":"Evil pursueth sinners: but to the righteous good shall be repayed.","words":[["H7451","Evil",0,4],["H7291","pursueth",5,13],["H2400","sinners",14,21],["H6662","but to the righteous",23,43],["H2896","good",44,48],["H7999","shall be repayed",49,65]]},"13:22":{"text":"A good man leaveth an inheritance to his children's children: and the wealth of the sinner is laid up for the just.","words":[["H2896","A good",0,6],["H5157","man leaveth an inheritance",7,33],["H1121","to his children's",34,51],["H1121","children",52,60],["H2428","and the wealth",62,76],["H2398","of the sinner",77,90],["H6845","is laid up",91,101],["H6662","for the just",102,114]]},"13:23":{"text":"Much food is in the tillage of the poor: but there is that is destroyed for want of judgment.","words":[["H7230","Much",0,4],["H0400","food",5,9],["H5215","is in the tillage",10,27],["H7218","of the poor",28,39],["H7326","of the poor",28,39],["H3426","but there is",41,53],["H5595","that is destroyed",54,71],["H3808","for want",72,80],["H4941","of judgment",81,92]]},"13:24":{"text":"He that spareth his rod hateth his son: but he that loveth him chasteneth him betimes.","words":[["H2820","He that spareth",0,15],["H7626","his rod",16,23],["H8130","hateth",24,30],["H1121","his son",31,38],["H0157","but he that loveth",40,58],["H4148","him chasteneth",59,73],["H7836","him betimes",74,85]]},"13:25":{"text":"The righteous eateth to the satisfying of his soul: but the belly of the wicked shall want.","words":[["H6662","The righteous",0,13],["H0398","eateth",14,20],["H7648","to the satisfying",21,38],["H5315","of his soul",39,50],["H0990","but the belly",52,65],["H7563","of the wicked",66,79],["H2637","shall want",80,90]]},"14:1":{"text":"Every wise woman buildeth her house: but the foolish plucketh it down with her hands.","words":[["H2454","Every wise",0,10],["H0802","woman",11,16],["H1129","buildeth",17,25],["H1004","her house",26,35],["H0200","but the foolish",37,52],["H2040","plucketh it down",53,69],["H3027","with her hands",70,84]]},"14:2":{"text":"He that walketh in his uprightness feareth the LORD: but he that is perverse in his ways despiseth him.","words":[["H1980","He that walketh",0,15],["H3476","in his uprightness",16,34],["H3373","feareth",35,42],["H3068","the LORD",43,51],["H3868","but he that is perverse",53,76],["H1870","in his ways",77,88],["H0959","despiseth",89,98]]},"14:3":{"text":"In the mouth of the foolish is a rod of pride: but the lips of the wise shall preserve them.","words":[["H6310","In the mouth",0,12],["H0191","of the foolish",13,27],["H2415","is a rod",28,36],["H1346","of pride",37,45],["H8193","but the lips",47,59],["H2450","of the wise",60,71],["H8104","shall preserve",72,86]]},"14:4":{"text":"Where no oxen are, the crib is clean: but much increase is by the strength of the ox.","words":[["H0504","Where no oxen",0,13],["H0018","are, the crib",14,27],["H1249","is clean",28,36],["H7230","but much",38,46],["H8393","increase",47,55],["H3581","is by the strength",56,74],["H7794","of the ox",75,84]]},"14:5":{"text":"A faithful witness will not lie: but a false witness will utter lies.","words":[["H0529","A faithful",0,10],["H5707","witness",11,18],["H3577","will not lie",19,31],["H8267","but a false",33,44],["H5707","witness",45,52],["H6315","will utter",53,63],["H3576","lies",64,68]]},"14:6":{"text":"A scorner seeketh wisdom, and findeth it not: but knowledge is easy unto him that understandeth.","words":[["H3887","A scorner",0,9],["H1245","seeketh",10,17],["H2451","wisdom",18,24],["H1847","and findeth it not: but knowledge",26,59],["H7043","is easy",60,67],["H0995","unto him that understandeth",68,95]]},"14:7":{"text":"Go from the presence of a foolish man, when thou perceivest not in him the lips of knowledge.","words":[["H3212","Go",0,2],["H5048","from the presence",3,20],["H3684","of a foolish",21,33],["H0376","man",34,37],["H3045","when thou perceivest",39,59],["H8193","not in him the lips",60,79],["H1847","of knowledge",80,92]]},"14:8":{"text":"The wisdom of the prudent is to understand his way: but the folly of fools is deceit.","words":[["H2451","The wisdom",0,10],["H6175","of the prudent",11,25],["H0995","is to understand",26,42],["H1870","his way",43,50],["H0200","but the folly",52,65],["H3684","of fools",66,74],["H4820","is deceit",75,84]]},"14:9":{"text":"Fools make a mock at sin: but among the righteous there is favour.","words":[["H0191","Fools",0,5],["H3887","make a mock",6,17],["H0817","at sin",18,24],["H3477","but among the righteous",26,49],["H7522","there is favour",50,65]]},"14:10":{"text":"The heart knoweth his own bitterness; and a stranger doth not intermeddle with his joy.","words":[["H3820","The heart",0,9],["H3045","knoweth",10,17],["H5315","his own",18,25],["H4787","bitterness",26,36],["H2114","and a stranger",38,52],["H6148","doth not intermeddle",53,73],["H8057","with his joy",74,86]]},"14:11":{"text":"The house of the wicked shall be overthrown: but the tabernacle of the upright shall flourish.","words":[["H1004","The house",0,9],["H7563","of the wicked",10,23],["H8045","shall be overthrown",24,43],["H0168","but the tabernacle",45,63],["H3477","of the upright",64,78],["H6524","shall flourish",79,93]]},"14:12":{"text":"There is a way which seemeth right unto a man, but the end thereof are the ways of death.","words":[["H3426","There is",0,8],["H1870","a way",9,14],["H3477","which seemeth right",15,34],["H6440","unto",35,39],["H0376","a man",40,45],["H0319","but the end",47,58],["H1870","thereof are the ways",59,79],["H4194","of death",80,88]]},"14:13":{"text":"Even in laughter the heart is sorrowful; and the end of that mirth is heaviness.","words":[["H7814","Even in laughter",0,16],["H3820","the heart",17,26],["H3510","is sorrowful",27,39],["H0319","and the end",41,52],["H8057","of that mirth",53,66],["H8424","is heaviness",67,79]]},"14:14":{"text":"The backslider in heart shall be filled with his own ways: and a good man shall be satisfied from himself.","words":[["H5472","The backslider",0,14],["H3820","in heart",15,23],["H7646","shall be filled",24,39],["H1870","with his own ways",40,57],["H2896","and a good",59,69],["H0376","man",70,73]]},"14:15":{"text":"The simple believeth every word: but the prudent man looketh well to his going.","words":[["H6612","The simple",0,10],["H0539","believeth",11,20],["H1697","every word",21,31],["H6175","but the prudent",33,48],["H0995","man looketh well",49,65],["H0838","to his going",66,78]]},"14:16":{"text":"A wise man feareth, and departeth from evil: but the fool rageth, and is confident.","words":[["H2450","A wise",0,6],["H3373","man feareth",7,18],["H5493","and departeth",20,33],["H7451","from evil",34,43],["H3684","but the fool",45,57],["H5674","rageth",58,64],["H0982","and is confident",66,82]]},"14:17":{"text":"He that is soon angry dealeth foolishly: and a man of wicked devices is hated.","words":[["H7116","He that is soon",0,15],["H0639","angry",16,21],["H6213","dealeth",22,29],["H0200","foolishly",30,39],["H0376","and a man",41,50],["H4209","of wicked devices",51,68],["H8130","is hated",69,77]]},"14:18":{"text":"The simple inherit folly: but the prudent are crowned with knowledge.","words":[["H6612","The simple",0,10],["H5157","inherit",11,18],["H0200","folly",19,24],["H6175","but the prudent",26,41],["H3803","are crowned",42,53],["H1847","with knowledge",54,68]]},"14:19":{"text":"The evil bow before the good; and the wicked at the gates of the righteous.","words":[["H7451","The evil",0,8],["H7817","bow",9,12],["H6440","before",13,19],["H2896","the good",20,28],["H7563","and the wicked",30,44],["H8179","at the gates",45,57],["H6662","of the righteous",58,74]]},"14:20":{"text":"The poor is hated even of his own neighbour: but the rich hath many friends.","words":[["H7326","The poor",0,8],["H8130","is hated",9,17],["H7453","even of his own neighbour",18,43],["H6223","but the rich",45,57],["H7227","hath many",58,67],["H0157","friends",68,75]]},"14:21":{"text":"He that despiseth his neighbour sinneth: but he that hath mercy on the poor, happy is he.","words":[["H0936","He that despiseth",0,17],["H7453","his neighbour",18,31],["H2398","sinneth",32,39],["H2603","but he that hath mercy",41,63],["H6035","on the poor",64,75],["H6041","on the poor",64,75],["H0835","happy",77,82]]},"14:22":{"text":"Do they not err that devise evil? but mercy and truth shall be to them that devise good.","words":[["H8582","Do they not err",0,15],["H2790","that devise",16,27],["H7451","evil",28,32],["H2617","but mercy",34,43],["H0571","and truth",44,53],["H2790","shall be to them that devise",54,82],["H2896","good",83,87]]},"14:23":{"text":"In all labour there is profit: but the talk of the lips tendeth only to penury.","words":[["H6089","In all labour",0,13],["H4195","there is profit",14,29],["H1697","but the talk",31,43],["H8193","of the lips",44,55],["H4270","tendeth only to penury",56,78]]},"14:24":{"text":"The crown of the wise is their riches: but the foolishness of fools is folly.","words":[["H5850","The crown",0,9],["H2450","of the wise",10,21],["H6239","is their riches",22,37],["H0200","but the foolishness",39,58],["H3684","of fools",59,67],["H0200","is folly",68,76]]},"14:25":{"text":"A true witness delivereth souls: but a deceitful witness speaketh lies.","words":[["H0571","A true",0,6],["H5707","witness",7,14],["H5337","delivereth",15,25],["H5315","souls",26,31],["H4820","but a deceitful",33,48],["H6315","witness speaketh",49,65],["H3577","lies",66,70]]},"14:26":{"text":"In the fear of the LORD is strong confidence: and his children shall have a place of refuge.","words":[["H3374","In the fear",0,11],["H3068","of the LORD",12,23],["H5797","is strong",24,33],["H4009","confidence",34,44],["H1121","and his children",46,62],["H4268","shall have a place of refuge",63,91]]},"14:27":{"text":"The fear of the LORD is a fountain of life, to depart from the snares of death.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H4726","is a fountain",21,34],["H2416","of life",35,42],["H5493","to depart",44,53],["H4170","from the snares",54,69],["H4194","of death",70,78]]},"14:28":{"text":"In the multitude of people is the king's honour: but in the want of people is the destruction of the prince.","words":[["H7230","In the multitude",0,16],["H5971","of people",17,26],["H4428","is the king's",27,40],["H1927","honour",41,47],["H0657","but in the want",49,64],["H3816","of people",65,74],["H4288","is the destruction",75,93],["H7333","of the prince",94,107]]},"14:29":{"text":"He that is slow to wrath is of great understanding: but he that is hasty of spirit exalteth folly.","words":[["H0750","He that is slow",0,15],["H0639","to wrath",16,24],["H7227","is of great",25,36],["H8394","understanding",37,50],["H7116","but he that is hasty",52,72],["H7307","of spirit",73,82],["H7311","exalteth",83,91],["H0200","folly",92,97]]},"14:30":{"text":"A sound heart is the life of the flesh: but envy the rottenness of the bones.","words":[["H4832","A sound",0,7],["H3820","heart",8,13],["H2416","is the life",14,25],["H1320","of the flesh",26,38],["H7068","but envy",40,48],["H7538","the rottenness",49,63],["H6106","of the bones",64,76]]},"14:31":{"text":"He that oppresseth the poor reproacheth his Maker: but he that honoureth him hath mercy on the poor.","words":[["H6231","He that oppresseth",0,18],["H1800","the poor",19,27],["H2778","reproacheth",28,39],["H6213","his Maker",40,49],["H3513","but he that honoureth",51,72],["H2603","him hath mercy",73,87],["H0034","on the poor",88,99]]},"14:32":{"text":"The wicked is driven away in his wickedness: but the righteous hath hope in his death.","words":[["H7563","The wicked",0,10],["H1760","is driven away",11,25],["H7451","in his wickedness",26,43],["H6662","but the righteous",45,62],["H2620","hath hope",63,72],["H4194","in his death",73,85]]},"14:33":{"text":"Wisdom resteth in the heart of him that hath understanding: but that which is in the midst of fools is made known.","words":[["H2451","Wisdom",0,6],["H5117","resteth",7,14],["H3820","in the heart",15,27],["H0995","of him that hath understanding",28,58],["H7130","but that which is in the midst",60,90],["H3684","of fools",91,99],["H3045","is made known",100,113]]},"14:34":{"text":"Righteousness exalteth a nation: but sin is a reproach to any people.","words":[["H6666","Righteousness",0,13],["H7311","exalteth",14,22],["H1471","a nation",23,31],["H2403","but sin",33,40],["H2617","is a reproach",41,54],["H3816","to any people",55,68]]},"14:35":{"text":"The king's favour is toward a wise servant: but his wrath is against him that causeth shame.","words":[["H4428","The king's",0,10],["H7522","favour",11,17],["H7919","is toward a wise",18,34],["H5650","servant",35,42],["H5678","but his wrath",44,57],["H0954","is against him that causeth shame",58,91]]},"15:1":{"text":"A soft answer turneth away wrath: but grievous words stir up anger.","words":[["H7390","A soft",0,6],["H4617","answer",7,13],["H7725","turneth",14,21],["H2534","away wrath",22,32],["H6089","but grievous",34,46],["H1697","words",47,52],["H5927","stir up",53,60],["H0639","anger",61,66]]},"15:2":{"text":"The tongue of the wise useth knowledge aright: but the mouth of fools poureth out foolishness.","words":[["H3956","The tongue",0,10],["H2450","of the wise",11,22],["H1847","useth knowledge",23,38],["H3190","aright",39,45],["H6310","but the mouth",47,60],["H3684","of fools",61,69],["H5042","poureth out",70,81],["H0200","foolishness",82,93]]},"15:3":{"text":"The eyes of the LORD are in every place, beholding the evil and the good.","words":[["H5869","The eyes",0,8],["H3068","of the LORD",9,20],["H4725","are in every place",21,39],["H6822","beholding",41,50],["H7451","the evil",51,59],["H2896","and the good",60,72]]},"15:4":{"text":"A wholesome tongue is a tree of life: but perverseness therein is a breach in the spirit.","words":[["H4832","A wholesome",0,11],["H3956","tongue",12,18],["H6086","is a tree",19,28],["H2416","of life",29,36],["H5558","but perverseness",38,54],["H7667","therein is a breach",55,74],["H7307","in the spirit",75,88]]},"15:5":{"text":"A fool despiseth his father's instruction: but he that regardeth reproof is prudent.","words":[["H0191","A fool",0,6],["H5006","despiseth",7,16],["H0001","his father's",17,29],["H4148","instruction",30,41],["H8104","but he that regardeth",43,64],["H8433","reproof",65,72],["H6191","is prudent",73,83]]},"15:6":{"text":"In the house of the righteous is much treasure: but in the revenues of the wicked is trouble.","words":[["H1004","In the house",0,12],["H6662","of the righteous",13,29],["H7227","is much",30,37],["H2633","treasure",38,46],["H8393","but in the revenues",48,67],["H7563","of the wicked",68,81],["H5916","is trouble",82,92]]},"15:7":{"text":"The lips of the wise disperse knowledge: but the heart of the foolish doeth not so.","words":[["H8193","The lips",0,8],["H2450","of the wise",9,20],["H2219","disperse",21,29],["H1847","knowledge",30,39],["H3820","but the heart",41,54],["H3684","of the foolish",55,69]]},"15:8":{"text":"The sacrifice of the wicked is an abomination to the LORD: but the prayer of the upright is his delight.","words":[["H2077","The sacrifice",0,13],["H7563","of the wicked",14,27],["H8441","is an abomination",28,45],["H3068","to the LORD",46,57],["H8605","but the prayer",59,73],["H3477","of the upright",74,88],["H7522","is his delight",89,103]]},"15:9":{"text":"The way of the wicked is an abomination unto the LORD: but he loveth him that followeth after righteousness.","words":[["H1870","The way",0,7],["H7563","of the wicked",8,21],["H8441","is an abomination",22,39],["H3068","unto the LORD",40,53],["H0157","but he loveth",55,68],["H7291","him that followeth",69,87],["H6666","after righteousness",88,107]]},"15:10":{"text":"Correction is grievous unto him that forsaketh the way: and he that hateth reproof shall die.","words":[["H4148","Correction",0,10],["H7451","is grievous",11,22],["H5800","unto him that forsaketh",23,46],["H0734","the way",47,54],["H8130","and he that hateth",56,74],["H8433","reproof",75,82],["H4191","shall die",83,92]]},"15:11":{"text":"Hell and destruction are before the LORD: how much more then the hearts of the children of men?","words":[["H7585","Hell",0,4],["H0011","and destruction",5,20],["H3068","are before the LORD",21,40],["H3826","how much more then the hearts",42,71],["H1121","of the children",72,87],["H0120","of men",88,94]]},"15:12":{"text":"A scorner loveth not one that reproveth him: neither will he go unto the wise.","words":[["H3887","A scorner",0,9],["H0157","loveth",10,16],["H3198","not one that reproveth",17,39],["H3212","him: neither will he go",40,63],["H2450","unto the wise",64,77]]},"15:13":{"text":"A merry heart maketh a cheerful countenance: but by sorrow of the heart the spirit is broken.","words":[["H8056","A merry",0,7],["H3820","heart",8,13],["H3190","maketh a cheerful",14,31],["H6440","countenance",32,43],["H6094","but by sorrow",45,58],["H3820","of the heart",59,71],["H7307","the spirit",72,82],["H5218","is broken",83,92]]},"15:14":{"text":"The heart of him that hath understanding seeketh knowledge: but the mouth of fools feedeth on foolishness.","words":[["H3820","The heart",0,9],["H0995","of him that hath understanding",10,40],["H1245","seeketh",41,48],["H1847","knowledge",49,58],["H6310","but the mouth",60,73],["H6440","but the mouth",60,73],["H3684","of fools",74,82],["H7462","feedeth",83,90],["H0200","on foolishness",91,105]]},"15:15":{"text":"All the days of the afflicted are evil: but he that is of a merry heart hath a continual feast.","words":[["H3117","All the days",0,12],["H6041","of the afflicted",13,29],["H7451","are evil",30,38],["H2896","but he that is of a merry",40,65],["H3820","heart",66,71],["H8548","hath a continual",72,88],["H4960","feast",89,94]]},"15:16":{"text":"Better is little with the fear of the LORD than great treasure and trouble therewith.","words":[["H2896","Better",0,6],["H4592","is little",7,16],["H3374","with the fear",17,30],["H3068","of the LORD",31,42],["H7227","than great",43,53],["H0214","treasure",54,62],["H4103","and trouble",63,74]]},"15:17":{"text":"Better is a dinner of herbs where love is, than a stalled ox and hatred therewith.","words":[["H2896","Better",0,6],["H0737","is a dinner",7,18],["H3419","of herbs",19,27],["H0160","where love",28,38],["H0075","is, than a stalled",39,57],["H7794","ox",58,60],["H8135","and hatred",61,71]]},"15:18":{"text":"A wrathful man stirreth up strife: but he that is slow to anger appeaseth strife.","words":[["H2534","A wrathful",0,10],["H0376","man",11,14],["H1624","stirreth up",15,26],["H4066","strife",27,33],["H0750","but he that is slow",35,54],["H0639","to anger",55,63],["H8252","appeaseth",64,73],["H7379","strife",74,80]]},"15:19":{"text":"The way of the slothful man is as an hedge of thorns: but the way of the righteous is made plain.","words":[["H1870","The way",0,7],["H6102","of the slothful",8,23],["H4881","man is as an hedge",24,42],["H2312","of thorns",43,52],["H0734","but the way",54,65],["H3477","of the righteous",66,82],["H5549","is made plain",83,96]]},"15:20":{"text":"A wise son maketh a glad father: but a foolish man despiseth his mother.","words":[["H2450","A wise",0,6],["H1121","son",7,10],["H8055","maketh a glad",11,24],["H0001","father",25,31],["H3684","but a foolish",33,46],["H0120","man",47,50],["H0959","despiseth",51,60],["H0517","his mother",61,71]]},"15:21":{"text":"Folly is joy to him that is destitute of wisdom: but a man of understanding walketh uprightly.","words":[["H0200","Folly",0,5],["H8057","is joy",6,12],["H2638","to him that is destitute",13,37],["H3820","of wisdom",38,47],["H0376","but a man",49,58],["H8394","of understanding",59,75],["H3212","walketh",76,83],["H3474","uprightly",84,93]]},"15:22":{"text":"Without counsel purposes are disappointed: but in the multitude of counsellors they are established.","words":[["H5475","Without counsel",0,15],["H4284","purposes",16,24],["H6565","are disappointed",25,41],["H7230","but in the multitude",43,63],["H3289","of counsellors",64,78],["H6965","they are established",79,99]]},"15:23":{"text":"A man hath joy by the answer of his mouth: and a word spoken in due season, how good is it!","words":[["H0376","A man",0,5],["H8057","hath joy",6,14],["H4617","by the answer",15,28],["H6310","of his mouth",29,41],["H1697","and a word",43,53],["H6256","spoken in due season",54,74],["H2896","how good",76,84]]},"15:24":{"text":"The way of life is above to the wise, that he may depart from hell beneath.","words":[["H0734","The way",0,7],["H2416","of life",8,15],["H4605","is above",16,24],["H7919","to the wise",25,36],["H5493","that he may depart",38,56],["H7585","from hell",57,66],["H4295","beneath",67,74]]},"15:25":{"text":"The LORD will destroy the house of the proud: but he will establish the border of the widow.","words":[["H3068","The LORD",0,8],["H5255","will destroy",9,21],["H1004","the house",22,31],["H1343","of the proud",32,44],["H5324","but he will establish",46,67],["H1366","the border",68,78],["H0490","of the widow",79,91]]},"15:26":{"text":"The thoughts of the wicked are an abomination to the LORD: but the words of the pure are pleasant words.","words":[["H4284","The thoughts",0,12],["H7451","of the wicked",13,26],["H8441","are an abomination",27,45],["H3068","to the LORD",46,57],["H2889","but the words of the pure",59,84],["H5278","are pleasant",85,97],["H0561","words",98,103]]},"15:27":{"text":"He that is greedy of gain troubleth his own house; but he that hateth gifts shall live.","words":[["H1214","He that is greedy",0,17],["H1215","of gain",18,25],["H5916","troubleth",26,35],["H1004","his own house",36,49],["H8130","but he that hateth",51,69],["H4979","gifts",70,75],["H2421","shall live",76,86]]},"15:28":{"text":"The heart of the righteous studieth to answer: but the mouth of the wicked poureth out evil things.","words":[["H3820","The heart",0,9],["H6662","of the righteous",10,26],["H1897","studieth",27,35],["H6030","to answer",36,45],["H6310","but the mouth",47,60],["H7563","of the wicked",61,74],["H5042","poureth",75,82],["H7451","out evil things",83,98]]},"15:29":{"text":"The LORD is far from the wicked: but he heareth the prayer of the righteous.","words":[["H3068","The LORD",0,8],["H7350","is far",9,15],["H7563","from the wicked",16,31],["H8085","but he heareth",33,47],["H8605","the prayer",48,58],["H6662","of the righteous",59,75]]},"15:30":{"text":"The light of the eyes rejoiceth the heart: and a good report maketh the bones fat.","words":[["H3974","The light",0,9],["H5869","of the eyes",10,21],["H8055","rejoiceth",22,31],["H3820","the heart",32,41],["H2896","and a good",43,53],["H8052","report",54,60],["H1878","maketh",61,67],["H6106","the bones",68,77],["H1878","fat",78,81]]},"15:31":{"text":"The ear that heareth the reproof of life abideth among the wise.","words":[["H0241","The ear",0,7],["H8085","that heareth",8,20],["H8433","the reproof",21,32],["H2416","of life",33,40],["H3885","abideth",41,48],["H7130","among",49,54],["H2450","the wise",55,63]]},"15:32":{"text":"He that refuseth instruction despiseth his own soul: but he that heareth reproof getteth understanding.","words":[["H6544","He that refuseth",0,16],["H4148","instruction",17,28],["H3988","despiseth",29,38],["H5315","his own soul",39,51],["H8085","but he that heareth",53,72],["H8433","reproof",73,80],["H7069","getteth",81,88],["H3820","understanding",89,102]]},"15:33":{"text":"The fear of the LORD is the instruction of wisdom; and before honour is humility.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H4148","is the instruction",21,39],["H2451","of wisdom",40,49],["H6440","and before",51,61],["H3519","honour",62,68],["H6038","is humility",69,80]]},"16:1":{"text":"The preparations of the heart in man, and the answer of the tongue, is from the LORD.","words":[["H4633","The preparations",0,16],["H3820","of the heart",17,29],["H0120","in man",30,36],["H4617","and the answer",38,52],["H3956","of the tongue",53,66],["H3068","is from the LORD",68,84]]},"16:2":{"text":"All the ways of a man are clean in his own eyes; but the LORD weigheth the spirits.","words":[["H1870","All the ways",0,12],["H0376","of a man",13,21],["H2134","are clean",22,31],["H5869","in his own eyes",32,47],["H3068","but the LORD",49,61],["H8505","weigheth",62,70],["H7307","the spirits",71,82]]},"16:3":{"text":"Commit thy works unto the LORD, and thy thoughts shall be established.","words":[["H1556","Commit",0,6],["H4639","thy works",7,16],["H3068","unto the LORD",17,30],["H4284","and thy thoughts",32,48],["H3559","shall be established",49,69]]},"16:4":{"text":"The LORD hath made all things for himself: yea, even the wicked for the day of evil.","words":[["H3068","The LORD",0,8],["H6466","hath made",9,18],["H4617","all things for himself",19,41],["H7563","yea, even the wicked",43,63],["H3117","for the day",64,75],["H7451","of evil",76,83]]},"16:5":{"text":"Every one that is proud in heart is an abomination to the LORD: though hand join in hand, he shall not be unpunished.","words":[["H1362","Every one that is proud",0,23],["H3820","in heart",24,32],["H8441","is an abomination",33,50],["H3068","to the LORD",51,62],["H3027","though hand",64,75],["H3027","join in hand",76,88],["H5352","he shall not be unpunished",90,116]]},"16:6":{"text":"By mercy and truth iniquity is purged: and by the fear of the LORD men depart from evil.","words":[["H2617","By mercy",0,8],["H0571","and truth",9,18],["H5771","iniquity",19,27],["H3722","is purged",28,37],["H3374","and by the fear",39,54],["H3068","of the LORD",55,66],["H5493","men depart",67,77],["H7451","from evil",78,87]]},"16:7":{"text":"When a man's ways please the LORD, he maketh even his enemies to be at peace with him.","words":[["H0376","When a man's",0,12],["H1870","ways",13,17],["H7521","please",18,24],["H3068","the LORD",25,33],["H0341","he maketh even his enemies",35,61],["H7999","to be at peace",62,76]]},"16:8":{"text":"Better is a little with righteousness than great revenues without right.","words":[["H2896","Better",0,6],["H4592","is a little",7,18],["H6666","with righteousness",19,37],["H7230","than great",38,48],["H8393","revenues",49,57],["H4941","without right",58,71]]},"16:9":{"text":"A man's heart deviseth his way: but the LORD directeth his steps.","words":[["H0120","A man's",0,7],["H3820","heart",8,13],["H2803","deviseth",14,22],["H1870","his way",23,30],["H3068","but the LORD",32,44],["H3559","directeth",45,54],["H6806","his steps",55,64]]},"16:10":{"text":"A divine sentence is in the lips of the king: his mouth transgresseth not in judgment.","words":[["H7081","A divine sentence",0,17],["H8193","is in the lips",18,32],["H4428","of the king",33,44],["H6310","his mouth",46,55],["H4603","transgresseth",56,69],["H4941","not in judgment",70,85]]},"16:11":{"text":"A just weight and balance are the LORD'S: all the weights of the bag are his work.","words":[["H4941","A just",0,6],["H6425","weight",7,13],["H3976","and balance",14,25],["H3068","are the LORD'S",26,40],["H0068","all the weights",42,57],["H3599","of the bag",58,68],["H4639","are his work",69,81]]},"16:12":{"text":"It is an abomination to kings to commit wickedness: for the throne is established by righteousness.","words":[["H8441","It is an abomination",0,20],["H4428","to kings",21,29],["H6213","to commit",30,39],["H7562","wickedness",40,50],["H3678","for the throne",52,66],["H3559","is established",67,81],["H6666","by righteousness",82,98]]},"16:13":{"text":"Righteous lips are the delight of kings; and they love him that speaketh right.","words":[["H6664","Righteous",0,9],["H8193","lips",10,14],["H7522","are the delight",15,30],["H4428","of kings",31,39],["H0157","and they love",41,54],["H1696","him that speaketh",55,72],["H3477","right",73,78]]},"16:14":{"text":"The wrath of a king is as messengers of death: but a wise man will pacify it.","words":[["H2534","The wrath",0,9],["H4428","of a king",10,19],["H4397","is as messengers",20,36],["H4194","of death",37,45],["H2450","but a wise",47,57],["H0376","man",58,61],["H3722","will pacify",62,73]]},"16:15":{"text":"In the light of the king's countenance is life; and his favour is as a cloud of the latter rain.","words":[["H0216","In the light",0,12],["H4428","of the king's",13,26],["H6440","countenance",27,38],["H2416","is life",39,46],["H7522","and his favour",48,62],["H5645","is as a cloud",63,76],["H4456","of the latter rain",77,95]]},"16:16":{"text":"How much better is it to get wisdom than gold! and to get understanding rather to be chosen than silver!","words":[["H2896","How much better",0,15],["H7069","is it to get",16,28],["H2451","wisdom",29,35],["H2742","than gold",36,45],["H7069","and to get",47,57],["H0998","understanding",58,71],["H0977","rather to be chosen",72,91],["H3701","than silver",92,103]]},"16:17":{"text":"The highway of the upright is to depart from evil: he that keepeth his way preserveth his soul.","words":[["H4546","The highway",0,11],["H3477","of the upright",12,26],["H5493","is to depart",27,39],["H7451","from evil",40,49],["H5341","he that keepeth",51,66],["H1870","his way",67,74],["H8104","preserveth",75,85],["H5315","his soul",86,94]]},"16:18":{"text":"Pride goeth before destruction, and an haughty spirit before a fall.","words":[["H1347","Pride",0,5],["H6440","goeth before",6,18],["H7667","destruction",19,30],["H1363","and an haughty",32,46],["H7307","spirit",47,53],["H6440","before",54,60],["H3783","a fall",61,67]]},"16:19":{"text":"Better it is to be of an humble spirit with the lowly, than to divide the spoil with the proud.","words":[["H2896","Better",0,6],["H8217","it is to be of an humble",7,31],["H7307","spirit",32,38],["H6035","with the lowly",39,53],["H6041","with the lowly",39,53],["H2505","than to divide",55,69],["H7998","the spoil",70,79],["H1343","with the proud",80,94]]},"16:20":{"text":"He that handleth a matter wisely shall find good: and whoso trusteth in the LORD, happy is he.","words":[["H1697","He that handleth a matter",0,25],["H7919","wisely",26,32],["H4672","shall find",33,43],["H2896","good",44,48],["H0982","and whoso trusteth",50,68],["H3068","in the LORD",69,80],["H0835","happy",82,87]]},"16:21":{"text":"The wise in heart shall be called prudent: and the sweetness of the lips increaseth learning.","words":[["H2450","The wise",0,8],["H3820","in heart",9,17],["H7121","shall be called",18,33],["H0995","prudent",34,41],["H4986","and the sweetness",43,60],["H8193","of the lips",61,72],["H3254","increaseth",73,83],["H3948","learning",84,92]]},"16:22":{"text":"Understanding is a wellspring of life unto him that hath it: but the instruction of fools is folly.","words":[["H7922","Understanding",0,13],["H4726","is a wellspring",14,29],["H2416","of life",30,37],["H1167","unto him that hath",38,56],["H4148","it: but the instruction",57,80],["H0191","of fools",81,89],["H0200","is folly",90,98]]},"16:23":{"text":"The heart of the wise teacheth his mouth, and addeth learning to his lips.","words":[["H3820","The heart",0,9],["H2450","of the wise",10,21],["H7919","teacheth",22,30],["H6310","his mouth",31,40],["H3254","and addeth",42,52],["H3948","learning",53,61],["H8193","to his lips",62,73]]},"16:24":{"text":"Pleasant words are as an honeycomb, sweet to the soul, and health to the bones.","words":[["H5278","Pleasant",0,8],["H0561","words",9,14],["H6688","are as an honeycomb",15,34],["H1706","are as an honeycomb",15,34],["H4966","sweet",36,41],["H5315","to the soul",42,53],["H4832","and health",55,65],["H6106","to the bones",66,78]]},"16:25":{"text":"There is a way that seemeth right unto a man, but the end thereof are the ways of death.","words":[["H3426","There is",0,8],["H1870","a way",9,14],["H3477","that seemeth right",15,33],["H6440","unto",34,38],["H0376","a man",39,44],["H0319","but the end",46,57],["H1870","thereof are the ways",58,78],["H4194","of death",79,87]]},"16:26":{"text":"He that laboureth laboureth for himself; for his mouth craveth it of him.","words":[["H5315","He",0,2],["H6001","that laboureth",3,17],["H5998","laboureth",18,27],["H6310","for himself; for his mouth",28,54],["H0404","craveth",55,62]]},"16:27":{"text":"An ungodly man diggeth up evil: and in his lips there is as a burning fire.","words":[["H1100","An ungodly",0,10],["H0376","man",11,14],["H3738","diggeth up",15,25],["H7451","evil",26,30],["H8193","and in his lips",32,47],["H6867","there is as a burning",48,69],["H0784","fire",70,74]]},"16:28":{"text":"A froward man soweth strife: and a whisperer separateth chief friends.","words":[["H8419","A froward",0,9],["H0376","man",10,13],["H7971","soweth",14,20],["H4066","strife",21,27],["H5372","and a whisperer",29,44],["H6504","separateth",45,55],["H0441","chief friends",56,69]]},"16:29":{"text":"A violent man enticeth his neighbour, and leadeth him into the way that is not good.","words":[["H2555","A violent",0,9],["H0376","man",10,13],["H6601","enticeth",14,22],["H7453","his neighbour",23,36],["H3212","and leadeth",38,49],["H1870","him into the way",50,66],["H2896","that is not good",67,83]]},"16:30":{"text":"He shutteth his eyes to devise froward things: moving his lips he bringeth evil to pass.","words":[["H6095","He shutteth",0,11],["H5869","his eyes",12,20],["H2803","to devise",21,30],["H8419","froward things",31,45],["H7169","moving",47,53],["H8193","his lips",54,62],["H3615","he bringeth",63,74],["H7451","evil",75,79],["H3615","to pass",80,87]]},"16:31":{"text":"The hoary head is a crown of glory, if it be found in the way of righteousness.","words":[["H7872","The hoary head",0,14],["H5850","is a crown",15,25],["H8597","of glory",26,34],["H4672","if it be found",36,50],["H1870","in the way",51,61],["H6666","of righteousness",62,78]]},"16:32":{"text":"He that is slow to anger is better than the mighty; and he that ruleth his spirit than he that taketh a city.","words":[["H0750","He that is slow",0,15],["H0639","to anger",16,24],["H2896","is better",25,34],["H1368","than the mighty",35,50],["H4910","and he that ruleth",52,70],["H7307","his spirit",71,81],["H3920","than he that taketh",82,101],["H5892","a city",102,108]]},"16:33":{"text":"The lot is cast into the lap; but the whole disposing thereof is of the LORD.","words":[["H1486","The lot",0,7],["H2904","is cast",8,15],["H2436","into the lap",16,28],["H4941","but the whole disposing",30,53],["H3068","thereof is of the LORD",54,76]]},"17:1":{"text":"Better is a dry morsel, and quietness therewith, than an house full of sacrifices with strife.","words":[["H2896","Better",0,6],["H2720","is a dry",7,15],["H6595","morsel",16,22],["H7962","and quietness",24,37],["H1004","therewith, than an house",38,62],["H4392","full",63,67],["H2077","of sacrifices",68,81],["H7379","with strife",82,93]]},"17:2":{"text":"A wise servant shall have rule over a son that causeth shame, and shall have part of the inheritance among the brethren.","words":[["H7919","A wise",0,6],["H5650","servant",7,14],["H4910","shall have rule",15,30],["H1121","over a son",31,41],["H0954","that causeth shame",42,60],["H2505","and shall have part",62,81],["H5159","of the inheritance",82,100],["H8432","among",101,106],["H0251","the brethren",107,119]]},"17:3":{"text":"The fining pot is for silver, and the furnace for gold: but the LORD trieth the hearts.","words":[["H4715","The fining pot",0,14],["H3701","is for silver",15,28],["H3564","and the furnace",30,45],["H2091","for gold",46,54],["H3068","but the LORD",56,68],["H0974","trieth",69,75],["H3826","the hearts",76,86]]},"17:4":{"text":"A wicked doer giveth heed to false lips; and a liar giveth ear to a naughty tongue.","words":[["H7489","A wicked doer",0,13],["H7181","giveth heed",14,25],["H0205","to false",26,34],["H8193","lips",35,39],["H8267","and a liar",41,51],["H0238","giveth ear",52,62],["H1942","to a naughty",63,75],["H3956","tongue",76,82]]},"17:5":{"text":"Whoso mocketh the poor reproacheth his Maker: and he that is glad at calamities shall not be unpunished.","words":[["H3932","Whoso mocketh",0,13],["H7326","the poor",14,22],["H2778","reproacheth",23,34],["H6213","his Maker",35,44],["H8056","and he that is glad",46,65],["H0343","at calamities",66,79],["H5352","shall not be unpunished",80,103]]},"17:6":{"text":"Children's children are the crown of old men; and the glory of children are their fathers.","words":[["H1121","Children's",0,10],["H1121","children",11,19],["H5850","are the crown",20,33],["H2205","of old men",34,44],["H8597","and the glory",46,59],["H1121","of children",60,71],["H0001","are their fathers",72,89]]},"17:7":{"text":"Excellent speech becometh not a fool: much less do lying lips a prince.","words":[["H3499","Excellent",0,9],["H8193","speech",10,16],["H5000","becometh",17,25],["H5036","not a fool",26,36],["H8267","much less do lying",38,56],["H8193","lips",57,61],["H5081","a prince",62,70]]},"17:8":{"text":"A gift is as a precious stone in the eyes of him that hath it: whithersoever it turneth, it prospereth.","words":[["H7810","A gift",0,6],["H2580","is as a precious",7,23],["H0068","stone",24,29],["H5869","in the eyes",30,41],["H1167","of him that hath",42,58],["H6437","it: whithersoever it turneth",59,87],["H7919","it prospereth",89,102]]},"17:9":{"text":"He that covereth a transgression seeketh love; but he that repeateth a matter separateth very friends.","words":[["H3680","He that covereth",0,16],["H6588","a transgression",17,32],["H1245","seeketh",33,40],["H0160","love",41,45],["H8138","but he that repeateth",47,68],["H1697","a matter",69,77],["H6504","separateth",78,88],["H0441","very friends",89,101]]},"17:10":{"text":"A reproof entereth more into a wise man than an hundred stripes into a fool.","words":[["H1606","A reproof",0,9],["H5181","entereth",10,18],["H0995","more into a wise man",19,39],["H3967","than an hundred",40,55],["H5221","stripes",56,63],["H3684","into a fool",64,75]]},"17:11":{"text":"An evil man seeketh only rebellion: therefore a cruel messenger shall be sent against him.","words":[["H7451","An evil",0,7],["H1245","man seeketh",8,19],["H4805","only rebellion",20,34],["H0394","therefore a cruel",36,53],["H4397","messenger",54,63],["H7971","shall be sent",64,77]]},"17:12":{"text":"Let a bear robbed of her whelps meet a man, rather than a fool in his folly.","words":[["H1677","Let a bear",0,10],["H7909","robbed",11,17],["H6298","of her whelps meet",18,36],["H0376","a man",37,42],["H0408","rather than",44,55],["H3684","a fool",56,62],["H0200","in his folly",63,75]]},"17:13":{"text":"Whoso rewardeth evil for good, evil shall not depart from his house.","words":[["H7725","Whoso rewardeth",0,15],["H7451","evil",16,20],["H2896","for good",21,29],["H7451","evil",31,35],["H4185","shall not depart",36,52],["H4185","shall not depart",36,52],["H1004","from his house",53,67]]},"17:14":{"text":"The beginning of strife is as when one letteth out water: therefore leave off contention, before it be meddled with.","words":[["H7225","The beginning",0,13],["H4066","of strife",14,23],["H6362","is as when one letteth out",24,50],["H4325","water",51,56],["H5203","therefore leave off",58,77],["H7379","contention",78,88],["H6440","before",90,96],["H1566","it be meddled",97,110]]},"17:15":{"text":"He that justifieth the wicked, and he that condemneth the just, even they both are abomination to the LORD.","words":[["H6663","He that justifieth",0,18],["H7563","the wicked",19,29],["H7561","and he that condemneth",31,53],["H6662","the just",54,62],["H8147","even they both",64,78],["H8441","are abomination",79,94],["H3068","to the LORD",95,106]]},"17:16":{"text":"Wherefore is there a price in the hand of a fool to get wisdom, seeing he hath no heart to it?","words":[["H4242","Wherefore is there a price",0,26],["H3027","in the hand",27,38],["H3684","of a fool",39,48],["H7069","to get",49,55],["H2451","wisdom",56,62],["H3820","seeing he hath no heart",64,87]]},"17:17":{"text":"A friend loveth at all times, and a brother is born for adversity.","words":[["H7453","A friend",0,8],["H0157","loveth",9,15],["H6256","at all times",16,28],["H0251","and a brother",30,43],["H3205","is born",44,51],["H6869","for adversity",52,65]]},"17:18":{"text":"A man void of understanding striketh hands, and becometh surety in the presence of his friend.","words":[["H0120","A man",0,5],["H2638","void",6,10],["H3820","of understanding",11,27],["H8628","striketh",28,36],["H3709","hands",37,42],["H6148","and becometh",44,56],["H6161","surety",57,63],["H6440","in the presence",64,79],["H7453","of his friend",80,93]]},"17:19":{"text":"He loveth transgression that loveth strife: and he that exalteth his gate seeketh destruction.","words":[["H0157","He loveth",0,9],["H6588","transgression",10,23],["H0157","that loveth",24,35],["H4683","strife",36,42],["H1361","and he that exalteth",44,64],["H6607","his gate",65,73],["H1245","seeketh",74,81],["H7667","destruction",82,93]]},"17:20":{"text":"He that hath a froward heart findeth no good: and he that hath a perverse tongue falleth into mischief.","words":[["H6141","He that hath a froward",0,22],["H3820","heart",23,28],["H4672","findeth",29,36],["H2896","no good",37,44],["H2015","and he that hath a perverse",46,73],["H3956","tongue",74,80],["H5307","falleth",81,88],["H7451","into mischief",89,102]]},"17:21":{"text":"He that begetteth a fool doeth it to his sorrow: and the father of a fool hath no joy.","words":[["H3205","He that begetteth",0,17],["H3684","a fool",18,24],["H8424","doeth it to his sorrow",25,47],["H0001","and the father",49,63],["H5036","of a fool",64,73],["H8055","hath no joy",74,85]]},"17:22":{"text":"A merry heart doeth good like a medicine: but a broken spirit drieth the bones.","words":[["H8056","A merry",0,7],["H3820","heart",8,13],["H3190","doeth good",14,24],["H1456","like a medicine",25,40],["H5218","but a broken",42,54],["H7307","spirit",55,61],["H3001","drieth",62,68],["H1634","the bones",69,78]]},"17:23":{"text":"A wicked man taketh a gift out of the bosom to pervert the ways of judgment.","words":[["H7563","A wicked",0,8],["H3947","man taketh",9,19],["H7810","a gift",20,26],["H2436","out of the bosom",27,43],["H5186","to pervert",44,54],["H0734","the ways",55,63],["H4941","of judgment",64,75]]},"17:24":{"text":"Wisdom is before him that hath understanding; but the eyes of a fool are in the ends of the earth.","words":[["H2451","Wisdom",0,6],["H6440","is before him that hath understanding",7,44],["H0995","is before him that hath understanding",7,44],["H5869","but the eyes",46,58],["H3684","of a fool",59,68],["H7097","are in the ends",69,84],["H0776","of the earth",85,97]]},"17:25":{"text":"A foolish son is a grief to his father, and bitterness to her that bare him.","words":[["H3684","A foolish",0,9],["H1121","son",10,13],["H3708","is a grief",14,24],["H0001","to his father",25,38],["H4470","and bitterness",40,54],["H3205","to her that bare",55,71]]},"17:26":{"text":"Also to punish the just is not good, nor to strike princes for equity.","words":[["H6064","Also to punish",0,14],["H6662","the just",15,23],["H2896","is not good",24,35],["H5221","nor to strike",37,50],["H5081","princes",51,58],["H3476","for equity",59,69]]},"17:27":{"text":"He that hath knowledge spareth his words: and a man of understanding is of an excellent spirit.","words":[["H3045","He that hath",0,12],["H1847","knowledge",13,22],["H2820","spareth",23,30],["H0561","his words",31,40],["H0376","and a man",42,51],["H8394","of understanding",52,68],["H3368","is of an excellent",69,87],["H7119","is of an excellent",69,87],["H7307","spirit",88,94]]},"17:28":{"text":"Even a fool, when he holdeth his peace, is counted wise: and he that shutteth his lips is esteemed a man of understanding.","words":[["H0191","Even a fool",0,11],["H2790","when he holdeth his peace",13,38],["H2803","is counted",40,50],["H2450","wise",51,55],["H0331","and he that shutteth",57,77],["H8193","his lips",78,86],["H0995","is esteemed a man of understanding",87,121]]},"18:1":{"text":"Through desire a man, having separated himself, seeketh and intermeddleth with all wisdom.","words":[["H8378","Through desire",0,14],["H6504","a man, having separated",15,38],["H1245","himself, seeketh",39,55],["H1566","and intermeddleth",56,73],["H8454","with all wisdom",74,89]]},"18:2":{"text":"A fool hath no delight in understanding, but that his heart may discover itself.","words":[["H3684","A fool",0,6],["H2654","hath no delight",7,22],["H8394","in understanding",23,39],["H3820","but that his heart",41,59],["H1540","may discover",60,72]]},"18:3":{"text":"When the wicked cometh, then cometh also contempt, and with ignominy reproach.","words":[["H7563","When the wicked",0,15],["H0935","cometh",16,22],["H0935","then cometh",24,35],["H0937","also contempt",36,49],["H7036","and with ignominy",51,68],["H2781","reproach",69,77]]},"18:4":{"text":"The words of a man's mouth are as deep waters, and the wellspring of wisdom as a flowing brook.","words":[["H1697","The words",0,9],["H0376","of a man's",10,20],["H6310","mouth",21,26],["H6013","are as deep",27,38],["H4325","waters",39,45],["H4726","and the wellspring",47,65],["H2451","of wisdom",66,75],["H5042","as a flowing",76,88],["H5158","brook",89,94]]},"18:5":{"text":"It is not good to accept the person of the wicked, to overthrow the righteous in judgment.","words":[["H2896","It is not good",0,14],["H5375","to accept",15,24],["H6440","the person",25,35],["H7563","of the wicked",36,49],["H5186","to overthrow",51,63],["H6662","the righteous",64,77],["H4941","in judgment",78,89]]},"18:6":{"text":"A fool's lips enter into contention, and his mouth calleth for strokes.","words":[["H3684","A fool's",0,8],["H8193","lips",9,13],["H0935","enter",14,19],["H7379","into contention",20,35],["H6310","and his mouth",37,50],["H7121","calleth",51,58],["H4112","for strokes",59,70]]},"18:7":{"text":"A fool's mouth is his destruction, and his lips are the snare of his soul.","words":[["H3684","A fool's",0,8],["H6310","mouth",9,14],["H4288","is his destruction",15,33],["H8193","and his lips",35,47],["H4170","are the snare",48,61],["H5315","of his soul",62,73]]},"18:8":{"text":"The words of a talebearer are as wounds, and they go down into the innermost parts of the belly.","words":[["H1697","The words",0,9],["H5372","of a talebearer",10,25],["H3859","are as wounds",26,39],["H3381","and they go down",41,57],["H2315","into the innermost parts",58,82],["H0990","of the belly",83,95]]},"18:9":{"text":"He also that is slothful in his work is brother to him that is a great waster.","words":[["H7503","He also that is slothful",0,24],["H4399","in his work",25,36],["H0251","is brother",37,47],["H1167","to him that is a great",48,70],["H7843","waster",71,77]]},"18:10":{"text":"The name of the LORD is a strong tower: the righteous runneth into it, and is safe.","words":[["H8034","The name",0,8],["H3068","of the LORD",9,20],["H5797","is a strong",21,32],["H4026","tower",33,38],["H6662","the righteous",40,53],["H7323","runneth",54,61],["H7682","into it, and is safe",62,82]]},"18:11":{"text":"The rich man's wealth is his strong city, and as an high wall in his own conceit.","words":[["H6223","The rich man's",0,14],["H1952","wealth",15,21],["H5797","is his strong",22,35],["H7151","city",36,40],["H7682","and as an high",42,56],["H2346","wall",57,61],["H4906","in his own conceit",62,80]]},"18:12":{"text":"Before destruction the heart of man is haughty, and before honour is humility.","words":[["H6440","Before",0,6],["H7667","destruction",7,18],["H3820","the heart",19,28],["H0376","of man",29,35],["H1361","is haughty",36,46],["H6440","and before",48,58],["H3519","honour",59,65],["H6038","is humility",66,77]]},"18:13":{"text":"He that answereth a matter before he heareth it, it is folly and shame unto him.","words":[["H7725","He that answereth",0,17],["H1697","a matter",18,26],["H8085","before he heareth",27,44],["H0200","it, it is folly",45,60],["H3639","and shame",61,70]]},"18:14":{"text":"The spirit of a man will sustain his infirmity; but a wounded spirit who can bear?","words":[["H7307","The spirit",0,10],["H0376","of a man",11,19],["H3557","will sustain",20,32],["H4245","his infirmity",33,46],["H5218","but a wounded",48,61],["H7307","spirit",62,68],["H5375","who can bear",69,81]]},"18:15":{"text":"The heart of the prudent getteth knowledge; and the ear of the wise seeketh knowledge.","words":[["H3820","The heart",0,9],["H0995","of the prudent",10,24],["H7069","getteth",25,32],["H1847","knowledge",33,42],["H0241","and the ear",44,55],["H2450","of the wise",56,67],["H1245","seeketh",68,75],["H1847","knowledge",76,85]]},"18:16":{"text":"A man's gift maketh room for him, and bringeth him before great men.","words":[["H0120","A man's",0,7],["H4976","gift",8,12],["H7337","maketh room",13,24],["H5148","for him, and bringeth",25,46],["H6440","him before",47,57],["H1419","great men",58,67]]},"18:17":{"text":"He that is first in his own cause seemeth just; but his neighbour cometh and searcheth him.","words":[["H7223","He that is first",0,16],["H7379","in his own cause",17,33],["H6662","seemeth just",34,46],["H7453","but his neighbour",48,65],["H0935","cometh",66,72],["H0935","cometh",66,72],["H2713","and searcheth",73,86]]},"18:18":{"text":"The lot causeth contentions to cease, and parteth between the mighty.","words":[["H1486","The lot",0,7],["H4079","causeth contentions",8,27],["H7673","to cease",28,36],["H6504","and parteth",38,49],["H6099","between the mighty",50,68]]},"18:19":{"text":"A brother offended is harder to be won than a strong city: and their contentions are like the bars of a castle.","words":[["H0251","A brother",0,9],["H6586","offended",10,18],["H5797","is harder to be won than a strong",19,52],["H7151","city",53,57],["H4079","and their contentions",59,80],["H4066","and their contentions",59,80],["H1280","are like the bars",81,98],["H0759","of a castle",99,110]]},"18:20":{"text":"A man's belly shall be satisfied with the fruit of his mouth; and with the increase of his lips shall he be filled.","words":[["H0376","A man's",0,7],["H0990","belly",8,13],["H7646","shall be satisfied",14,32],["H6529","with the fruit",33,47],["H6310","of his mouth",48,60],["H8393","and with the increase",62,83],["H8193","of his lips",84,95],["H7646","shall he be filled",96,114]]},"18:21":{"text":"Death and life are in the power of the tongue: and they that love it shall eat the fruit thereof.","words":[["H4194","Death",0,5],["H2416","and life",6,14],["H3027","are in the power",15,31],["H3956","of the tongue",32,45],["H0157","and they that love",47,65],["H0398","it shall eat",66,78],["H6529","the fruit",79,88]]},"18:22":{"text":"Whoso findeth a wife findeth a good thing, and obtaineth favour of the LORD.","words":[["H4672","Whoso findeth",0,13],["H0802","a wife",14,20],["H4672","findeth",21,28],["H2896","a good",29,35],["H6329","thing, and obtaineth",36,56],["H7522","favour",57,63],["H3068","of the LORD",64,75]]},"18:23":{"text":"The poor useth intreaties; but the rich answereth roughly.","words":[["H7326","The poor",0,8],["H1696","useth",9,14],["H8469","intreaties",15,25],["H6223","but the rich",27,39],["H6030","answereth",40,49],["H5794","roughly",50,57]]},"18:24":{"text":"A man that hath friends must shew himself friendly: and there is a friend that sticketh closer than a brother.","words":[["H0376","A man",0,5],["H7453","that hath friends",6,23],["H7489","must shew himself friendly",24,50],["H3426","and there is",52,64],["H0157","a friend",65,73],["H1695","that sticketh closer",74,94],["H0251","than a brother",95,109]]},"19:1":{"text":"Better is the poor that walketh in his integrity, than he that is perverse in his lips, and is a fool.","words":[["H2896","Better",0,6],["H7326","is the poor",7,18],["H1980","that walketh",19,31],["H8537","in his integrity",32,48],["H6141","than he that is perverse",50,74],["H8193","in his lips",75,86],["H3684","and is a fool",88,101]]},"19:2":{"text":"Also, that the soul be without knowledge, it is not good; and he that hasteth with his feet sinneth.","words":[["H5315","Also, that the soul",0,19],["H1847","be without knowledge",20,40],["H2896","it is not good",42,56],["H0213","and he that hasteth",58,77],["H7272","with his feet",78,91],["H2398","sinneth",92,99]]},"19:3":{"text":"The foolishness of man perverteth his way: and his heart fretteth against the LORD.","words":[["H0200","The foolishness",0,15],["H0120","of man",16,22],["H5557","perverteth",23,33],["H1870","his way",34,41],["H3820","and his heart",43,56],["H2196","fretteth",57,65],["H3068","against the LORD",66,82]]},"19:4":{"text":"Wealth maketh many friends; but the poor is separated from his neighbour.","words":[["H1952","Wealth",0,6],["H3254","maketh",7,13],["H7227","many",14,18],["H7453","friends",19,26],["H1800","but the poor",28,40],["H6504","is separated",41,53],["H7453","from his neighbour",54,72]]},"19:5":{"text":"A false witness shall not be unpunished, and he that speaketh lies shall not escape.","words":[["H8267","A false",0,7],["H5707","witness",8,15],["H5352","shall not be unpunished",16,39],["H6315","and he that speaketh",41,61],["H3577","lies",62,66],["H4422","shall not escape",67,83]]},"19:6":{"text":"Many will intreat the favour of the prince: and every man is a friend to him that giveth gifts.","words":[["H7227","Many",0,4],["H2470","will intreat",5,17],["H6440","the favour",18,28],["H5081","of the prince",29,42],["H7453","and every man is a friend",44,69],["H0376","to him",70,76],["H4976","that giveth gifts",77,94]]},"19:7":{"text":"All the brethren of the poor do hate him: how much more do his friends go far from him? he pursueth them with words, yet they are wanting to him.","words":[["H0251","All the brethren",0,16],["H7326","of the poor",17,28],["H8130","do hate",29,36],["H4828","him: how much more do his friends",37,70],["H7368","go far",71,77],["H7291","from him? he pursueth",78,99],["H0561","them with words",100,115]]},"19:8":{"text":"He that getteth wisdom loveth his own soul: he that keepeth understanding shall find good.","words":[["H7069","He that getteth",0,15],["H3820","wisdom",16,22],["H0157","loveth",23,29],["H5315","his own soul",30,42],["H8104","he that keepeth",44,59],["H8394","understanding",60,73],["H4672","shall find",74,84],["H2896","good",85,89]]},"19:9":{"text":"A false witness shall not be unpunished, and he that speaketh lies shall perish.","words":[["H8267","A false",0,7],["H5707","witness",8,15],["H5352","shall not be unpunished",16,39],["H6315","and he that speaketh",41,61],["H3577","lies",62,66],["H0006","shall perish",67,79]]},"19:10":{"text":"Delight is not seemly for a fool; much less for a servant to have rule over princes.","words":[["H8588","Delight",0,7],["H5000","is not seemly",8,21],["H3684","for a fool",22,32],["H5650","much less for a servant",34,57],["H4910","to have rule",58,70],["H8269","over princes",71,83]]},"19:11":{"text":"The discretion of a man deferreth his anger; and it is his glory to pass over a transgression.","words":[["H7922","The discretion",0,14],["H0120","of a man",15,23],["H0748","deferreth",24,33],["H0639","his anger",34,43],["H8597","and it is his glory",45,64],["H5674","to pass over",65,77],["H6588","a transgression",78,93]]},"19:12":{"text":"The king's wrath is as the roaring of a lion; but his favour is as dew upon the grass.","words":[["H4428","The king's",0,10],["H2197","wrath",11,16],["H5099","is as the roaring",17,34],["H3715","of a lion",35,44],["H7522","but his favour",46,60],["H2919","is as dew",61,70],["H6212","upon the grass",71,85]]},"19:13":{"text":"A foolish son is the calamity of his father: and the contentions of a wife are a continual dropping.","words":[["H3684","A foolish",0,9],["H1121","son",10,13],["H1942","is the calamity",14,29],["H0001","of his father",30,43],["H4079","and the contentions",45,64],["H0802","of a wife",65,74],["H2956","are a continual",75,90],["H1812","dropping",91,99]]},"19:14":{"text":"House and riches are the inheritance of fathers: and a prudent wife is from the LORD.","words":[["H1004","House",0,5],["H1952","and riches",6,16],["H5159","are the inheritance",17,36],["H0001","of fathers",37,47],["H7919","and a prudent",49,62],["H0802","wife",63,67],["H3068","is from the LORD",68,84]]},"19:15":{"text":"Slothfulness casteth into a deep sleep; and an idle soul shall suffer hunger.","words":[["H6103","Slothfulness",0,12],["H5307","casteth",13,20],["H8639","into a deep sleep",21,38],["H7423","and an idle",40,51],["H5315","soul",52,56],["H7456","shall suffer hunger",57,76]]},"19:16":{"text":"He that keepeth the commandment keepeth his own soul; but he that despiseth his ways shall die.","words":[["H8104","He that keepeth",0,15],["H4687","the commandment",16,31],["H8104","keepeth",32,39],["H5315","his own soul",40,52],["H0959","but he that despiseth",54,75],["H1870","his ways",76,84],["H4191","shall die",85,94]]},"19:17":{"text":"He that hath pity upon the poor lendeth unto the LORD; and that which he hath given will he pay him again.","words":[["H2603","He that hath pity",0,17],["H1800","upon the poor",18,31],["H3867","lendeth",32,39],["H3068","unto the LORD",40,53],["H1576","and that which he hath given",55,83],["H7999","will he pay him again",84,105]]},"19:18":{"text":"Chasten thy son while there is hope, and let not thy soul spare for his crying.","words":[["H3256","Chasten",0,7],["H1121","thy son",8,15],["H3426","while there is",16,30],["H8615","hope",31,35],["H5315","and let not thy soul",37,57],["H5375","spare",58,63],["H4191","for his crying",64,78]]},"19:19":{"text":"A man of great wrath shall suffer punishment: for if thou deliver him, yet thou must do it again.","words":[["H1419","A man",0,5],["H1632","of great",6,14],["H2534","wrath",15,20],["H5375","shall suffer",21,33],["H6066","punishment",34,44],["H5337","for if thou deliver",46,65],["H3254","him, yet thou must do it again",66,96]]},"19:20":{"text":"Hear counsel, and receive instruction, that thou mayest be wise in thy latter end.","words":[["H8085","Hear",0,4],["H6098","counsel",5,12],["H6901","and receive",14,25],["H4148","instruction",26,37],["H2449","that thou mayest be wise",39,63],["H0319","in thy latter end",64,81]]},"19:21":{"text":"There are many devices in a man's heart; nevertheless the counsel of the LORD, that shall stand.","words":[["H7227","There are many",0,14],["H4284","devices",15,22],["H0376","in a man's",23,33],["H3820","heart",34,39],["H6098","nevertheless the counsel",41,65],["H3068","of the LORD",66,77],["H6965","that shall stand",79,95]]},"19:22":{"text":"The desire of a man is his kindness: and a poor man is better than a liar.","words":[["H8378","The desire",0,10],["H0120","of a man",11,19],["H2617","is his kindness",20,35],["H7326","and a poor man",37,51],["H2896","is better",52,61],["H0376","than",62,66],["H3577","a liar",67,73]]},"19:23":{"text":"The fear of the LORD tendeth to life: and he that hath it shall abide satisfied; he shall not be visited with evil.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H2416","tendeth to life",21,36],["H3885","and he that hath it shall abide",38,69],["H7649","satisfied",70,79],["H6485","he shall not be visited",81,104],["H7451","with evil",105,114]]},"19:24":{"text":"A slothful man hideth his hand in his bosom, and will not so much as bring it to his mouth again.","words":[["H6102","A slothful",0,10],["H2934","man hideth",11,21],["H3027","his hand",22,30],["H6747","in his bosom",31,43],["H7725","and will not so much as bring",45,74],["H6310","it to his mouth",75,90],["H7725","again",91,96]]},"19:25":{"text":"Smite a scorner, and the simple will beware: and reprove one that hath understanding, and he will understand knowledge.","words":[["H5221","Smite",0,5],["H3887","a scorner",6,15],["H6612","and the simple",17,31],["H6191","will beware",32,43],["H3198","and reprove",45,56],["H0995","one that hath understanding",57,84],["H0995","and he will understand",86,108],["H1847","knowledge",109,118]]},"19:26":{"text":"He that wasteth his father, and chaseth away his mother, is a son that causeth shame, and bringeth reproach.","words":[["H7703","He that wasteth",0,15],["H0001","his father",16,26],["H1272","and chaseth away",28,44],["H0517","his mother",45,55],["H1121","is a son",57,65],["H0954","that causeth shame",66,84],["H2659","and bringeth reproach",86,107]]},"19:27":{"text":"Cease, my son, to hear the instruction that causeth to err from the words of knowledge.","words":[["H2308","Cease",0,5],["H1121","my son",7,13],["H8085","to hear",15,22],["H4148","the instruction",23,38],["H7686","that causeth to err",39,58],["H0561","from the words",59,73],["H1847","of knowledge",74,86]]},"19:28":{"text":"An ungodly witness scorneth judgment: and the mouth of the wicked devoureth iniquity.","words":[["H1100","An ungodly",0,10],["H5707","witness",11,18],["H3887","scorneth",19,27],["H4941","judgment",28,36],["H6310","and the mouth",38,51],["H7563","of the wicked",52,65],["H1104","devoureth",66,75],["H0205","iniquity",76,84]]},"19:29":{"text":"Judgments are prepared for scorners, and stripes for the back of fools.","words":[["H8201","Judgments",0,9],["H3559","are prepared",10,22],["H3887","for scorners",23,35],["H4112","and stripes",37,48],["H1460","for the back",49,61],["H3684","of fools",62,70]]},"20:1":{"text":"Wine is a mocker, strong drink is raging: and whosoever is deceived thereby is not wise.","words":[["H3196","Wine",0,4],["H3887","is a mocker",5,16],["H7941","strong drink",18,30],["H1993","is raging",31,40],["H7686","and whosoever is deceived",42,67],["H2449","thereby is not wise",68,87]]},"20:2":{"text":"The fear of a king is as the roaring of a lion: whoso provoketh him to anger sinneth against his own soul.","words":[["H0367","The fear",0,8],["H4428","of a king",9,18],["H5099","is as the roaring",19,36],["H3715","of a lion",37,46],["H5674","whoso provoketh him to anger",48,76],["H2398","sinneth",77,84],["H5315","against his own soul",85,105]]},"20:3":{"text":"It is an honour for a man to cease from strife: but every fool will be meddling.","words":[["H3519","It is an honour",0,15],["H0376","for a man",16,25],["H7674","to cease",26,34],["H7379","from strife",35,46],["H0191","but every fool",48,62],["H1566","will be meddling",63,79]]},"20:4":{"text":"The sluggard will not plow by reason of the cold; therefore shall he beg in harvest, and have nothing.","words":[["H6102","The sluggard",0,12],["H2790","will not plow",13,26],["H2779","by reason of the cold",27,48],["H7592","therefore shall he beg",50,72],["H7592","therefore shall he beg",50,72],["H7105","in harvest",73,83]]},"20:5":{"text":"Counsel in the heart of man is like deep water; but a man of understanding will draw it out.","words":[["H6098","Counsel",0,7],["H3820","in the heart",8,20],["H0376","of man",21,27],["H6013","is like deep",28,40],["H4325","water",41,46],["H0376","but a man",48,57],["H8394","of understanding",58,74],["H1802","will draw it out",75,91]]},"20:6":{"text":"Most men will proclaim every one his own goodness: but a faithful man who can find?","words":[["H7230","Most",0,4],["H0120","men",5,8],["H7121","will proclaim",9,22],["H0376","every one",23,32],["H2617","his own goodness",33,49],["H0529","but a faithful",51,65],["H0376","man",66,69],["H4672","who can find",70,82]]},"20:7":{"text":"The just man walketh in his integrity: his children are blessed after him.","words":[["H6662","The just",0,8],["H1980","man walketh",9,20],["H8537","in his integrity",21,37],["H1121","his children",39,51],["H0835","are blessed",52,63],["H0310","after",64,69]]},"20:8":{"text":"A king that sitteth in the throne of judgment scattereth away all evil with his eyes.","words":[["H4428","A king",0,6],["H3427","that sitteth in",7,22],["H3678","the throne",23,33],["H1779","of judgment",34,45],["H2219","scattereth away",46,61],["H7451","all evil",62,70],["H5869","with his eyes",71,84]]},"20:9":{"text":"Who can say, I have made my heart clean, I am pure from my sin?","words":[["H0559","Who can say",0,11],["H3820","I have made my heart",13,33],["H2135","clean",34,39],["H2891","I am pure",41,50],["H2403","from my sin",51,62]]},"20:10":{"text":"Divers weights, and divers measures, both of them are alike abomination to the LORD.","words":[["H0068","Divers weights",0,14],["H0068","Divers weights",0,14],["H0374","and divers measures",16,35],["H0374","and divers measures",16,35],["H8147","both",37,41],["H1571","of them are alike",42,59],["H8441","abomination",60,71],["H3068","to the LORD",72,83]]},"20:11":{"text":"Even a child is known by his doings, whether his work be pure, and whether it be right.","words":[["H5288","Even a child",0,12],["H5234","is known",13,21],["H4611","by his doings",22,35],["H6467","whether his work",37,53],["H2134","be pure",54,61],["H3477","and whether it be right",63,86]]},"20:12":{"text":"The hearing ear, and the seeing eye, the LORD hath made even both of them.","words":[["H8085","The hearing",0,11],["H0241","ear",12,15],["H7200","and the seeing",17,31],["H5869","eye",32,35],["H3068","the LORD",37,45],["H6213","hath made",46,55],["H8147","even both",56,65]]},"20:13":{"text":"Love not sleep, lest thou come to poverty; open thine eyes, and thou shalt be satisfied with bread.","words":[["H0157","Love",0,4],["H8142","not sleep",5,14],["H3423","lest thou come to poverty",16,41],["H6491","open",43,47],["H5869","thine eyes",48,58],["H7646","and thou shalt be satisfied",60,87],["H3899","with bread",88,98]]},"20:14":{"text":"It is naught, it is naught, saith the buyer: but when he is gone his way, then he boasteth.","words":[["H7451","It is naught",0,12],["H7451","it is naught",14,26],["H0559","saith",28,33],["H7069","the buyer",34,43],["H0235","but when he is gone",45,64],["H1984","his way, then he boasteth",65,90]]},"20:15":{"text":"There is gold, and a multitude of rubies: but the lips of knowledge are a precious jewel.","words":[["H3426","There is",0,8],["H2091","gold",9,13],["H7230","and a multitude",15,30],["H6443","of rubies",31,40],["H8193","but the lips",42,54],["H1847","of knowledge",55,67],["H3366","are a precious",68,82],["H3627","jewel",83,88]]},"20:16":{"text":"Take his garment that is surety for a stranger: and take a pledge of him for a strange woman.","words":[["H3947","Take",0,4],["H0899","his garment",5,16],["H6148","that is surety",17,31],["H2114","for a stranger",32,46],["H2254","and take a pledge",48,65],["H5237","of him for a strange woman",66,92]]},"20:17":{"text":"Bread of deceit is sweet to a man; but afterwards his mouth shall be filled with gravel.","words":[["H3899","Bread",0,5],["H8267","of deceit",6,15],["H6156","is sweet",16,24],["H0376","to a man",25,33],["H0310","but afterwards",35,49],["H6310","his mouth",50,59],["H4390","shall be filled",60,75],["H2687","with gravel",76,87]]},"20:18":{"text":"Every purpose is established by counsel: and with good advice make war.","words":[["H4284","Every purpose",0,13],["H3559","is established",14,28],["H6098","by counsel",29,39],["H8458","and with good advice",41,61],["H6213","make",62,66],["H4421","war",67,70]]},"20:19":{"text":"He that goeth about as a talebearer revealeth secrets: therefore meddle not with him that flattereth with his lips.","words":[["H1980","He that goeth about",0,19],["H7400","as a talebearer",20,35],["H1540","revealeth",36,45],["H5475","secrets",46,53],["H6148","therefore meddle",55,71],["H6601","not with him that flattereth",72,100],["H8193","with his lips",101,114]]},"20:20":{"text":"Whoso curseth his father or his mother, his lamp shall be put out in obscure darkness.","words":[["H7043","Whoso curseth",0,13],["H0001","his father",14,24],["H0517","or his mother",25,38],["H5216","his lamp",40,48],["H1846","shall be put out",49,65],["H0380","in obscure",66,76],["H0380","in obscure",66,76],["H2822","darkness",77,85]]},"20:21":{"text":"An inheritance may be gotten hastily at the beginning; but the end thereof shall not be blessed.","words":[["H5159","An inheritance",0,14],["H0926","may be gotten hastily",15,36],["H0973","may be gotten hastily",15,36],["H7223","at the beginning",37,53],["H0319","but the end",55,66],["H1288","thereof shall not be blessed",67,95]]},"20:22":{"text":"Say not thou, I will recompense evil; but wait on the LORD, and he shall save thee.","words":[["H0559","Say",0,3],["H7999","not thou, I will recompense",4,31],["H7451","evil",32,36],["H6960","but wait on",38,49],["H3068","the LORD",50,58],["H3467","and he shall save",60,77]]},"20:23":{"text":"Divers weights are an abomination unto the LORD; and a false balance is not good.","words":[["H0068","Divers weights",0,14],["H0068","Divers weights",0,14],["H8441","are an abomination",15,33],["H3068","unto the LORD",34,47],["H4820","and a false",49,60],["H3976","balance",61,68],["H2896","is not good",69,80]]},"20:24":{"text":"Man's goings are of the LORD; how can a man then understand his own way?","words":[["H1397","Man's",0,5],["H4703","goings",6,12],["H3068","are of the LORD",13,28],["H0120","how can a man",30,43],["H0995","then understand",44,59],["H1870","his own way",60,71]]},"20:25":{"text":"It is a snare to the man who devoureth that which is holy, and after vows to make enquiry.","words":[["H4170","It is a snare",0,13],["H0120","to the man",14,24],["H3216","who devoureth",25,38],["H6944","that which is holy",39,57],["H0310","and after",59,68],["H5088","vows",69,73],["H1239","to make enquiry",74,89]]},"20:26":{"text":"A wise king scattereth the wicked, and bringeth the wheel over them.","words":[["H2450","A wise",0,6],["H4428","king",7,11],["H2219","scattereth",12,22],["H7563","the wicked",23,33],["H7725","and bringeth",35,47],["H0212","the wheel",48,57]]},"20:27":{"text":"The spirit of man is the candle of the LORD, searching all the inward parts of the belly.","words":[["H5397","The spirit",0,10],["H0120","of man",11,17],["H5216","is the candle",18,31],["H3068","of the LORD",32,43],["H2664","searching",45,54],["H2315","all the inward parts",55,75],["H0990","of the belly",76,88]]},"20:28":{"text":"Mercy and truth preserve the king: and his throne is upholden by mercy.","words":[["H2617","Mercy",0,5],["H0571","and truth",6,15],["H5341","preserve",16,24],["H4428","the king",25,33],["H3678","and his throne",35,49],["H5582","is upholden",50,61],["H2617","by mercy",62,70]]},"20:29":{"text":"The glory of young men is their strength: and the beauty of old men is the gray head.","words":[["H8597","The glory",0,9],["H0970","of young men",10,22],["H3581","is their strength",23,40],["H1926","and the beauty",42,56],["H2205","of old men",57,67],["H7872","is the gray head",68,84]]},"20:30":{"text":"The blueness of a wound cleanseth away evil: so do stripes the inward parts of the belly.","words":[["H2250","The blueness",0,12],["H6482","of a wound",13,23],["H8562","cleanseth",24,33],["H7451","away evil",34,43],["H4347","so do stripes",45,58],["H2315","the inward parts",59,75],["H0990","of the belly",76,88]]},"21:1":{"text":"The king's heart is in the hand of the LORD, as the rivers of water: he turneth it whithersoever he will.","words":[["H4428","The king's",0,10],["H3820","heart",11,16],["H3027","is in the hand",17,31],["H3068","of the LORD",32,43],["H6388","as the rivers",45,58],["H4325","of water",59,67],["H5186","he turneth",69,79],["H2654","it whithersoever he will",80,104]]},"21:2":{"text":"Every way of a man is right in his own eyes: but the LORD pondereth the hearts.","words":[["H1870","Every way",0,9],["H0376","of a man",10,18],["H3477","is right",19,27],["H5869","in his own eyes",28,43],["H3068","but the LORD",45,57],["H8505","pondereth",58,67],["H3826","the hearts",68,78]]},"21:3":{"text":"To do justice and judgment is more acceptable to the LORD than sacrifice.","words":[["H6213","To do",0,5],["H6666","justice",6,13],["H4941","and judgment",14,26],["H0977","is more acceptable",27,45],["H3068","to the LORD",46,57],["H2077","than sacrifice",58,72]]},"21:4":{"text":"An high look, and a proud heart, and the plowing of the wicked, is sin.","words":[["H7312","An high",0,7],["H5869","look",8,12],["H7342","and a proud",14,25],["H3820","heart",26,31],["H5215","and the plowing",33,48],["H7563","of the wicked",49,62],["H2403","is sin",64,70]]},"21:5":{"text":"The thoughts of the diligent tend only to plenteousness; but of every one that is hasty only to want.","words":[["H4284","The thoughts",0,12],["H2742","of the diligent",13,28],["H4195","tend only to plenteousness",29,55],["H0213","but of every one that is hasty",57,87],["H4270","only to want",88,100]]},"21:6":{"text":"The getting of treasures by a lying tongue is a vanity tossed to and fro of them that seek death.","words":[["H6467","The getting",0,11],["H0214","of treasures",12,24],["H8267","by a lying",25,35],["H3956","tongue",36,42],["H1892","is a vanity",43,54],["H5086","tossed to and fro of",55,75],["H1245","them that seek",76,90],["H4194","death",91,96]]},"21:7":{"text":"The robbery of the wicked shall destroy them; because they refuse to do judgment.","words":[["H7701","The robbery",0,11],["H7563","of the wicked",12,25],["H1641","shall destroy",26,39],["H3985","them; because they refuse",40,65],["H6213","to do",66,71],["H4941","judgment",72,80]]},"21:8":{"text":"The way of man is froward and strange: but as for the pure, his work is right.","words":[["H1870","The way",0,7],["H0376","of man",8,14],["H2019","is froward",15,25],["H2054","and strange",26,37],["H2134","but as for the pure",39,58],["H6467","his work",60,68],["H3477","is right",69,77]]},"21:9":{"text":"It is better to dwell in a corner of the housetop, than with a brawling woman in a wide house.","words":[["H2896","It is better",0,12],["H3427","to dwell",13,21],["H6438","in a corner",22,33],["H1406","of the housetop",34,49],["H4079","than with a brawling",51,71],["H4066","than with a brawling",51,71],["H0802","woman",72,77],["H2267","in a wide",78,87],["H1004","house",88,93]]},"21:10":{"text":"The soul of the wicked desireth evil: his neighbour findeth no favour in his eyes.","words":[["H5315","The soul",0,8],["H7563","of the wicked",9,22],["H0183","desireth",23,31],["H7451","evil",32,36],["H7453","his neighbour",38,51],["H2603","findeth no favour",52,69],["H5869","in his eyes",70,81]]},"21:11":{"text":"When the scorner is punished, the simple is made wise: and when the wise is instructed, he receiveth knowledge.","words":[["H3887","When the scorner",0,16],["H6064","is punished",17,28],["H6612","the simple",30,40],["H2449","is made wise",41,53],["H2450","and when the wise",55,72],["H7919","is instructed",73,86],["H3947","he receiveth",88,100],["H1847","knowledge",101,110]]},"21:12":{"text":"The righteous man wisely considereth the house of the wicked: but God overthroweth the wicked for their wickedness.","words":[["H6662","The righteous",0,13],["H7919","man wisely considereth",14,36],["H1004","the house",37,46],["H7563","of the wicked",47,60],["H5557","but God overthroweth",62,82],["H7563","the wicked",83,93],["H7451","for their wickedness",94,114]]},"21:13":{"text":"Whoso stoppeth his ears at the cry of the poor, he also shall cry himself, but shall not be heard.","words":[["H0331","Whoso stoppeth",0,14],["H0241","his ears",15,23],["H2201","at the cry",24,34],["H1800","of the poor",35,46],["H7121","he also shall cry",48,65],["H6030","himself, but shall not be heard",66,97]]},"21:14":{"text":"A gift in secret pacifieth anger: and a reward in the bosom strong wrath.","words":[["H4976","A gift",0,6],["H5643","in secret",7,16],["H3711","pacifieth",17,26],["H0639","anger",27,32],["H7810","and a reward",34,46],["H2436","in the bosom",47,59],["H5794","strong",60,66],["H2534","wrath",67,72]]},"21:15":{"text":"It is joy to the just to do judgment: but destruction shall be to the workers of iniquity.","words":[["H8057","It is joy",0,9],["H6662","to the just",10,21],["H6213","to do",22,27],["H4941","judgment",28,36],["H4288","but destruction",38,53],["H6466","shall be to the workers",54,77],["H0205","of iniquity",78,89]]},"21:16":{"text":"The man that wandereth out of the way of understanding shall remain in the congregation of the dead.","words":[["H0120","The man",0,7],["H8582","that wandereth",8,22],["H1870","out of the way",23,37],["H7919","of understanding",38,54],["H5117","shall remain",55,67],["H6951","in the congregation",68,87],["H7496","of the dead",88,99]]},"21:17":{"text":"He that loveth pleasure shall be a poor man: he that loveth wine and oil shall not be rich.","words":[["H0157","He that loveth",0,14],["H8057","pleasure",15,23],["H4270","shall be a poor",24,39],["H0376","man",40,43],["H0157","he that loveth",45,59],["H3196","wine",60,64],["H8081","and oil",65,72],["H6238","shall not be rich",73,90]]},"21:18":{"text":"The wicked shall be a ransom for the righteous, and the transgressor for the upright.","words":[["H7563","The wicked",0,10],["H3724","shall be a ransom",11,28],["H6662","for the righteous",29,46],["H0898","and the transgressor",48,68],["H3477","for the upright",69,84]]},"21:19":{"text":"It is better to dwell in the wilderness, than with a contentious and an angry woman.","words":[["H2896","It is better",0,12],["H3427","to dwell",13,21],["H0776","in the wilderness",22,39],["H4057","in the wilderness",22,39],["H4079","than with a contentious",41,64],["H4066","than with a contentious",41,64],["H3708","and an angry",65,77],["H0802","woman",78,83]]},"21:20":{"text":"There is treasure to be desired and oil in the dwelling of the wise; but a foolish man spendeth it up.","words":[["H0214","There is treasure",0,17],["H2530","to be desired",18,31],["H8081","and oil",32,39],["H5116","in the dwelling",40,55],["H2450","of the wise",56,67],["H3684","but a foolish",69,82],["H0120","man",83,86],["H1104","spendeth it up",87,101]]},"21:21":{"text":"He that followeth after righteousness and mercy findeth life, righteousness, and honour.","words":[["H7291","He that followeth",0,17],["H6666","after righteousness",18,37],["H2617","and mercy",38,47],["H4672","findeth",48,55],["H2416","life",56,60],["H6666","righteousness",62,75],["H3519","and honour",77,87]]},"21:22":{"text":"A wise man scaleth the city of the mighty, and casteth down the strength of the confidence thereof.","words":[["H2450","A wise",0,6],["H5927","man scaleth",7,18],["H5892","the city",19,27],["H1368","of the mighty",28,41],["H3381","and casteth down",43,59],["H5797","the strength",60,72],["H4009","of the confidence",73,90]]},"21:23":{"text":"Whoso keepeth his mouth and his tongue keepeth his soul from troubles.","words":[["H8104","Whoso keepeth",0,13],["H6310","his mouth",14,23],["H3956","and his tongue",24,38],["H8104","keepeth",39,46],["H5315","his soul",47,55],["H6869","from troubles",56,69]]},"21:24":{"text":"Proud and haughty scorner is his name, who dealeth in proud wrath.","words":[["H2086","Proud",0,5],["H3093","and haughty",6,17],["H3887","scorner",18,25],["H8034","is his name",26,37],["H6213","who dealeth",39,50],["H2087","in proud",51,59],["H5678","wrath",60,65]]},"21:25":{"text":"The desire of the slothful killeth him; for his hands refuse to labour.","words":[["H8378","The desire",0,10],["H6102","of the slothful",11,26],["H4191","killeth",27,34],["H3027","him; for his hands",35,53],["H3985","refuse",54,60],["H6213","to labour",61,70]]},"21:26":{"text":"He coveteth greedily all the day long: but the righteous giveth and spareth not.","words":[["H0183","He coveteth",0,11],["H8378","greedily",12,20],["H3117","all the day",21,32],["H6662","long: but the righteous",33,56],["H5414","giveth",57,63],["H2820","and spareth",64,75]]},"21:27":{"text":"The sacrifice of the wicked is abomination: how much more, when he bringeth it with a wicked mind?","words":[["H2077","The sacrifice",0,13],["H7563","of the wicked",14,27],["H8441","is abomination",28,42],["H0935","how much more, when he bringeth",44,75],["H2154","it with a wicked mind",76,97]]},"21:28":{"text":"A false witness shall perish: but the man that heareth speaketh constantly.","words":[["H3577","A false",0,7],["H5707","witness",8,15],["H0006","shall perish",16,28],["H0376","but the man",30,41],["H8085","that heareth",42,54],["H1696","speaketh",55,63],["H5331","constantly",64,74]]},"21:29":{"text":"A wicked man hardeneth his face: but as for the upright, he directeth his way.","words":[["H7563","A wicked",0,8],["H0376","man",9,12],["H5810","hardeneth",13,22],["H6440","his face",23,31],["H3477","but as for the upright",33,55],["H0995","he directeth",57,69],["H3559","he directeth",57,69],["H1870","his way",70,77]]},"21:30":{"text":"There is no wisdom nor understanding nor counsel against the LORD.","words":[["H2451","There is no wisdom",0,18],["H8394","nor understanding",19,36],["H6098","nor counsel",37,48],["H3068","against the LORD",49,65]]},"21:31":{"text":"The horse is prepared against the day of battle: but safety is of the LORD.","words":[["H5483","The horse",0,9],["H3559","is prepared",10,21],["H3117","against the day",22,37],["H4421","of battle",38,47],["H8668","but safety",49,59],["H3068","is of the LORD",60,74]]},"22:1":{"text":"A good name is rather to be chosen than great riches, and loving favour rather than silver and gold.","words":[["H8034","A good name",0,11],["H0977","is rather to be chosen",12,34],["H7227","than great",35,45],["H6239","riches",46,52],["H2896","and loving",54,64],["H2580","favour",65,71],["H3701","rather than silver",72,90],["H2091","and gold",91,99]]},"22:2":{"text":"The rich and poor meet together: the LORD is the maker of them all.","words":[["H6223","The rich",0,8],["H7326","and poor",9,17],["H6298","meet together",18,31],["H3068","the LORD",33,41],["H6213","is the maker",42,54]]},"22:3":{"text":"A prudent man foreseeth the evil, and hideth himself: but the simple pass on, and are punished.","words":[["H6175","A prudent",0,9],["H7200","man foreseeth",10,23],["H7451","the evil",24,32],["H5641","and hideth",34,44],["H5641","and hideth",34,44],["H6612","himself: but the simple",45,68],["H5674","pass on",69,76],["H6064","and are punished",78,94]]},"22:4":{"text":"By humility and the fear of the LORD are riches, and honour, and life.","words":[["H6118","By",0,2],["H6038","humility",3,11],["H3374","and the fear",12,24],["H3068","of the LORD",25,36],["H6239","are riches",37,47],["H3519","and honour",49,59],["H2416","and life",61,69]]},"22:5":{"text":"Thorns and snares are in the way of the froward: he that doth keep his soul shall be far from them.","words":[["H6791","Thorns",0,6],["H6341","and snares",7,17],["H1870","are in the way",18,32],["H6141","of the froward",33,47],["H8104","he that doth keep",49,66],["H5315","his soul",67,75],["H7368","shall be far",76,88]]},"22:6":{"text":"Train up a child in the way he should go: and when he is old, he will not depart from it.","words":[["H2596","Train up",0,8],["H5288","a child",9,16],["H1870","in the way",17,27],["H6310","he should go",28,40],["H2204","and when he is old",42,60],["H5493","he will not depart",62,80]]},"22:7":{"text":"The rich ruleth over the poor, and the borrower is servant to the lender.","words":[["H6223","The rich",0,8],["H4910","ruleth",9,15],["H7326","over the poor",16,29],["H3867","and the borrower",31,47],["H5650","is servant",48,58],["H0376","to the lender",59,72],["H3867","to the lender",59,72]]},"22:8":{"text":"He that soweth iniquity shall reap vanity: and the rod of his anger shall fail.","words":[["H2232","He that soweth",0,14],["H5766","iniquity",15,23],["H7114","shall reap",24,34],["H0205","vanity",35,41],["H7626","and the rod",43,54],["H5678","of his anger",55,67],["H3615","shall fail",68,78]]},"22:9":{"text":"He that hath a bountiful eye shall be blessed; for he giveth of his bread to the poor.","words":[["H2896","He that hath a bountiful",0,24],["H5869","eye",25,28],["H1288","shall be blessed",29,45],["H5414","for he giveth",47,60],["H3899","of his bread",61,73],["H1800","to the poor",74,85]]},"22:10":{"text":"Cast out the scorner, and contention shall go out; yea, strife and reproach shall cease.","words":[["H1644","Cast out",0,8],["H3887","the scorner",9,20],["H4066","and contention",22,36],["H3318","shall go out",37,49],["H1779","yea, strife",51,62],["H7036","and reproach",63,75],["H7673","shall cease",76,87]]},"22:11":{"text":"He that loveth pureness of heart, for the grace of his lips the king shall be his friend.","words":[["H0157","He that loveth",0,14],["H2890","pureness",15,23],["H2889","pureness",15,23],["H3820","of heart",24,32],["H2580","for the grace",34,47],["H8193","of his lips",48,59],["H4428","the king",60,68],["H7453","shall be his friend",69,88]]},"22:12":{"text":"The eyes of the LORD preserve knowledge, and he overthroweth the words of the transgressor.","words":[["H5869","The eyes",0,8],["H3068","of the LORD",9,20],["H5341","preserve",21,29],["H1847","knowledge",30,39],["H5557","and he overthroweth",41,60],["H1697","the words",61,70],["H0898","of the transgressor",71,90]]},"22:13":{"text":"The slothful man saith, There is a lion without, I shall be slain in the streets.","words":[["H6102","The slothful",0,12],["H0559","man saith",13,22],["H0738","There is a lion",24,39],["H2351","without",40,47],["H7523","I shall be slain",49,65],["H8432","in",66,68],["H7339","the streets",69,80]]},"22:14":{"text":"The mouth of strange women is a deep pit: he that is abhorred of the LORD shall fall therein.","words":[["H6310","The mouth",0,9],["H2114","of strange women",10,26],["H6013","is a deep",27,36],["H7745","pit",37,40],["H2194","he that is abhorred",42,61],["H3068","of the LORD",62,73],["H5307","shall fall",74,84]]},"22:15":{"text":"Foolishness is bound in the heart of a child; but the rod of correction shall drive it far from him.","words":[["H0200","Foolishness",0,11],["H7194","is bound",12,20],["H3820","in the heart",21,33],["H5288","of a child",34,44],["H7626","but the rod",46,57],["H4148","of correction",58,71],["H7368","shall drive it far",72,90]]},"22:16":{"text":"He that oppresseth the poor to increase his riches, and he that giveth to the rich, shall surely come to want.","words":[["H6231","He that oppresseth",0,18],["H1800","the poor",19,27],["H7235","to increase",28,39],["H5414","his riches, and he that giveth",40,70],["H6223","to the rich",71,82],["H4270","shall surely come to want",84,109]]},"22:17":{"text":"Bow down thine ear, and hear the words of the wise, and apply thine heart unto my knowledge.","words":[["H5186","Bow down",0,8],["H0241","thine ear",9,18],["H8085","and hear",20,28],["H1697","the words",29,38],["H2450","of the wise",39,50],["H7896","and apply",52,61],["H3820","thine heart",62,73],["H1847","unto my knowledge",74,91]]},"22:18":{"text":"For it is a pleasant thing if thou keep them within thee; they shall withal be fitted in thy lips.","words":[["H5273","For it is a pleasant thing",0,26],["H8104","if thou keep",27,39],["H0990","them within",40,51],["H3162","thee; they shall withal",52,75],["H3559","be fitted",76,85],["H8193","in thy lips",86,97]]},"22:19":{"text":"That thy trust may be in the LORD, I have made known to thee this day, even to thee.","words":[["H4009","That thy trust",0,14],["H3068","may be in the LORD",15,33],["H3045","I have made known",35,52],["H3117","to thee this day",53,69]]},"22:20":{"text":"Have not I written to thee excellent things in counsels and knowledge,","words":[["H3789","Have not I written",0,18],["H8032","to thee",19,26],["H7991","excellent things",27,43],["H4156","in counsels",44,55],["H1847","and knowledge",56,69]]},"22:21":{"text":"That I might make thee know the certainty of the words of truth; that thou mightest answer the words of truth to them that send unto thee?","words":[["H3045","That I might make thee know",0,27],["H7189","the certainty",28,41],["H0561","of the words",42,54],["H0571","of truth",55,63],["H7725","that thou mightest answer",65,90],["H0561","the words",91,100],["H0571","of truth",101,109],["H7971","to them that send",110,127]]},"22:22":{"text":"Rob not the poor, because he is poor: neither oppress the afflicted in the gate:","words":[["H1497","Rob",0,3],["H1800","not the poor",4,16],["H1800","because he is poor",18,36],["H1792","neither oppress",38,53],["H6041","the afflicted",54,67],["H8179","in the gate",68,79]]},"22:23":{"text":"For the LORD will plead their cause, and spoil the soul of those that spoiled them.","words":[["H3068","For the LORD",0,12],["H7378","will plead",13,23],["H7379","their cause",24,35],["H6906","and spoil",37,46],["H5315","the soul",47,55],["H6906","of those that spoiled",56,77]]},"22:24":{"text":"Make no friendship with an angry man; and with a furious man thou shalt not go:","words":[["H7462","Make no friendship",0,18],["H0639","with an angry",19,32],["H1167","man",33,36],["H2534","and with a furious",38,56],["H0376","man",57,60],["H0935","thou shalt not go",61,78]]},"22:25":{"text":"Lest thou learn his ways, and get a snare to thy soul.","words":[["H0502","Lest thou learn",0,15],["H0734","his ways",16,24],["H3947","and get",26,33],["H4170","a snare",34,41],["H5315","to thy soul",42,53]]},"22:26":{"text":"Be not thou one of them that strike hands, or of them that are sureties for debts.","words":[["H8628","Be not thou one of them that strike",0,35],["H3709","hands",36,41],["H6148","or of them that are sureties",43,71],["H4859","for debts",72,81]]},"22:27":{"text":"If thou hast nothing to pay, why should he take away thy bed from under thee?","words":[["H7999","If thou hast nothing to pay",0,27],["H3947","why should he take away",29,52],["H4904","thy bed",53,60]]},"22:28":{"text":"Remove not the ancient landmark, which thy fathers have set.","words":[["H5253","Remove",0,6],["H5769","not the ancient",7,22],["H1366","landmark",23,31],["H0001","which thy fathers",33,50],["H6213","have set",51,59]]},"22:29":{"text":"Seest thou a man diligent in his business? he shall stand before kings; he shall not stand before mean men.","words":[["H2372","Seest",0,5],["H0376","thou a man",6,16],["H4106","diligent",17,25],["H4399","in his business",26,41],["H3320","he shall stand",43,57],["H6440","before",58,64],["H4428","kings",65,70],["H3320","he shall not stand",72,90],["H6440","before",91,97],["H2823","mean",98,102]]},"23:1":{"text":"When thou sittest to eat with a ruler, consider diligently what is before thee:","words":[["H3427","When thou sittest",0,17],["H3898","to eat",18,24],["H4910","with a ruler",25,37],["H0995","consider",39,47],["H0995","diligently",48,58],["H6440","what is before",59,73]]},"23:2":{"text":"And put a knife to thy throat, if thou be a man given to appetite.","words":[["H7760","And put",0,7],["H7915","a knife",8,15],["H3930","to thy throat",16,29],["H1167","if thou be a man given",31,53],["H5315","to appetite",54,65]]},"23:3":{"text":"Be not desirous of his dainties: for they are deceitful meat.","words":[["H0183","Be not desirous",0,15],["H4303","of his dainties",16,31],["H3577","for they are deceitful",33,55],["H3899","meat",56,60]]},"23:4":{"text":"Labour not to be rich: cease from thine own wisdom.","words":[["H3021","Labour",0,6],["H6238","not to be rich",7,21],["H2308","cease",23,28],["H0998","from thine own wisdom",29,50]]},"23:5":{"text":"Wilt thou set thine eyes upon that which is not? for riches certainly make themselves wings; they fly away as an eagle toward heaven.","words":[["H5774","Wilt thou set",0,13],["H5774","Wilt thou set",0,13],["H5869","thine eyes",14,24],["H6213","upon that which is not? for riches certainly",25,69],["H6213","make",70,74],["H3671","themselves wings",75,91],["H5774","they fly away",93,106],["H5774","they fly away",93,106],["H5404","as an eagle",107,118],["H8064","toward heaven",119,132]]},"23:6":{"text":"Eat thou not the bread of him that hath an evil eye, neither desire thou his dainty meats:","words":[["H3898","Eat",0,3],["H3899","thou not the bread",4,22],["H7451","of him that hath an evil",23,47],["H5869","eye",48,51],["H0183","neither desire",53,67],["H4303","thou his dainty meats",68,89]]},"23:7":{"text":"For as he thinketh in his heart, so is he: Eat and drink, saith he to thee; but his heart is not with thee.","words":[["H8176","For as he thinketh",0,18],["H5315","in his heart",19,31],["H0398","so is he: Eat",33,46],["H8354","and drink",47,56],["H0559","saith",58,63],["H3820","he to thee; but his heart",64,89]]},"23:8":{"text":"The morsel which thou hast eaten shalt thou vomit up, and lose thy sweet words.","words":[["H6595","The morsel",0,10],["H0398","which thou hast eaten",11,32],["H6958","shalt thou vomit up",33,52],["H7843","and lose",54,62],["H5273","thy sweet",63,72],["H1697","words",73,78]]},"23:9":{"text":"Speak not in the ears of a fool: for he will despise the wisdom of thy words.","words":[["H1696","Speak",0,5],["H0241","not in the ears",6,21],["H3684","of a fool",22,31],["H0936","for he will despise",33,52],["H7922","the wisdom",53,63],["H4405","of thy words",64,76]]},"23:10":{"text":"Remove not the old landmark; and enter not into the fields of the fatherless:","words":[["H5253","Remove",0,6],["H5769","not the old",7,18],["H1366","landmark",19,27],["H0935","and enter",29,38],["H7704","not into the fields",39,58],["H3490","of the fatherless",59,76]]},"23:11":{"text":"For their redeemer is mighty; he shall plead their cause with thee.","words":[["H1350","For their redeemer",0,18],["H2389","is mighty",19,28],["H7378","he shall plead",30,44],["H7379","their cause",45,56]]},"23:12":{"text":"Apply thine heart unto instruction, and thine ears to the words of knowledge.","words":[["H0935","Apply",0,5],["H3820","thine heart",6,17],["H4148","unto instruction",18,34],["H0241","and thine ears",36,50],["H0561","to the words",51,63],["H1847","of knowledge",64,76]]},"23:13":{"text":"Withhold not correction from the child: for if thou beatest him with the rod, he shall not die.","words":[["H4513","Withhold",0,8],["H4148","not correction",9,23],["H5288","from the child",24,38],["H5221","for if thou beatest",40,59],["H7626","him with the rod",60,76],["H4191","he shall not die",78,94]]},"23:14":{"text":"Thou shalt beat him with the rod, and shalt deliver his soul from hell.","words":[["H5221","Thou shalt beat",0,15],["H7626","him with the rod",16,32],["H5337","and shalt deliver",34,51],["H5315","his soul",52,60],["H7585","from hell",61,70]]},"23:15":{"text":"My son, if thine heart be wise, my heart shall rejoice, even mine.","words":[["H1121","My son",0,6],["H3820","if thine heart",8,22],["H2449","be wise",23,30],["H3820","my heart",32,40],["H8055","shall rejoice",41,54],["H0589","even mine",56,65]]},"23:16":{"text":"Yea, my reins shall rejoice, when thy lips speak right things.","words":[["H3629","Yea, my reins",0,13],["H5937","shall rejoice",14,27],["H8193","when thy lips",29,42],["H1696","speak",43,48],["H4339","right things",49,61]]},"23:17":{"text":"Let not thine heart envy sinners: but be thou in the fear of the LORD all the day long.","words":[["H3820","Let not thine heart",0,19],["H7065","envy",20,24],["H2400","sinners",25,32],["H3374","but be thou in the fear",34,57],["H3068","of the LORD",58,69],["H3117","all the day",70,81]]},"23:18":{"text":"For surely there is an end; and thine expectation shall not be cut off.","words":[["H3426","For surely there is",0,19],["H0319","an end",20,26],["H8615","and thine expectation",28,49],["H3772","shall not be cut off",50,70]]},"23:19":{"text":"Hear thou, my son, and be wise, and guide thine heart in the way.","words":[["H8085","Hear",0,4],["H1121","thou, my son",5,17],["H2449","and be wise",19,30],["H0833","and guide",32,41],["H3820","thine heart",42,53],["H1870","in the way",54,64]]},"23:20":{"text":"Be not among winebibbers; among riotous eaters of flesh:","words":[["H3196","Be not among winebibbers",0,24],["H5433","Be not among winebibbers",0,24],["H2151","among riotous eaters",26,46],["H1320","of flesh",47,55]]},"23:21":{"text":"For the drunkard and the glutton shall come to poverty: and drowsiness shall clothe a man with rags.","words":[["H5433","For the drunkard",0,16],["H2151","and the glutton",17,32],["H3423","shall come to poverty",33,54],["H5124","and drowsiness",56,70],["H3847","shall clothe",71,83],["H7168","a man with rags",84,99]]},"23:22":{"text":"Hearken unto thy father that begat thee, and despise not thy mother when she is old.","words":[["H8085","Hearken",0,7],["H0001","unto thy father",8,23],["H3205","that begat",24,34],["H0936","thee, and despise",35,52],["H0517","not thy mother",53,67],["H2204","when she is old",68,83]]},"23:23":{"text":"Buy the truth, and sell it not; also wisdom, and instruction, and understanding.","words":[["H7069","Buy",0,3],["H0571","the truth",4,13],["H4376","and sell",15,23],["H2451","it not; also wisdom",24,43],["H4148","and instruction",45,60],["H0998","and understanding",62,79]]},"23:24":{"text":"The father of the righteous shall greatly rejoice: and he that begetteth a wise child shall have joy of him.","words":[["H0001","The father",0,10],["H6662","of the righteous",11,27],["H1524","shall greatly",28,41],["H1523","rejoice",42,49],["H3205","and he that begetteth",51,72],["H2450","a wise",73,79],["H8055","child shall have joy",80,100]]},"23:25":{"text":"Thy father and thy mother shall be glad, and she that bare thee shall rejoice.","words":[["H0001","Thy father",0,10],["H0517","and thy mother",11,25],["H8055","shall be glad",26,39],["H3205","and she that bare",41,58],["H1523","thee shall rejoice",59,77]]},"23:26":{"text":"My son, give me thine heart, and let thine eyes observe my ways.","words":[["H1121","My son",0,6],["H5414","give",8,12],["H3820","me thine heart",13,27],["H5869","and let thine eyes",29,47],["H7521","observe",48,55],["H5341","observe",48,55],["H1870","my ways",56,63]]},"23:27":{"text":"For a whore is a deep ditch; and a strange woman is a narrow pit.","words":[["H2181","For a whore",0,11],["H6013","is a deep",12,21],["H7745","ditch",22,27],["H5237","and a strange woman",29,48],["H6862","is a narrow",49,60],["H0875","pit",61,64]]},"23:28":{"text":"She also lieth in wait as for a prey, and increaseth the transgressors among men.","words":[["H0693","She also lieth in wait",0,22],["H2863","as for a prey",23,36],["H3254","and increaseth",38,52],["H0898","the transgressors",53,70],["H0120","among men",71,80]]},"23:29":{"text":"Who hath woe? who hath sorrow? who hath contentions? who hath babbling? who hath wounds without cause? who hath redness of eyes?","words":[["H0188","Who hath woe",0,12],["H0017","who hath sorrow",14,29],["H4079","who hath contentions",31,51],["H4066","who hath contentions",31,51],["H7879","who hath babbling",53,70],["H6482","who hath wounds",72,87],["H2600","without cause",88,101],["H2448","who hath redness",103,119],["H5869","of eyes",120,127]]},"23:30":{"text":"They that tarry long at the wine; they that go to seek mixed wine.","words":[["H0309","They that tarry long",0,20],["H3196","at the wine",21,32],["H0935","they that go",34,46],["H2713","to seek",47,54],["H4469","mixed wine",55,65]]},"23:31":{"text":"Look not thou upon the wine when it is red, when it giveth his colour in the cup, when it moveth itself aright.","words":[["H7200","Look",0,4],["H3196","not thou upon the wine",5,27],["H0119","when it is red",28,42],["H5414","when it giveth",44,58],["H5869","his colour",59,69],["H3563","in the cup",70,80],["H3599","in the cup",70,80],["H1980","when it moveth",82,96],["H4339","itself aright",97,110]]},"23:32":{"text":"At the last it biteth like a serpent, and stingeth like an adder.","words":[["H0319","At the last",0,11],["H5391","it biteth",12,21],["H5175","like a serpent",22,36],["H6567","and stingeth",38,50],["H6848","like an adder",51,64]]},"23:33":{"text":"Thine eyes shall behold strange women, and thine heart shall utter perverse things.","words":[["H5869","Thine eyes",0,10],["H7200","shall behold",11,23],["H2114","strange women",24,37],["H3820","and thine heart",39,54],["H1696","shall utter",55,66],["H8419","perverse things",67,82]]},"23:34":{"text":"Yea, thou shalt be as he that lieth down in the midst of the sea, or as he that lieth upon the top of a mast.","words":[["H7901","Yea, thou shalt be as he that lieth down",0,40],["H3820","in the midst",41,53],["H3220","of the sea",54,64],["H7901","or as he that lieth",66,85],["H7218","upon the top",86,98],["H2260","of a mast",99,108]]},"23:35":{"text":"They have stricken me, shalt thou say, and I was not sick; they have beaten me, and I felt it not: when shall I awake? I will seek it yet again.","words":[["H5221","They have stricken",0,18],["H2470","me, shalt thou say, and I was not sick",19,57],["H1986","they have beaten",59,75],["H3045","me, and I felt",76,90],["H6974","it not: when shall I awake",91,117],["H1245","I will seek",119,130],["H3254","it yet",131,137]]},"24:1":{"text":"Be not thou envious against evil men, neither desire to be with them.","words":[["H7065","Be not thou envious",0,19],["H7451","against evil",20,32],["H0582","men",33,36],["H0183","neither desire",38,52]]},"24:2":{"text":"For their heart studieth destruction, and their lips talk of mischief.","words":[["H3820","For their heart",0,15],["H1897","studieth",16,24],["H7701","destruction",25,36],["H8193","and their lips",38,52],["H1696","talk",53,57],["H5999","of mischief",58,69]]},"24:3":{"text":"Through wisdom is an house builded; and by understanding it is established:","words":[["H2451","Through wisdom",0,14],["H1004","is an house",15,26],["H1129","builded",27,34],["H8394","and by understanding",36,56],["H3559","it is established",57,74]]},"24:4":{"text":"And by knowledge shall the chambers be filled with all precious and pleasant riches.","words":[["H1847","And by knowledge",0,16],["H2315","shall the chambers",17,35],["H4390","be filled",36,45],["H3368","with all precious",46,63],["H5273","and pleasant",64,76],["H1952","riches",77,83]]},"24:5":{"text":"A wise man is strong; yea, a man of knowledge increaseth strength.","words":[["H2450","A wise",0,6],["H1397","man",7,10],["H5797","is strong",11,20],["H0376","yea, a man",22,32],["H1847","of knowledge",33,45],["H0553","increaseth",46,56],["H3581","strength",57,65]]},"24:6":{"text":"For by wise counsel thou shalt make thy war: and in multitude of counsellors there is safety.","words":[["H8458","For by wise counsel",0,19],["H6213","thou shalt make",20,35],["H4421","thy war",36,43],["H7230","and in multitude",45,61],["H3289","of counsellors",62,76],["H8668","there is safety",77,92]]},"24:7":{"text":"Wisdom is too high for a fool: he openeth not his mouth in the gate.","words":[["H2454","Wisdom",0,6],["H7311","is too high",7,18],["H0191","for a fool",19,29],["H6605","he openeth",31,41],["H6310","not his mouth",42,55],["H8179","in the gate",56,67]]},"24:8":{"text":"He that deviseth to do evil shall be called a mischievous person.","words":[["H2803","He that deviseth",0,16],["H7489","to do evil",17,27],["H7121","shall be called",28,43],["H4209","a mischievous",44,57],["H1167","person",58,64]]},"24:9":{"text":"The thought of foolishness is sin: and the scorner is an abomination to men.","words":[["H2154","The thought",0,11],["H0200","of foolishness",12,26],["H2403","is sin",27,33],["H3887","and the scorner",35,50],["H8441","is an abomination",51,68],["H0120","to men",69,75]]},"24:10":{"text":"If thou faint in the day of adversity, thy strength is small.","words":[["H7503","If thou faint",0,13],["H3117","in the day",14,24],["H6869","of adversity",25,37],["H3581","thy strength",39,51],["H6862","is small",52,60]]},"24:11":{"text":"If thou forbear to deliver them that are drawn unto death, and those that are ready to be slain;","words":[["H2820","If thou forbear",0,15],["H5337","to deliver",16,26],["H3947","them that are drawn",27,46],["H4194","unto death",47,57],["H4131","and those that are ready",59,83],["H2027","to be slain",84,95]]},"24:12":{"text":"If thou sayest, Behold, we knew it not; doth not he that pondereth the heart consider it? and he that keepeth thy soul, doth not he know it? and shall not he render to every man according to his works?","words":[["H0559","If thou sayest",0,14],["H3045","Behold, we knew",16,31],["H8505","it not; doth not he that pondereth",32,66],["H3826","the heart",67,76],["H0995","consider",77,85],["H5341","it? and he that keepeth",86,109],["H5315","thy soul",110,118],["H3045","doth not he know",120,136],["H7725","it? and shall not he render",137,164],["H0120","to every man",165,177],["H6467","according to his works",178,200]]},"24:13":{"text":"My son, eat thou honey, because it is good; and the honeycomb, which is sweet to thy taste:","words":[["H1121","My son",0,6],["H0398","eat",8,11],["H1706","thou honey",12,22],["H2896","because it is good",24,42],["H5317","and the honeycomb",44,61],["H4966","which is sweet",63,77],["H2441","to thy taste",78,90]]},"24:14":{"text":"So shall the knowledge of wisdom be unto thy soul: when thou hast found it, then there shall be a reward, and thy expectation shall not be cut off.","words":[["H3045","So shall the knowledge",0,22],["H2451","of wisdom",23,32],["H5315","be unto thy soul",33,49],["H4672","when thou hast found",51,71],["H3426","it, then there shall be",72,95],["H0319","a reward",96,104],["H8615","and thy expectation",106,125],["H3772","shall not be cut off",126,146]]},"24:15":{"text":"Lay not wait, O wicked man, against the dwelling of the righteous; spoil not his resting place:","words":[["H0693","Lay not wait",0,12],["H7563","O wicked",14,22],["H5116","man, against the dwelling",23,48],["H6662","of the righteous",49,65],["H7703","spoil",67,72],["H7258","not his resting place",73,94]]},"24:16":{"text":"For a just man falleth seven times, and riseth up again: but the wicked shall fall into mischief.","words":[["H6662","For a just",0,10],["H5307","man falleth",11,22],["H7651","seven times",23,34],["H6965","and riseth up again",36,55],["H7563","but the wicked",57,71],["H3782","shall fall",72,82],["H7451","into mischief",83,96]]},"24:17":{"text":"Rejoice not when thine enemy falleth, and let not thine heart be glad when he stumbleth:","words":[["H8055","Rejoice",0,7],["H0341","not when thine enemy",8,28],["H5307","falleth",29,36],["H3820","and let not thine heart",38,61],["H1523","be glad",62,69],["H3782","when he stumbleth",70,87]]},"24:18":{"text":"Lest the LORD see it, and it displease him, and he turn away his wrath from him.","words":[["H3068","Lest the LORD",0,13],["H7200","see",14,17],["H7489","it, and it displease",18,38],["H5869","it, and it displease",18,38],["H7725","him, and he turn away",39,60],["H0639","his wrath",61,70]]},"24:19":{"text":"Fret not thyself because of evil men, neither be thou envious at the wicked;","words":[["H2734","Fret",0,4],["H7489","not thyself because of evil",5,32],["H7065","men, neither be thou envious",33,61],["H7563","at the wicked",62,75]]},"24:20":{"text":"For there shall be no reward to the evil man; the candle of the wicked shall be put out.","words":[["H0319","For there shall be no reward",0,28],["H7451","to the evil",29,40],["H5216","man; the candle",41,56],["H7563","of the wicked",57,70],["H1846","shall be put out",71,87]]},"24:21":{"text":"My son, fear thou the LORD and the king: and meddle not with them that are given to change:","words":[["H1121","My son",0,6],["H3372","fear",8,12],["H3068","thou the LORD",13,26],["H4428","and the king",27,39],["H6148","and meddle",41,51],["H8138","not with them that are given to change",52,90]]},"24:22":{"text":"For their calamity shall rise suddenly; and who knoweth the ruin of them both?","words":[["H0343","For their calamity",0,18],["H6965","shall rise",19,29],["H6597","suddenly",30,38],["H3045","and who knoweth",40,55],["H6365","the ruin",56,64],["H8147","of them both",65,77]]},"24:23":{"text":"These things also belong to the wise. It is not good to have respect of persons in judgment.","words":[["H2450","These things also belong to the wise",0,36],["H2896","It is not good",38,52],["H5234","to have respect",53,68],["H6440","of persons",69,79],["H4941","in judgment",80,91]]},"24:24":{"text":"He that saith unto the wicked, Thou art righteous; him shall the people curse, nations shall abhor him:","words":[["H0559","He that saith",0,13],["H7563","unto the wicked",14,29],["H6662","Thou art righteous",31,49],["H5971","him shall the people",51,71],["H5344","curse",72,77],["H3816","nations",79,86],["H2194","shall abhor",87,98]]},"24:25":{"text":"But to them that rebuke him shall be delight, and a good blessing shall come upon them.","words":[["H3198","But to them that rebuke",0,23],["H5276","him shall be delight",24,44],["H2896","and a good",46,56],["H1293","blessing",57,65],["H0935","shall come",66,76]]},"24:26":{"text":"Every man shall kiss his lips that giveth a right answer.","words":[["H5401","Every man shall kiss",0,20],["H8193","his lips",21,29],["H7725","that giveth",30,41],["H5228","a right",42,49],["H1697","answer",50,56]]},"24:27":{"text":"Prepare thy work without, and make it fit for thyself in the field; and afterwards build thine house.","words":[["H3559","Prepare",0,7],["H4399","thy work",8,16],["H2351","without",17,24],["H6257","and make it fit",26,41],["H7704","for thyself in the field",42,66],["H0310","and afterwards",68,82],["H1129","build",83,88],["H1004","thine house",89,100]]},"24:28":{"text":"Be not a witness against thy neighbour without cause; and deceive not with thy lips.","words":[["H5707","Be not a witness",0,16],["H7453","against thy neighbour",17,38],["H2600","without cause",39,52],["H6601","and deceive",54,65],["H8193","not with thy lips",66,83]]},"24:29":{"text":"Say not, I will do so to him as he hath done to me: I will render to the man according to his work.","words":[["H0559","Say",0,3],["H6213","not, I will do",4,18],["H6213","so to him as he hath done",19,44],["H7725","to me: I will render",45,65],["H0376","to the man",66,76],["H6467","according to his work",77,98]]},"24:30":{"text":"I went by the field of the slothful, and by the vineyard of the man void of understanding;","words":[["H5674","I went",0,6],["H7704","by the field",7,19],["H0376","of the slothful",20,35],["H6102","of the slothful",20,35],["H3754","and by the vineyard",37,56],["H0120","of the man",57,67],["H2638","void",68,72],["H3820","of understanding",73,89]]},"24:31":{"text":"And, lo, it was all grown over with thorns, and nettles had covered the face thereof, and the stone wall thereof was broken down.","words":[["H5927","And, lo, it was all grown over",0,30],["H7063","with thorns",31,42],["H2738","and nettles",44,55],["H3680","had covered",56,67],["H6440","the face",68,76],["H0068","thereof, and the stone",77,99],["H1444","wall",100,104],["H2040","thereof was broken down",105,128]]},"24:32":{"text":"Then I saw, and considered it well: I looked upon it, and received instruction.","words":[["H2372","Then I saw",0,10],["H7896","and considered it well",12,34],["H3820","and considered it well",12,34],["H7200","I looked",36,44],["H3947","upon it, and received",45,66],["H4148","instruction",67,78]]},"24:33":{"text":"Yet a little sleep, a little slumber, a little folding of the hands to sleep:","words":[["H4592","Yet a little",0,12],["H8142","sleep",13,18],["H4592","a little",20,28],["H8572","slumber",29,36],["H4592","a little",38,46],["H2264","folding",47,54],["H3027","of the hands",55,67],["H7901","to sleep",68,76]]},"24:34":{"text":"So shall thy poverty come as one that travelleth; and thy want as an armed man.","words":[["H7389","So shall thy poverty",0,20],["H0935","come",21,25],["H1980","as one that travelleth",26,48],["H4270","and thy want",50,62],["H4043","as an armed",63,74],["H0376","man",75,78]]},"25:1":{"text":"These are also proverbs of Solomon, which the men of Hezekiah king of Judah copied out.","words":[["H4912","These are also proverbs",0,23],["H8010","of Solomon",24,34],["H0582","which the men",36,49],["H2396","of Hezekiah",50,61],["H4428","king",62,66],["H3063","of Judah",67,75],["H6275","copied out",76,86]]},"25:2":{"text":"It is the glory of God to conceal a thing: but the honour of kings is to search out a matter.","words":[["H3519","It is the glory",0,15],["H0430","of God",16,22],["H5641","to conceal",23,33],["H1697","a thing",34,41],["H3519","but the honour",43,57],["H4428","of kings",58,66],["H2713","is to search out",67,83],["H1697","a matter",84,92]]},"25:3":{"text":"The heaven for height, and the earth for depth, and the heart of kings is unsearchable.","words":[["H8064","The heaven",0,10],["H7312","for height",11,21],["H0776","and the earth",23,36],["H6011","for depth",37,46],["H3820","and the heart",48,61],["H4428","of kings",62,70],["H2714","is unsearchable",71,86]]},"25:4":{"text":"Take away the dross from the silver, and there shall come forth a vessel for the finer.","words":[["H1898","Take away",0,9],["H5509","the dross",10,19],["H3701","from the silver",20,35],["H3318","and there shall come forth",37,63],["H3627","a vessel",64,72],["H6884","for the finer",73,86]]},"25:5":{"text":"Take away the wicked from before the king, and his throne shall be established in righteousness.","words":[["H1898","Take away",0,9],["H7563","the wicked",10,20],["H6440","from before",21,32],["H4428","the king",33,41],["H3678","and his throne",43,57],["H3559","shall be established",58,78],["H6664","in righteousness",79,95]]},"25:6":{"text":"Put not forth thyself in the presence of the king, and stand not in the place of great men:","words":[["H1921","Put not forth",0,13],["H6440","thyself in the presence",14,37],["H4428","of the king",38,49],["H5975","and stand",51,60],["H4725","not in the place",61,77],["H1419","of great",78,86]]},"25:7":{"text":"For better it is that it be said unto thee, Come up hither; than that thou shouldest be put lower in the presence of the prince whom thine eyes have seen.","words":[["H2896","For better",0,10],["H0559","it is that it be said",11,32],["H5927","unto thee, Come up",33,51],["H8213","hither; than that thou shouldest be put lower",52,97],["H6440","in the presence",98,113],["H5081","of the prince",114,127],["H5869","whom thine eyes",128,143],["H7200","have seen",144,153]]},"25:8":{"text":"Go not forth hastily to strive, lest thou know not what to do in the end thereof, when thy neighbour hath put thee to shame.","words":[["H3318","Go not forth",0,12],["H4118","hastily",13,20],["H7378","to strive",21,30],["H6213","lest thou know not what to do",32,61],["H0319","in the end",62,72],["H7453","thereof, when thy neighbour",73,100],["H3637","hath put thee to shame",101,123]]},"25:9":{"text":"Debate thy cause with thy neighbour himself; and discover not a secret to another:","words":[["H7378","Debate",0,6],["H7379","thy cause",7,16],["H7453","with thy neighbour",17,35],["H1540","himself; and discover",36,57],["H5475","not a secret",58,70],["H0312","to another",71,81]]},"25:10":{"text":"Lest he that heareth it put thee to shame, and thine infamy turn not away.","words":[["H8085","Lest he that heareth",0,20],["H2616","it put thee to shame",21,41],["H1681","and thine infamy",43,59],["H7725","turn not away",60,73]]},"25:11":{"text":"A word fitly spoken is like apples of gold in pictures of silver.","words":[["H1697","A word",0,6],["H0212","fitly",7,12],["H0655","fitly",7,12],["H1696","spoken",13,19],["H8598","is like apples",20,34],["H2091","of gold",35,42],["H4906","in pictures",43,54],["H3701","of silver",55,64]]},"25:12":{"text":"As an earring of gold, and an ornament of fine gold, so is a wise reprover upon an obedient ear.","words":[["H5141","As an earring",0,13],["H2091","of gold",14,21],["H2481","and an ornament",23,38],["H3800","of fine gold",39,51],["H2450","so is a wise",53,65],["H3198","reprover",66,74],["H8085","upon an obedient",75,91],["H0241","ear",92,95]]},"25:13":{"text":"As the cold of snow in the time of harvest, so is a faithful messenger to them that send him: for he refresheth the soul of his masters.","words":[["H6793","As the cold",0,11],["H7950","of snow",12,19],["H3117","in the time",20,31],["H7105","of harvest",32,42],["H0539","so is a faithful",44,60],["H6735","messenger",61,70],["H7971","to them that send",71,88],["H7725","him: for he refresheth",89,111],["H5315","the soul",112,120],["H0113","of his masters",121,135]]},"25:14":{"text":"Whoso boasteth himself of a false gift is like clouds and wind without rain.","words":[["H0376","Whoso",0,5],["H1984","boasteth",6,14],["H8267","himself of a false",15,33],["H4991","gift",34,38],["H5387","is like clouds",39,53],["H7307","and wind",54,62],["H1653","without rain",63,75]]},"25:15":{"text":"By long forbearing is a prince persuaded, and a soft tongue breaketh the bone.","words":[["H0753","By long",0,7],["H0639","forbearing",8,18],["H7101","is a prince",19,30],["H6601","persuaded",31,40],["H7390","and a soft",42,52],["H3956","tongue",53,59],["H7665","breaketh",60,68],["H1634","the bone",69,77]]},"25:16":{"text":"Hast thou found honey? eat so much as is sufficient for thee, lest thou be filled therewith, and vomit it.","words":[["H4672","Hast thou found",0,15],["H1706","honey",16,21],["H0398","eat",23,26],["H1767","so much as is sufficient",27,51],["H7646","for thee, lest thou be filled",52,81],["H6958","therewith, and vomit",82,102]]},"25:17":{"text":"Withdraw thy foot from thy neighbour's house; lest he be weary of thee, and so hate thee.","words":[["H3365","Withdraw",0,8],["H7272","thy foot",9,17],["H7453","from thy neighbour's",18,38],["H1004","house",39,44],["H7646","lest he be weary",46,62],["H8130","of thee, and so hate",63,83]]},"25:18":{"text":"A man that beareth false witness against his neighbour is a maul, and a sword, and a sharp arrow.","words":[["H0376","A man",0,5],["H6030","that beareth",6,18],["H8267","false",19,24],["H5707","witness",25,32],["H7453","against his neighbour",33,54],["H4650","is a maul",55,64],["H2719","and a sword",66,77],["H8150","and a sharp",79,90],["H2671","arrow",91,96]]},"25:19":{"text":"Confidence in an unfaithful man in time of trouble is like a broken tooth, and a foot out of joint.","words":[["H4009","Confidence",0,10],["H0898","in an unfaithful man",11,31],["H3117","in time",32,39],["H6869","of trouble",40,50],["H7465","is like a broken",51,67],["H8127","tooth",68,73],["H7272","and a foot",75,85],["H4154","out of joint",86,98]]},"25:20":{"text":"As he that taketh away a garment in cold weather, and as vinegar upon nitre, so is he that singeth songs to an heavy heart.","words":[["H5710","As he that taketh away",0,22],["H0899","a garment",23,32],["H7135","in cold",33,40],["H3117","weather",41,48],["H2558","and as vinegar",50,64],["H5427","upon nitre",65,75],["H7891","so is he that singeth",77,98],["H7892","songs",99,104],["H7451","to an heavy",105,116],["H3820","heart",117,122]]},"25:21":{"text":"If thine enemy be hungry, give him bread to eat; and if he be thirsty, give him water to drink:","words":[["H8130","If thine enemy",0,14],["H7457","be hungry",15,24],["H3899","give him bread",26,40],["H0398","to eat",41,47],["H6771","and if he be thirsty",49,69],["H4325","give him water",71,85],["H8248","to drink",86,94]]},"25:22":{"text":"For thou shalt heap coals of fire upon his head, and the LORD shall reward thee.","words":[["H2846","For thou shalt heap",0,19],["H1513","coals of fire",20,33],["H7218","upon his head",34,47],["H3068","and the LORD",49,61],["H7999","shall reward",62,74]]},"25:23":{"text":"The north wind driveth away rain: so doth an angry countenance a backbiting tongue.","words":[["H6828","The north",0,9],["H7307","wind",10,14],["H2342","driveth away",15,27],["H1653","rain",28,32],["H2194","so doth an angry",34,50],["H6440","countenance",51,62],["H5643","a backbiting",63,75],["H3956","tongue",76,82]]},"25:24":{"text":"It is better to dwell in the corner of the housetop, than with a brawling woman and in a wide house.","words":[["H2896","It is better",0,12],["H3427","to dwell",13,21],["H6438","in the corner",22,35],["H1406","of the housetop",36,51],["H4079","than with a brawling",53,73],["H4066","than with a brawling",53,73],["H0802","woman",74,79],["H2267","and in a wide",80,93],["H1004","house",94,99]]},"25:25":{"text":"As cold waters to a thirsty soul, so is good news from a far country.","words":[["H7119","As cold",0,7],["H4325","waters",8,14],["H5889","to a thirsty",15,27],["H5315","soul",28,32],["H2896","so is good",34,44],["H8052","news",45,49],["H4801","from a far",50,60],["H0776","country",61,68]]},"25:26":{"text":"A righteous man falling down before the wicked is as a troubled fountain, and a corrupt spring.","words":[["H6662","A righteous",0,11],["H4131","man falling down",12,28],["H6440","before",29,35],["H7563","the wicked",36,46],["H7515","is as a troubled",47,63],["H4599","fountain",64,72],["H7843","and a corrupt",74,87],["H4726","spring",88,94]]},"25:27":{"text":"It is not good to eat much honey: so for men to search their own glory is not glory.","words":[["H2896","It is not good",0,14],["H0398","to eat",15,21],["H7235","much",22,26],["H1706","honey",27,32],["H2714","so for men to search",34,54],["H3519","their own glory",55,70],["H3519","is not glory",71,83]]},"25:28":{"text":"He that hath no rule over his own spirit is like a city that is broken down, and without walls.","words":[["H0376","He",0,2],["H4623","that hath no rule",3,20],["H7307","over his own spirit",21,40],["H5892","is like a city",41,55],["H6555","that is broken down",56,75],["H2346","and without walls",77,94]]},"26:1":{"text":"As snow in summer, and as rain in harvest, so honour is not seemly for a fool.","words":[["H7950","As snow",0,7],["H7019","in summer",8,17],["H4306","and as rain",19,30],["H7105","in harvest",31,41],["H3519","so honour",43,52],["H5000","is not seemly",53,66],["H3684","for a fool",67,77]]},"26:2":{"text":"As the bird by wandering, as the swallow by flying, so the curse causeless shall not come.","words":[["H6833","As the bird",0,11],["H5110","by wandering",12,24],["H1866","as the swallow",26,40],["H5774","by flying",41,50],["H7045","so the curse",52,64],["H2600","causeless",65,74],["H0935","shall not come",75,89]]},"26:3":{"text":"A whip for the horse, a bridle for the ass, and a rod for the fool's back.","words":[["H7752","A whip",0,6],["H5483","for the horse",7,20],["H4964","a bridle",22,30],["H2543","for the ass",31,42],["H7626","and a rod",44,53],["H3684","for the fool's",54,68],["H1460","back",69,73]]},"26:4":{"text":"Answer not a fool according to his folly, lest thou also be like unto him.","words":[["H6030","Answer",0,6],["H3684","not a fool",7,17],["H0200","according to his folly",18,40],["H7737","lest thou also be like",42,64]]},"26:5":{"text":"Answer a fool according to his folly, lest he be wise in his own conceit.","words":[["H6030","Answer",0,6],["H3684","a fool",7,13],["H0200","according to his folly",14,36],["H2450","lest he be wise",38,53],["H5869","in his own conceit",54,72]]},"26:6":{"text":"He that sendeth a message by the hand of a fool cutteth off the feet, and drinketh damage.","words":[["H7971","He that sendeth",0,15],["H1697","a message",16,25],["H3027","by the hand",26,37],["H3684","of a fool",38,47],["H7096","cutteth off",48,59],["H7272","the feet",60,68],["H8354","and drinketh",70,82],["H2555","damage",83,89]]},"26:7":{"text":"The legs of the lame are not equal: so is a parable in the mouth of fools.","words":[["H7785","The legs",0,8],["H6455","of the lame",9,20],["H1809","are not equal",21,34],["H4912","so is a parable",36,51],["H6310","in the mouth",52,64],["H3684","of fools",65,73]]},"26:8":{"text":"As he that bindeth a stone in a sling, so is he that giveth honour to a fool.","words":[["H6872","As he that bindeth",0,18],["H6887","As he that bindeth",0,18],["H0068","a stone",19,26],["H4773","in a sling",27,37],["H5414","so is he that giveth",39,59],["H3519","honour",60,66],["H3684","to a fool",67,76]]},"26:9":{"text":"As a thorn goeth up into the hand of a drunkard, so is a parable in the mouth of fools.","words":[["H2336","As a thorn",0,10],["H5927","goeth up",11,19],["H3027","into the hand",20,33],["H7910","of a drunkard",34,47],["H4912","so is a parable",49,64],["H6310","in the mouth",65,77],["H3684","of fools",78,86]]},"26:10":{"text":"The great God that formed all things both rewardeth the fool, and rewardeth transgressors.","words":[["H7227","The great",0,9],["H2342","God that formed",10,25],["H7936","all things both rewardeth",26,51],["H3684","the fool",52,60],["H7936","and rewardeth",62,75],["H5674","transgressors",76,89]]},"26:11":{"text":"As a dog returneth to his vomit, so a fool returneth to his folly.","words":[["H3611","As a dog",0,8],["H7725","returneth",9,18],["H6892","to his vomit",19,31],["H3684","so a fool",33,42],["H8138","returneth",43,52],["H0200","to his folly",53,65]]},"26:12":{"text":"Seest thou a man wise in his own conceit? there is more hope of a fool than of him.","words":[["H7200","Seest",0,5],["H0376","thou a man",6,16],["H2450","wise",17,21],["H5869","in his own conceit",22,40],["H8615","there is more hope",42,60],["H3684","of a fool",61,70]]},"26:13":{"text":"The slothful man saith, There is a lion in the way; a lion is in the streets.","words":[["H6102","The slothful",0,12],["H0559","man saith",13,22],["H7826","There is a lion",24,39],["H1870","in the way",40,50],["H0738","a lion",52,58],["H7339","is in the streets",59,76]]},"26:14":{"text":"As the door turneth upon his hinges, so doth the slothful upon his bed.","words":[["H1817","As the door",0,11],["H5437","turneth",12,19],["H6735","upon his hinges",20,35],["H6102","so doth the slothful",37,57],["H4296","upon his bed",58,70]]},"26:15":{"text":"The slothful hideth his hand in his bosom; it grieveth him to bring it again to his mouth.","words":[["H6102","The slothful",0,12],["H2934","hideth",13,19],["H3027","his hand",20,28],["H6747","in his bosom",29,41],["H3811","it grieveth",43,54],["H7725","him to bring it again",55,76],["H6310","to his mouth",77,89]]},"26:16":{"text":"The sluggard is wiser in his own conceit than seven men that can render a reason.","words":[["H6102","The sluggard",0,12],["H2450","is wiser",13,21],["H5869","in his own conceit",22,40],["H7651","than seven men",41,55],["H7725","that can render",56,71],["H2940","a reason",72,80]]},"26:17":{"text":"He that passeth by, and meddleth with strife belonging not to him, is like one that taketh a dog by the ears.","words":[["H5674","He that passeth by",0,18],["H5674","and meddleth",20,32],["H7379","with strife",33,44],["H2388","belonging not to him, is like one that taketh",45,90],["H3611","a dog",91,96],["H0241","by the ears",97,108]]},"26:18":{"text":"As a mad man who casteth firebrands, arrows, and death,","words":[["H3856","As a mad",0,8],["H3384","man who casteth",9,24],["H2131","firebrands",25,35],["H2671","arrows",37,43],["H4194","and death",45,54]]},"26:19":{"text":"So is the man that deceiveth his neighbour, and saith, Am not I in sport?","words":[["H0376","So is the man",0,13],["H7411","that deceiveth",14,28],["H7453","his neighbour",29,42],["H0559","and saith",44,53],["H7832","Am not I in sport",55,72]]},"26:20":{"text":"Where no wood is, there the fire goeth out: so where there is no talebearer, the strife ceaseth.","words":[["H0657","Where no",0,8],["H6086","wood",9,13],["H0784","is, there the fire",14,32],["H3518","goeth out",33,42],["H5372","so where there is no talebearer",44,75],["H4066","the strife",77,87],["H8367","ceaseth",88,95]]},"26:21":{"text":"As coals are to burning coals, and wood to fire; so is a contentious man to kindle strife.","words":[["H6352","As coals",0,8],["H1513","are to burning coals",9,29],["H6086","and wood",31,39],["H0784","to fire",40,47],["H4079","so is a contentious",49,68],["H4066","so is a contentious",49,68],["H0376","man",69,72],["H2787","to kindle",73,82],["H7379","strife",83,89]]},"26:22":{"text":"The words of a talebearer are as wounds, and they go down into the innermost parts of the belly.","words":[["H1697","The words",0,9],["H5372","of a talebearer",10,25],["H3859","are as wounds",26,39],["H3381","and they go down",41,57],["H2315","into the innermost parts",58,82],["H0990","of the belly",83,95]]},"26:23":{"text":"Burning lips and a wicked heart are like a potsherd covered with silver dross.","words":[["H1814","Burning",0,7],["H8193","lips",8,12],["H7451","and a wicked",13,25],["H3820","heart",26,31],["H2789","are like a potsherd",32,51],["H6823","covered",52,59],["H3701","with silver",60,71],["H5509","dross",72,77]]},"26:24":{"text":"He that hateth dissembleth with his lips, and layeth up deceit within him;","words":[["H8130","He that hateth",0,14],["H5234","dissembleth",15,26],["H8193","with his lips",27,40],["H7896","and layeth up",42,55],["H4820","deceit",56,62],["H7130","within",63,69]]},"26:25":{"text":"When he speaketh fair, believe him not: for there are seven abominations in his heart.","words":[["H6963","When he speaketh",0,16],["H2603","fair",17,21],["H0539","believe",23,30],["H7651","him not: for there are seven",31,59],["H8441","abominations",60,72],["H3820","in his heart",73,85]]},"26:26":{"text":"Whose hatred is covered by deceit, his wickedness shall be shewed before the whole congregation.","words":[["H8135","Whose hatred",0,12],["H3680","is covered",13,23],["H4860","by deceit",24,33],["H7451","his wickedness",35,49],["H1540","shall be shewed",50,65],["H6951","before the whole congregation",66,95]]},"26:27":{"text":"Whoso diggeth a pit shall fall therein: and he that rolleth a stone, it will return upon him.","words":[["H3738","Whoso diggeth",0,13],["H7845","a pit",14,19],["H5307","shall fall",20,30],["H1556","therein: and he that rolleth",31,59],["H0068","a stone",60,67],["H7725","it will return",69,83]]},"26:28":{"text":"A lying tongue hateth those that are afflicted by it; and a flattering mouth worketh ruin.","words":[["H8267","A lying",0,7],["H3956","tongue",8,14],["H8130","hateth",15,21],["H1790","those that are afflicted",22,46],["H2509","by it; and a flattering",47,70],["H6310","mouth",71,76],["H6213","worketh",77,84],["H4072","ruin",85,89]]},"27:1":{"text":"Boast not thyself of to morrow; for thou knowest not what a day may bring forth.","words":[["H1984","Boast",0,5],["H4279","not thyself of to morrow",6,30],["H3045","for thou knowest",32,48],["H3117","not what a day",49,63],["H3205","may bring forth",64,79]]},"27:2":{"text":"Let another man praise thee, and not thine own mouth; a stranger, and not thine own lips.","words":[["H2114","Let another man",0,15],["H1984","praise",16,22],["H6310","thee, and not thine own mouth",23,52],["H5237","a stranger",54,64],["H8193","and not thine own lips",66,88]]},"27:3":{"text":"A stone is heavy, and the sand weighty; but a fool's wrath is heavier than them both.","words":[["H0068","A stone",0,7],["H3514","is heavy",8,16],["H2344","and the sand",18,30],["H5192","weighty",31,38],["H0191","but a fool's",40,52],["H3708","wrath",53,58],["H3515","is heavier",59,69],["H8147","than them both",70,84]]},"27:4":{"text":"Wrath is cruel, and anger is outrageous; but who is able to stand before envy?","words":[["H2534","Wrath",0,5],["H0395","is cruel",6,14],["H0639","and anger",16,25],["H7858","is outrageous",26,39],["H5975","but who is able to stand",41,65],["H6440","before",66,72],["H7068","envy",73,77]]},"27:5":{"text":"Open rebuke is better than secret love.","words":[["H1540","Open",0,4],["H8433","rebuke",5,11],["H2896","is better",12,21],["H5641","than secret",22,33],["H0160","love",34,38]]},"27:6":{"text":"Faithful are the wounds of a friend; but the kisses of an enemy are deceitful.","words":[["H0539","Faithful",0,8],["H6482","are the wounds",9,23],["H0157","of a friend",24,35],["H5390","but the kisses",37,51],["H8130","of an enemy",52,63],["H6280","are deceitful",64,77]]},"27:7":{"text":"The full soul loatheth an honeycomb; but to the hungry soul every bitter thing is sweet.","words":[["H7649","The full",0,8],["H5315","soul",9,13],["H0947","loatheth",14,22],["H5317","an honeycomb",23,35],["H7457","but to the hungry",37,54],["H5315","soul",55,59],["H4751","every bitter thing",60,78],["H4966","is sweet",79,87]]},"27:8":{"text":"As a bird that wandereth from her nest, so is a man that wandereth from his place.","words":[["H6833","As a bird",0,9],["H5074","that wandereth",10,24],["H7064","from her nest",25,38],["H0376","so is a man",40,51],["H5074","that wandereth",52,66],["H4725","from his place",67,81]]},"27:9":{"text":"Ointment and perfume rejoice the heart: so doth the sweetness of a man's friend by hearty counsel.","words":[["H8081","Ointment",0,8],["H7004","and perfume",9,20],["H8055","rejoice",21,28],["H3820","the heart",29,38],["H4986","so doth the sweetness",40,61],["H7453","of a man's friend",62,79],["H5315","by hearty",80,89],["H6098","counsel",90,97]]},"27:10":{"text":"Thine own friend, and thy father's friend, forsake not; neither go into thy brother's house in the day of thy calamity: for better is a neighbour that is near than a brother far off.","words":[["H7453","Thine own friend",0,16],["H0001","and thy father's",18,34],["H7453","friend",35,41],["H5800","forsake",43,50],["H0935","not; neither go",51,66],["H0251","into thy brother's",67,85],["H1004","house",86,91],["H3117","in the day",92,102],["H0343","of thy calamity",103,118],["H2896","for better",120,130],["H7934","is a neighbour",131,145],["H7138","that is near",146,158],["H0251","than a brother",159,173],["H7350","far off",174,181]]},"27:11":{"text":"My son, be wise, and make my heart glad, that I may answer him that reproacheth me.","words":[["H1121","My son",0,6],["H2449","be wise",8,15],["H3820","and make my heart",17,34],["H8055","glad",35,39],["H7725","that I may answer",41,58],["H1697","that I may answer",41,58],["H2778","him that reproacheth",59,79]]},"27:12":{"text":"A prudent man foreseeth the evil, and hideth himself; but the simple pass on, and are punished.","words":[["H6175","A prudent",0,9],["H7200","man foreseeth",10,23],["H7451","the evil",24,32],["H5641","and hideth",34,44],["H6612","himself; but the simple",45,68],["H5674","pass on",69,76],["H6064","and are punished",78,94]]},"27:13":{"text":"Take his garment that is surety for a stranger, and take a pledge of him for a strange woman.","words":[["H3947","Take",0,4],["H0899","his garment",5,16],["H6148","that is surety",17,31],["H2114","for a stranger",32,46],["H2254","and take a pledge",48,65],["H5237","of him for a strange woman",66,92]]},"27:14":{"text":"He that blesseth his friend with a loud voice, rising early in the morning, it shall be counted a curse to him.","words":[["H1288","He that blesseth",0,16],["H7453","his friend",17,27],["H1419","with a loud",28,39],["H6963","voice",40,45],["H7925","rising early",47,59],["H1242","in the morning",60,74],["H2803","it shall be counted",76,95],["H7045","a curse",96,103]]},"27:15":{"text":"A continual dropping in a very rainy day and a contentious woman are alike.","words":[["H2956","A continual",0,11],["H1812","dropping",12,20],["H5464","in a very rainy",21,36],["H3117","day",37,40],["H4079","and a contentious",41,58],["H4066","and a contentious",41,58],["H0802","woman",59,64],["H7737","are alike",65,74]]},"27:16":{"text":"Whosoever hideth her hideth the wind, and the ointment of his right hand, which bewrayeth itself.","words":[["H6845","Whosoever hideth",0,16],["H6845","her hideth",17,27],["H7307","the wind",28,36],["H8081","and the ointment",38,54],["H3225","of his right hand",55,72],["H7121","which bewrayeth",74,89]]},"27:17":{"text":"Iron sharpeneth iron; so a man sharpeneth the countenance of his friend.","words":[["H1270","Iron",0,4],["H2300","sharpeneth",5,15],["H1270","iron",16,20],["H0376","so a man",22,30],["H2300","sharpeneth",31,41],["H6440","the countenance",42,57],["H7453","of his friend",58,71]]},"27:18":{"text":"Whoso keepeth the fig tree shall eat the fruit thereof: so he that waiteth on his master shall be honoured.","words":[["H5341","Whoso keepeth",0,13],["H8384","the fig tree",14,26],["H0398","shall eat",27,36],["H6529","the fruit",37,46],["H8104","thereof: so he that waiteth",47,74],["H0113","on his master",75,88],["H3513","shall be honoured",89,106]]},"27:19":{"text":"As in water face answereth to face, so the heart of man to man.","words":[["H4325","As in water",0,11],["H6440","face",12,16],["H6440","answereth to face",17,34],["H3820","so the heart",36,48],["H0120","of man",49,55],["H0120","to man",56,62]]},"27:20":{"text":"Hell and destruction are never full; so the eyes of man are never satisfied.","words":[["H7585","Hell",0,4],["H0011","and destruction",5,20],["H0010","and destruction",5,20],["H3808","are never",21,30],["H7646","full",31,35],["H5869","so the eyes",37,48],["H0120","of man",49,55],["H7646","are never satisfied",56,75]]},"27:21":{"text":"As the fining pot for silver, and the furnace for gold; so is a man to his praise.","words":[["H4715","As the fining pot",0,17],["H3701","for silver",18,28],["H3564","and the furnace",30,45],["H2091","for gold",46,54],["H0376","so is a man",56,67],["H6310","to",68,70],["H4110","his praise",71,81]]},"27:22":{"text":"Though thou shouldest bray a fool in a mortar among wheat with a pestle, yet will not his foolishness depart from him.","words":[["H3806","Though thou shouldest bray",0,26],["H0191","a fool",27,33],["H4388","in a mortar",34,45],["H8432","among",46,51],["H7383","wheat",52,57],["H5940","with a pestle",58,71],["H0200","yet will not his foolishness",73,101],["H5493","depart",102,108]]},"27:23":{"text":"Be thou diligent to know the state of thy flocks, and look well to thy herds.","words":[["H3045","Be thou diligent",0,16],["H3045","to know",17,24],["H6440","the state",25,34],["H6629","of thy flocks",35,48],["H7896","and look",50,58],["H3820","well",59,63],["H5739","to thy herds",64,76]]},"27:24":{"text":"For riches are not for ever: and doth the crown endure to every generation?","words":[["H2633","For riches",0,10],["H5769","are not for ever",11,27],["H5145","and doth the crown",29,47],["H1755","endure to every",48,63],["H1755","generation",64,74]]},"27:25":{"text":"The hay appeareth, and the tender grass sheweth itself, and herbs of the mountains are gathered.","words":[["H2682","The hay",0,7],["H1540","appeareth",8,17],["H1877","and the tender grass",19,39],["H7200","sheweth",40,47],["H6212","itself, and herbs",48,65],["H2022","of the mountains",66,82],["H0622","are gathered",83,95]]},"27:26":{"text":"The lambs are for thy clothing, and the goats are the price of the field.","words":[["H3532","The lambs",0,9],["H3830","are for thy clothing",10,30],["H6260","and the goats",32,45],["H4242","are the price",46,59],["H7704","of the field",60,72]]},"27:27":{"text":"And thou shalt have goats' milk enough for thy food, for the food of thy household, and for the maintenance for thy maidens.","words":[["H5795","And thou shalt have goats'",0,26],["H2461","milk",27,31],["H1767","enough",32,38],["H3899","for thy food",39,51],["H3899","for the food",53,65],["H1004","of thy household",66,82],["H2416","and for the maintenance",84,107],["H5291","for thy maidens",108,123]]},"28:1":{"text":"The wicked flee when no man pursueth: but the righteous are bold as a lion.","words":[["H7563","The wicked",0,10],["H5127","flee",11,15],["H7291","when no man pursueth",16,36],["H6662","but the righteous",38,55],["H0982","are bold",56,64],["H3715","as a lion",65,74]]},"28:2":{"text":"For the transgression of a land many are the princes thereof: but by a man of understanding and knowledge the state thereof shall be prolonged.","words":[["H6588","For the transgression",0,21],["H0776","of a land",22,31],["H7227","many",32,36],["H8269","are the princes",37,52],["H0120","thereof: but by a man",53,74],["H0995","of understanding",75,91],["H3045","and knowledge",92,105],["H3651","the state",106,115],["H0748","thereof shall be prolonged",116,142]]},"28:3":{"text":"A poor man that oppresseth the poor is like a sweeping rain which leaveth no food.","words":[["H7326","A poor",0,6],["H1397","man",7,10],["H6231","that oppresseth",11,26],["H1800","the poor",27,35],["H5502","is like a sweeping",36,54],["H4306","rain",55,59],["H3899","which leaveth no food",60,81]]},"28:4":{"text":"They that forsake the law praise the wicked: but such as keep the law contend with them.","words":[["H5800","They that forsake",0,17],["H8451","the law",18,25],["H1984","praise",26,32],["H7563","the wicked",33,43],["H8104","but such as keep",45,61],["H8451","the law",62,69],["H1624","contend",70,77]]},"28:5":{"text":"Evil men understand not judgment: but they that seek the LORD understand all things.","words":[["H7451","Evil",0,4],["H0582","men",5,8],["H0995","understand",9,19],["H4941","not judgment",20,32],["H1245","but they that seek",34,52],["H3068","the LORD",53,61],["H0995","understand",62,72]]},"28:6":{"text":"Better is the poor that walketh in his uprightness, than he that is perverse in his ways, though he be rich.","words":[["H2896","Better",0,6],["H7326","is the poor",7,18],["H1980","that walketh",19,31],["H8537","in his uprightness",32,50],["H6141","than he that is perverse",52,76],["H1870","in his ways",77,88],["H6223","though he be rich",90,107]]},"28:7":{"text":"Whoso keepeth the law is a wise son: but he that is a companion of riotous men shameth his father.","words":[["H5341","Whoso keepeth",0,13],["H8451","the law",14,21],["H0995","is a wise",22,31],["H1121","son",32,35],["H7462","but he that is a companion",37,63],["H2151","of riotous",64,74],["H3637","men shameth",75,86],["H0001","his father",87,97]]},"28:8":{"text":"He that by usury and unjust gain increaseth his substance, he shall gather it for him that will pity the poor.","words":[["H5392","He that by usury",0,16],["H8636","and unjust gain",17,32],["H7235","increaseth",33,43],["H1952","his substance",44,57],["H6908","he shall gather",59,74],["H2603","it for him that will pity",75,100],["H1800","the poor",101,109]]},"28:9":{"text":"He that turneth away his ear from hearing the law, even his prayer shall be abomination.","words":[["H5493","He that turneth away",0,20],["H0241","his ear",21,28],["H8085","from hearing",29,41],["H8451","the law",42,49],["H8605","even his prayer",51,66],["H8441","shall be abomination",67,87]]},"28:10":{"text":"Whoso causeth the righteous to go astray in an evil way, he shall fall himself into his own pit: but the upright shall have good things in possession.","words":[["H3477","Whoso causeth the righteous",0,27],["H7686","to go astray",28,40],["H7451","in an evil",41,51],["H1870","way",52,55],["H5307","he shall fall",57,70],["H7816","himself into his own pit",71,95],["H8549","but the upright",97,112],["H2896","shall have good",113,128],["H5157","things in possession",129,149]]},"28:11":{"text":"The rich man is wise in his own conceit; but the poor that hath understanding searcheth him out.","words":[["H6223","The rich",0,8],["H0376","man",9,12],["H2450","is wise",13,20],["H5869","in his own conceit",21,39],["H1800","but the poor",41,53],["H0995","that hath understanding",54,77],["H2713","searcheth him out",78,95]]},"28:12":{"text":"When righteous men do rejoice, there is great glory: but when the wicked rise, a man is hidden.","words":[["H6662","When righteous",0,14],["H5970","men do rejoice",15,29],["H7227","there is great",31,45],["H8597","glory",46,51],["H7563","but when the wicked",53,72],["H6965","rise",73,77],["H0120","a man",79,84],["H2664","is hidden",85,94]]},"28:13":{"text":"He that covereth his sins shall not prosper: but whoso confesseth and forsaketh them shall have mercy.","words":[["H3680","He that covereth",0,16],["H6588","his sins",17,25],["H6743","shall not prosper",26,43],["H3034","but whoso confesseth",45,65],["H5800","and forsaketh",66,79],["H7355","them shall have mercy",80,101]]},"28:14":{"text":"Happy is the man that feareth alway: but he that hardeneth his heart shall fall into mischief.","words":[["H0835","Happy",0,5],["H0120","is the man",6,16],["H6342","that feareth",17,29],["H8548","alway",30,35],["H7185","but he that hardeneth",37,58],["H3820","his heart",59,68],["H5307","shall fall",69,79],["H7451","into mischief",80,93]]},"28:15":{"text":"As a roaring lion, and a ranging bear; so is a wicked ruler over the poor people.","words":[["H5098","As a roaring",0,12],["H0738","lion",13,17],["H8264","and a ranging",19,32],["H1677","bear",33,37],["H7563","so is a wicked",39,53],["H4910","ruler",54,59],["H1800","over the poor",60,73],["H5971","people",74,80]]},"28:16":{"text":"The prince that wanteth understanding is also a great oppressor: but he that hateth covetousness shall prolong his days.","words":[["H5057","The prince",0,10],["H2638","that wanteth",11,23],["H8394","understanding",24,37],["H7227","is also a great",38,53],["H4642","oppressor",54,63],["H8130","but he that hateth",65,83],["H1215","covetousness",84,96],["H0748","shall prolong",97,110],["H3117","his days",111,119]]},"28:17":{"text":"A man that doeth violence to the blood of any person shall flee to the pit; let no man stay him.","words":[["H0120","A man",0,5],["H6231","that doeth violence",6,25],["H1818","to the blood",26,38],["H5315","of any person",39,52],["H5127","shall flee",53,63],["H0953","to the pit",64,74],["H8551","let no man stay",76,91]]},"28:18":{"text":"Whoso walketh uprightly shall be saved: but he that is perverse in his ways shall fall at once.","words":[["H1980","Whoso walketh",0,13],["H8549","uprightly",14,23],["H3467","shall be saved",24,38],["H6140","but he that is perverse",40,63],["H1870","in his ways",64,75],["H5307","shall fall",76,86],["H0259","at once",87,94]]},"28:19":{"text":"He that tilleth his land shall have plenty of bread: but he that followeth after vain persons shall have poverty enough.","words":[["H5647","He that tilleth",0,15],["H0127","his land",16,24],["H7646","shall have plenty",25,42],["H3899","of bread",43,51],["H7291","but he that followeth",53,74],["H7386","after vain",75,85],["H7389","persons shall have poverty enough",86,119]]},"28:20":{"text":"A faithful man shall abound with blessings: but he that maketh haste to be rich shall not be innocent.","words":[["H0530","A faithful",0,10],["H0376","man",11,14],["H7227","shall abound",15,27],["H1293","with blessings",28,42],["H0213","but he that maketh haste",44,68],["H6238","to be rich",69,79],["H5352","shall not be innocent",80,101]]},"28:21":{"text":"To have respect of persons is not good: for for a piece of bread that man will transgress.","words":[["H5234","To have respect",0,15],["H6440","of persons",16,26],["H2896","is not good",27,38],["H6595","for for a piece",40,55],["H3899","of bread",56,64],["H1397","that man",65,73],["H6586","will transgress",74,89]]},"28:22":{"text":"He that hasteth to be rich hath an evil eye, and considereth not that poverty shall come upon him.","words":[["H0376","He",0,2],["H0926","that hasteth",3,15],["H1952","to be rich",16,26],["H7451","hath an evil",27,39],["H5869","eye",40,43],["H3045","and considereth",45,60],["H2639","not that poverty",61,77],["H0935","shall come",78,88]]},"28:23":{"text":"He that rebuketh a man afterwards shall find more favour than he that flattereth with the tongue.","words":[["H3198","He that rebuketh",0,16],["H0120","a man",17,22],["H0310","afterwards",23,33],["H4672","shall find",34,44],["H2580","more favour",45,56],["H2505","than he that flattereth",57,80],["H3956","with the tongue",81,96]]},"28:24":{"text":"Whoso robbeth his father or his mother, and saith, It is no transgression; the same is the companion of a destroyer.","words":[["H1497","Whoso robbeth",0,13],["H0001","his father",14,24],["H0517","or his mother",25,38],["H0559","and saith",40,49],["H6588","It is no transgression",51,73],["H2270","the same is the companion",75,100],["H0376","of a destroyer",101,115],["H7843","of a destroyer",101,115]]},"28:25":{"text":"He that is of a proud heart stirreth up strife: but he that putteth his trust in the LORD shall be made fat.","words":[["H7342","He that is of a proud",0,21],["H5315","heart",22,27],["H1624","stirreth up",28,39],["H4066","strife",40,46],["H0982","but he that putteth his trust",48,77],["H3068","in the LORD",78,89],["H1878","shall be made fat",90,107]]},"28:26":{"text":"He that trusteth in his own heart is a fool: but whoso walketh wisely, he shall be delivered.","words":[["H0982","He that trusteth",0,16],["H3820","in his own heart",17,33],["H3684","is a fool",34,43],["H1980","but whoso walketh",45,62],["H2451","wisely",63,69],["H4422","he shall be delivered",71,92]]},"28:27":{"text":"He that giveth unto the poor shall not lack: but he that hideth his eyes shall have many a curse.","words":[["H5414","He that giveth",0,14],["H7326","unto the poor",15,28],["H4270","shall not lack",29,43],["H5956","but he that hideth",45,63],["H5869","his eyes",64,72],["H7227","shall have many",73,88],["H3994","a curse",89,96]]},"28:28":{"text":"When the wicked rise, men hide themselves: but when they perish, the righteous increase.","words":[["H7563","When the wicked",0,15],["H6965","rise",16,20],["H0120","men",22,25],["H5641","hide",26,30],["H0006","themselves: but when they perish",31,63],["H6662","the righteous",65,78],["H7235","increase",79,87]]},"29:1":{"text":"He, that being often reproved hardeneth his neck, shall suddenly be destroyed, and that without remedy.","words":[["H0376","He",0,2],["H8433","that being often reproved",4,29],["H7185","hardeneth",30,39],["H6203","his neck",40,48],["H6621","shall suddenly",50,64],["H7665","be destroyed",65,77],["H4832","and that without remedy",79,102]]},"29:2":{"text":"When the righteous are in authority, the people rejoice: but when the wicked beareth rule, the people mourn.","words":[["H6662","When the righteous",0,18],["H7235","are in authority",19,35],["H5971","the people",37,47],["H8055","rejoice",48,55],["H7563","but when the wicked",57,76],["H4910","beareth rule",77,89],["H5971","the people",91,101],["H0584","mourn",102,107]]},"29:3":{"text":"Whoso loveth wisdom rejoiceth his father: but he that keepeth company with harlots spendeth his substance.","words":[["H0376","Whoso",0,5],["H0157","loveth",6,12],["H2451","wisdom",13,19],["H8055","rejoiceth",20,29],["H0001","his father",30,40],["H7462","but he that keepeth company",42,69],["H2181","with harlots",70,82],["H0006","spendeth",83,91],["H1952","his substance",92,105]]},"29:4":{"text":"The king by judgment establisheth the land: but he that receiveth gifts overthroweth it.","words":[["H4428","The king",0,8],["H4941","by judgment",9,20],["H5975","establisheth",21,33],["H0776","the land",34,42],["H0376","but he",44,50],["H8641","that receiveth gifts",51,71],["H2040","overthroweth",72,84]]},"29:5":{"text":"A man that flattereth his neighbour spreadeth a net for his feet.","words":[["H1397","A man",0,5],["H2505","that flattereth",6,21],["H7453","his neighbour",22,35],["H6566","spreadeth",36,45],["H7568","a net",46,51],["H6471","for his feet",52,64]]},"29:6":{"text":"In the transgression of an evil man there is a snare: but the righteous doth sing and rejoice.","words":[["H6588","In the transgression",0,20],["H7451","of an evil",21,31],["H0376","man",32,35],["H4170","there is a snare",36,52],["H6662","but the righteous",54,71],["H7442","doth sing",72,81],["H8056","and rejoice",82,93]]},"29:7":{"text":"The righteous considereth the cause of the poor: but the wicked regardeth not to know it.","words":[["H6662","The righteous",0,13],["H3045","considereth",14,25],["H1779","the cause",26,35],["H1800","of the poor",36,47],["H7563","but the wicked",49,63],["H0995","regardeth",64,73],["H1847","not to know",74,85]]},"29:8":{"text":"Scornful men bring a city into a snare: but wise men turn away wrath.","words":[["H3944","Scornful",0,8],["H0582","men",9,12],["H6315","bring",13,18],["H7151","a city",19,25],["H6315","into a snare",26,38],["H2450","but wise",40,48],["H7725","men turn away",49,62],["H0639","wrath",63,68]]},"29:9":{"text":"If a wise man contendeth with a foolish man, whether he rage or laugh, there is no rest.","words":[["H2450","If a wise",0,9],["H0376","man",10,13],["H8199","contendeth",14,24],["H0191","with a foolish",25,39],["H0376","man",40,43],["H7264","whether he rage",45,60],["H7832","or laugh",61,69],["H5183","there is no rest",71,87]]},"29:10":{"text":"The bloodthirsty hate the upright: but the just seek his soul.","words":[["H0582","The bloodthirsty",0,16],["H1818","The bloodthirsty",0,16],["H8130","hate",17,21],["H8535","the upright",22,33],["H3477","but the just",35,47],["H1245","seek",48,52],["H5315","his soul",53,61]]},"29:11":{"text":"A fool uttereth all his mind: but a wise man keepeth it in till afterwards.","words":[["H3684","A fool",0,6],["H3318","uttereth",7,15],["H7307","all his mind",16,28],["H2450","but a wise",30,40],["H7623","man keepeth",41,52],["H0268","it in till afterwards",53,74]]},"29:12":{"text":"If a ruler hearken to lies, all his servants are wicked.","words":[["H4910","If a ruler",0,10],["H7181","hearken",11,18],["H1697","to lies",19,26],["H8267","to lies",19,26],["H8334","all his servants",28,44],["H7563","are wicked",45,55]]},"29:13":{"text":"The poor and the deceitful man meet together: the LORD lighteneth both their eyes.","words":[["H7326","The poor",0,8],["H8501","and the deceitful",9,26],["H0376","man",27,30],["H6298","meet together",31,44],["H3068","the LORD",46,54],["H0215","lighteneth",55,65],["H8147","both",66,70],["H5869","their eyes",71,81]]},"29:14":{"text":"The king that faithfully judgeth the poor, his throne shall be established for ever.","words":[["H4428","The king",0,8],["H0571","that faithfully",9,24],["H8199","judgeth",25,32],["H1800","the poor",33,41],["H3678","his throne",43,53],["H3559","shall be established",54,74],["H5703","for ever",75,83]]},"29:15":{"text":"The rod and reproof give wisdom: but a child left to himself bringeth his mother to shame.","words":[["H7626","The rod",0,7],["H8433","and reproof",8,19],["H5414","give",20,24],["H2451","wisdom",25,31],["H5288","but a child",33,44],["H7971","left",45,49],["H0517","to himself bringeth his mother",50,80],["H0954","to shame",81,89]]},"29:16":{"text":"When the wicked are multiplied, transgression increaseth: but the righteous shall see their fall.","words":[["H7563","When the wicked",0,15],["H7235","are multiplied",16,30],["H6588","transgression",32,45],["H7235","increaseth",46,56],["H6662","but the righteous",58,75],["H7200","shall see",76,85],["H4658","their fall",86,96]]},"29:17":{"text":"Correct thy son, and he shall give thee rest; yea, he shall give delight unto thy soul.","words":[["H3256","Correct",0,7],["H1121","thy son",8,15],["H5117","and he shall give thee rest",17,44],["H5414","yea, he shall give",46,64],["H4574","delight",65,72],["H5315","unto thy soul",73,86]]},"29:18":{"text":"Where there is no vision, the people perish: but he that keepeth the law, happy is he.","words":[["H2377","Where there is no vision",0,24],["H5971","the people",26,36],["H6544","perish",37,43],["H8104","but he that keepeth",45,64],["H8451","the law",65,72],["H0835","happy",74,79]]},"29:19":{"text":"A servant will not be corrected by words: for though he understand he will not answer.","words":[["H5650","A servant",0,9],["H3256","will not be corrected",10,31],["H1697","by words",32,40],["H0995","for though he understand",42,66],["H4617","he will not answer",67,85]]},"29:20":{"text":"Seest thou a man that is hasty in his words? there is more hope of a fool than of him.","words":[["H2372","Seest",0,5],["H0376","thou a man",6,16],["H0213","that is hasty",17,30],["H1697","in his words",31,43],["H8615","there is more hope",45,63],["H3684","of a fool",64,73]]},"29:21":{"text":"He that delicately bringeth up his servant from a child shall have him become his son at the length.","words":[["H6445","He that delicately bringeth up",0,30],["H5650","his servant",31,42],["H5290","from a child",43,55],["H4497","shall have him become his son",56,85],["H0319","at the length",86,99]]},"29:22":{"text":"An angry man stirreth up strife, and a furious man aboundeth in transgression.","words":[["H0639","An angry",0,8],["H0376","man",9,12],["H1624","stirreth up",13,24],["H4066","strife",25,31],["H2534","and a furious",33,46],["H1167","man",47,50],["H7227","aboundeth in",51,63],["H6588","transgression",64,77]]},"29:23":{"text":"A man's pride shall bring him low: but honour shall uphold the humble in spirit.","words":[["H0120","A man's",0,7],["H1346","pride",8,13],["H8213","shall bring him low",14,33],["H3519","but honour",35,45],["H8551","shall uphold",46,58],["H8217","the humble",59,69],["H7307","in spirit",70,79]]},"29:24":{"text":"Whoso is partner with a thief hateth his own soul: he heareth cursing, and bewrayeth it not.","words":[["H2505","Whoso is partner",0,16],["H1590","with a thief",17,29],["H8130","hateth",30,36],["H5315","his own soul",37,49],["H8085","he heareth",51,61],["H0423","cursing",62,69],["H5046","and bewrayeth",71,84]]},"29:25":{"text":"The fear of man bringeth a snare: but whoso putteth his trust in the LORD shall be safe.","words":[["H2731","The fear",0,8],["H0120","of man",9,15],["H5414","bringeth",16,24],["H4170","a snare",25,32],["H0982","but whoso putteth his trust",34,61],["H3068","in the LORD",62,73],["H7682","shall be safe",74,87]]},"29:26":{"text":"Many seek the ruler's favour; but every man's judgment cometh from the LORD.","words":[["H7227","Many",0,4],["H1245","seek",5,9],["H4910","the ruler's",10,21],["H6440","favour",22,28],["H0376","but every man's",30,45],["H4941","judgment",46,54],["H3068","cometh from the LORD",55,75]]},"29:27":{"text":"An unjust man is an abomination to the just: and he that is upright in the way is abomination to the wicked.","words":[["H5766","An unjust",0,9],["H0376","man",10,13],["H8441","is an abomination",14,31],["H6662","to the just",32,43],["H3477","and he that is upright",45,67],["H1870","in the way",68,78],["H8441","is abomination",79,93],["H7563","to the wicked",94,107]]},"30:1":{"text":"The words of Agur the son of Jakeh, even the prophecy: the man spake unto Ithiel, even unto Ithiel and Ucal,","words":[["H1697","The words",0,9],["H0094","of Agur",10,17],["H1121","the son",18,25],["H3348","of Jakeh",26,34],["H4853","even the prophecy",36,53],["H1397","the man",55,62],["H5002","spake",63,68],["H0384","unto Ithiel",69,80],["H0384","even unto Ithiel",82,98],["H0401","and Ucal",99,107]]},"30:2":{"text":"Surely I am more brutish than any man, and have not the understanding of a man.","words":[["H1198","Surely I am more brutish",0,24],["H0376","than any man",25,37],["H0998","and have not the understanding",39,69],["H0120","of a man",70,78]]},"30:3":{"text":"I neither learned wisdom, nor have the knowledge of the holy.","words":[["H3925","I neither learned",0,17],["H2451","wisdom",18,24],["H3045","nor have",26,34],["H1847","the knowledge",35,48],["H6918","of the holy",49,60]]},"30:4":{"text":"Who hath ascended up into heaven, or descended? who hath gathered the wind in his fists? who hath bound the waters in a garment? who hath established all the ends of the earth? what is his name, and what is his son's name, if thou canst tell?","words":[["H5927","Who hath ascended up",0,20],["H8064","into heaven",21,32],["H3381","or descended",34,46],["H0622","who hath gathered",48,65],["H7307","the wind",66,74],["H2651","in his fists",75,87],["H6887","who hath bound",89,103],["H4325","the waters",104,114],["H8071","in a garment",115,127],["H6965","who hath established",129,149],["H0657","all the ends",150,162],["H0776","of the earth",163,175],["H8034","what is his name",177,193],["H1121","and what is his son's",195,216],["H8034","name",217,221],["H3045","if thou canst tell",223,241]]},"30:5":{"text":"Every word of God is pure: he is a shield unto them that put their trust in him.","words":[["H0565","Every word",0,10],["H0433","of God",11,17],["H6884","is pure",18,25],["H4043","he is a shield",27,41],["H2620","unto them that put their trust",42,72]]},"30:6":{"text":"Add thou not unto his words, lest he reprove thee, and thou be found a liar.","words":[["H3254","Add",0,3],["H1697","thou not unto his words",4,27],["H3198","lest he reprove",29,44],["H3576","thee, and thou be found a liar",45,75]]},"30:7":{"text":"Two things have I required of thee; deny me them not before I die:","words":[["H8147","Two",0,3],["H7592","things have I required",4,26],["H4513","of thee; deny",27,40],["H4191","me them not before I die",41,65]]},"30:8":{"text":"Remove far from me vanity and lies: give me neither poverty nor riches; feed me with food convenient for me:","words":[["H7368","Remove far",0,10],["H7723","from me vanity",11,25],["H1697","and lies",26,34],["H3577","and lies",26,34],["H5414","give",36,40],["H7389","me neither poverty",41,59],["H6239","nor riches",60,70],["H2963","feed",72,76],["H3899","me with food",77,89],["H2706","convenient",90,100]]},"30:9":{"text":"Lest I be full, and deny thee, and say, Who is the LORD? or lest I be poor, and steal, and take the name of my God in vain.","words":[["H7646","Lest I be full",0,14],["H3584","and deny",16,24],["H0559","thee, and say",25,38],["H3068","Who is the LORD",40,55],["H3423","or lest I be poor",57,74],["H1589","and steal",76,85],["H8610","and take",87,95],["H8034","the name",96,104],["H0430","of my God",105,114]]},"30:10":{"text":"Accuse not a servant unto his master, lest he curse thee, and thou be found guilty.","words":[["H3960","Accuse",0,6],["H5650","not a servant",7,20],["H0113","unto his master",21,36],["H7043","lest he curse",38,51],["H0816","thee, and thou be found guilty",52,82]]},"30:11":{"text":"There is a generation that curseth their father, and doth not bless their mother.","words":[["H1755","There is a generation",0,21],["H7043","that curseth",22,34],["H0001","their father",35,47],["H1288","and doth not bless",49,67],["H0517","their mother",68,80]]},"30:12":{"text":"There is a generation that are pure in their own eyes, and yet is not washed from their filthiness.","words":[["H1755","There is a generation",0,21],["H2889","that are pure",22,35],["H5869","in their own eyes",36,53],["H7364","and yet is not washed",55,76],["H6675","from their filthiness",77,98]]},"30:13":{"text":"There is a generation, O how lofty are their eyes! and their eyelids are lifted up.","words":[["H1755","There is a generation",0,21],["H7311","O how lofty",23,34],["H5869","are their eyes",35,49],["H6079","and their eyelids",51,68],["H5375","are lifted up",69,82]]},"30:14":{"text":"There is a generation, whose teeth are as swords, and their jaw teeth as knives, to devour the poor from off the earth, and the needy from among men.","words":[["H1755","There is a generation",0,21],["H8127","whose teeth",23,34],["H2719","are as swords",35,48],["H4973","and their jaw teeth",50,69],["H3979","as knives",70,79],["H0398","to devour",81,90],["H6041","the poor",91,99],["H0776","from off the earth",100,118],["H0034","and the needy",120,133],["H0120","from among men",134,148]]},"30:15":{"text":"The horseleach hath two daughters, crying, Give, give. There are three things that are never satisfied, yea, four things say not, It is enough:","words":[["H5936","The horseleach",0,14],["H8147","hath two",15,23],["H1323","daughters",24,33],["H3051","crying, Give",35,47],["H3051","give",49,53],["H7969","There are three",55,70],["H7646","things that are never satisfied",71,102],["H0702","yea, four",104,113],["H0559","things say",114,124],["H1952","not, It is enough",125,142]]},"30:16":{"text":"The grave; and the barren womb; the earth that is not filled with water; and the fire that saith not, It is enough.","words":[["H7585","The grave",0,9],["H6115","and the barren",11,25],["H7356","womb",26,30],["H0776","the earth",32,41],["H7646","that is not filled",42,60],["H4325","with water",61,71],["H0784","and the fire",73,85],["H0559","that saith",86,96],["H1952","not, It is enough",97,114]]},"30:17":{"text":"The eye that mocketh at his father, and despiseth to obey his mother, the ravens of the valley shall pick it out, and the young eagles shall eat it.","words":[["H5869","The eye",0,7],["H3932","that mocketh",8,20],["H0001","at his father",21,34],["H0936","and despiseth",36,49],["H3349","to obey",50,57],["H0517","his mother",58,68],["H6158","the ravens",70,80],["H5158","of the valley",81,94],["H5365","shall pick it out",95,112],["H1121","and the young",114,127],["H5404","eagles",128,134],["H0398","shall eat",135,144]]},"30:18":{"text":"There be three things which are too wonderful for me, yea, four which I know not:","words":[["H7969","There be three",0,14],["H6381","things which are too wonderful",15,45],["H0702","for me, yea, four",46,63],["H3045","which I know",64,76]]},"30:19":{"text":"The way of an eagle in the air; the way of a serpent upon a rock; the way of a ship in the midst of the sea; and the way of a man with a maid.","words":[["H1870","The way",0,7],["H5404","of an eagle",8,19],["H8064","in the air",20,30],["H1870","the way",32,39],["H5175","of a serpent",40,52],["H6697","upon a rock",53,64],["H1870","the way",66,73],["H0591","of a ship",74,83],["H3820","in the midst",84,96],["H3220","of the sea",97,107],["H1870","and the way",109,120],["H1397","of a man",121,129],["H5959","with a maid",130,141]]},"30:20":{"text":"Such is the way of an adulterous woman; she eateth, and wipeth her mouth, and saith, I have done no wickedness.","words":[["H1870","Such is the way",0,15],["H5003","of an adulterous",16,32],["H0802","woman",33,38],["H0398","she eateth",40,50],["H4229","and wipeth",52,62],["H6310","her mouth",63,72],["H0559","and saith",74,83],["H6466","I have done",85,96],["H0205","no wickedness",97,110]]},"30:21":{"text":"For three things the earth is disquieted, and for four which it cannot bear:","words":[["H7969","For three",0,9],["H0776","things the earth",10,26],["H7264","is disquieted",27,40],["H0702","and for four",42,54],["H3201","which it cannot",55,70],["H5375","bear",71,75]]},"30:22":{"text":"For a servant when he reigneth; and a fool when he is filled with meat;","words":[["H5650","For a servant",0,13],["H4427","when he reigneth",14,30],["H5036","and a fool",32,42],["H7646","when he is filled",43,60],["H3899","with meat",61,70]]},"30:23":{"text":"For an odious woman when she is married; and an handmaid that is heir to her mistress.","words":[["H8130","For an odious",0,13],["H1166","woman when she is married",14,39],["H8198","and an handmaid",41,56],["H3423","that is heir",57,69],["H1404","to her mistress",70,85]]},"30:24":{"text":"There be four things which are little upon the earth, but they are exceeding wise:","words":[["H0702","There be four",0,13],["H6996","things which are little",14,37],["H0776","upon the earth",38,52],["H2449","but they are exceeding",54,76],["H2450","wise",77,81]]},"30:25":{"text":"The ants are a people not strong, yet they prepare their meat in the summer;","words":[["H5244","The ants",0,8],["H5971","are a people",9,21],["H5794","not strong",22,32],["H3559","yet they prepare",34,50],["H3899","their meat",51,61],["H7019","in the summer",62,75]]},"30:26":{"text":"The conies are but a feeble folk, yet make they their houses in the rocks;","words":[["H8227","The conies",0,10],["H6099","are but a feeble",11,27],["H5971","folk",28,32],["H7760","yet make",34,42],["H1004","they their houses",43,60],["H5553","in the rocks",61,73]]},"30:27":{"text":"The locusts have no king, yet go they forth all of them by bands;","words":[["H0697","The locusts",0,11],["H4428","have no king",12,24],["H3318","yet go they forth",26,43],["H2686","all of them by bands",44,64]]},"30:28":{"text":"The spider taketh hold with her hands, and is in kings' palaces.","words":[["H8079","The spider",0,10],["H8610","taketh hold",11,22],["H3027","with her hands",23,37],["H4428","and is in kings'",39,55],["H1964","palaces",56,63]]},"30:29":{"text":"There be three things which go well, yea, four are comely in going:","words":[["H7969","There be three",0,14],["H6806","things which go",15,30],["H3190","well",31,35],["H0702","yea, four",37,46],["H2895","are comely",47,57],["H3212","in going",58,66]]},"30:30":{"text":"A lion which is strongest among beasts, and turneth not away for any;","words":[["H3918","A lion",0,6],["H1368","which is strongest",7,25],["H0929","among beasts",26,38],["H7725","and turneth not away",40,60],["H6440","for",61,64]]},"30:31":{"text":"A greyhound; an he goat also; and a king, against whom there is no rising up.","words":[["H4975","A greyhound",0,11],["H2223","A greyhound",0,11],["H8495","an he goat",13,23],["H0176","also",24,28],["H4428","and a king",30,40],["H0510","against whom there is no rising up",42,76]]},"30:32":{"text":"If thou hast done foolishly in lifting up thyself, or if thou hast thought evil, lay thine hand upon thy mouth.","words":[["H5034","If thou hast done foolishly",0,27],["H5375","in lifting up",28,41],["H2161","thyself, or if thou hast thought evil",42,79],["H3027","lay thine hand",81,95],["H6310","upon thy mouth",96,110]]},"30:33":{"text":"Surely the churning of milk bringeth forth butter, and the wringing of the nose bringeth forth blood: so the forcing of wrath bringeth forth strife.","words":[["H4330","Surely the churning",0,19],["H2461","of milk",20,27],["H3318","bringeth forth",28,42],["H2529","butter",43,49],["H4330","and the wringing",51,67],["H0639","of the nose",68,79],["H3318","bringeth forth",80,94],["H1818","blood",95,100],["H4330","so the forcing",102,116],["H0639","of wrath",117,125],["H3318","bringeth forth",126,140],["H7379","strife",141,147]]},"31:1":{"text":"The words of king Lemuel, the prophecy that his mother taught him.","words":[["H1697","The words",0,9],["H4428","of king",10,17],["H3927","Lemuel",18,24],["H4853","the prophecy",26,38],["H0517","that his mother",39,54],["H3256","taught",55,61]]},"31:2":{"text":"What, my son? and what, the son of my womb? and what, the son of my vows?","words":[["H1248","What, my son",0,12],["H1248","and what, the son",14,31],["H0990","of my womb",32,42],["H1248","and what, the son",44,61],["H5088","of my vows",62,72]]},"31:3":{"text":"Give not thy strength unto women, nor thy ways to that which destroyeth kings.","words":[["H5414","Give",0,4],["H2428","not thy strength",5,21],["H0802","unto women",22,32],["H1870","nor thy ways",34,46],["H4229","to that which destroyeth",47,71],["H4428","kings",72,77]]},"31:4":{"text":"It is not for kings, O Lemuel, it is not for kings to drink wine; nor for princes strong drink:","words":[["H4428","It is not for kings",0,19],["H3927","O Lemuel",21,29],["H4428","it is not for kings",31,50],["H8354","to drink",51,59],["H3196","wine",60,64],["H0335","nor for",66,73],["H0176","nor for",66,73],["H7336","princes",74,81],["H7941","strong drink",82,94]]},"31:5":{"text":"Lest they drink, and forget the law, and pervert the judgment of any of the afflicted.","words":[["H8354","Lest they drink",0,15],["H7911","and forget",17,27],["H2710","the law",28,35],["H8138","and pervert",37,48],["H1779","the judgment",49,61],["H1121","of any of the afflicted",62,85],["H6040","of any of the afflicted",62,85]]},"31:6":{"text":"Give strong drink unto him that is ready to perish, and wine unto those that be of heavy hearts.","words":[["H5414","Give",0,4],["H7941","strong drink",5,17],["H0006","unto him that is ready to perish",18,50],["H3196","and wine",52,60],["H4751","unto those that be of heavy",61,88],["H5315","hearts",89,95]]},"31:7":{"text":"Let him drink, and forget his poverty, and remember his misery no more.","words":[["H8354","Let him drink",0,13],["H7911","and forget",15,25],["H7389","his poverty",26,37],["H2142","and remember",39,51],["H5999","his misery",52,62]]},"31:8":{"text":"Open thy mouth for the dumb in the cause of all such as are appointed to destruction.","words":[["H6605","Open",0,4],["H6310","thy mouth",5,14],["H0483","for the dumb",15,27],["H1779","in the cause",28,40],["H1121","of all such as are appointed",41,69],["H2475","to destruction",70,84]]},"31:9":{"text":"Open thy mouth, judge righteously, and plead the cause of the poor and needy.","words":[["H6605","Open",0,4],["H6310","thy mouth",5,14],["H8199","judge",16,21],["H6664","righteously",22,33],["H1777","and plead",35,44],["H6041","the cause of the poor",45,66],["H0034","and needy",67,76]]},"31:10":{"text":"Who can find a virtuous woman? for her price is far above rubies.","words":[["H4672","Who can find",0,12],["H2428","a virtuous",13,23],["H0802","woman",24,29],["H4377","for her price",31,44],["H7350","is far",45,51],["H6443","above rubies",52,64]]},"31:11":{"text":"The heart of her husband doth safely trust in her, so that he shall have no need of spoil.","words":[["H3820","The heart",0,9],["H1167","of her husband",10,24],["H0982","doth safely trust",25,42],["H2637","in her, so that he shall have no need",43,80],["H7998","of spoil",81,89]]},"31:12":{"text":"She will do him good and not evil all the days of her life.","words":[["H1580","She will do",0,11],["H2896","him good",12,20],["H7451","and not evil",21,33],["H3117","all the days",34,46],["H2416","of her life",47,58]]},"31:13":{"text":"She seeketh wool, and flax, and worketh willingly with her hands.","words":[["H1875","She seeketh",0,11],["H6785","wool",12,16],["H6593","and flax",18,26],["H6213","and worketh",28,39],["H2656","willingly",40,49],["H3709","with her hands",50,64]]},"31:14":{"text":"She is like the merchants' ships; she bringeth her food from afar.","words":[["H5503","She is like the merchants'",0,26],["H0591","ships",27,32],["H0935","she bringeth",34,46],["H3899","her food",47,55],["H4801","from afar",56,65]]},"31:15":{"text":"She riseth also while it is yet night, and giveth meat to her household, and a portion to her maidens.","words":[["H6965","She riseth",0,10],["H3915","also while it is yet night",11,37],["H5414","and giveth",39,49],["H2964","meat",50,54],["H1004","to her household",55,71],["H2706","and a portion",73,86],["H5291","to her maidens",87,101]]},"31:16":{"text":"She considereth a field, and buyeth it: with the fruit of her hands she planteth a vineyard.","words":[["H2161","She considereth",0,15],["H7704","a field",16,23],["H3947","and buyeth",25,35],["H6529","it: with the fruit",36,54],["H3709","of her hands",55,67],["H5193","she planteth",68,80],["H3754","a vineyard",81,91]]},"31:17":{"text":"She girdeth her loins with strength, and strengtheneth her arms.","words":[["H2296","She girdeth",0,11],["H4975","her loins",12,21],["H5797","with strength",22,35],["H0553","and strengtheneth",37,54],["H2220","her arms",55,63]]},"31:18":{"text":"She perceiveth that her merchandise is good: her candle goeth not out by night.","words":[["H2938","She perceiveth",0,14],["H5504","that her merchandise",15,35],["H2896","is good",36,43],["H5216","her candle",45,55],["H3518","goeth not out",56,69],["H3915","by night",70,78]]},"31:19":{"text":"She layeth her hands to the spindle, and her hands hold the distaff.","words":[["H7971","She layeth",0,10],["H3027","her hands",11,20],["H3601","to the spindle",21,35],["H3709","and her hands",37,50],["H8551","hold",51,55],["H6418","the distaff",56,67]]},"31:20":{"text":"She stretcheth out her hand to the poor; yea, she reacheth forth her hands to the needy.","words":[["H6566","She stretcheth out",0,18],["H3709","her hand",19,27],["H6041","to the poor",28,39],["H7971","yea, she reacheth forth",41,64],["H3027","her hands",65,74],["H0034","to the needy",75,87]]},"31:21":{"text":"She is not afraid of the snow for her household: for all her household are clothed with scarlet.","words":[["H3372","She is not afraid",0,17],["H7950","of the snow",18,29],["H1004","for her household",30,47],["H1004","for all her household",49,70],["H3847","are clothed",71,82],["H8144","with scarlet",83,95]]},"31:22":{"text":"She maketh herself coverings of tapestry; her clothing is silk and purple.","words":[["H6213","She maketh",0,10],["H4765","herself coverings of tapestry",11,40],["H3830","her clothing",42,54],["H8336","is silk",55,62],["H0713","and purple",63,73]]},"31:23":{"text":"Her husband is known in the gates, when he sitteth among the elders of the land.","words":[["H1167","Her husband",0,11],["H3045","is known",12,20],["H8179","in the gates",21,33],["H3427","when he sitteth",35,50],["H2205","among the elders",51,67],["H0776","of the land",68,79]]},"31:24":{"text":"She maketh fine linen, and selleth it; and delivereth girdles unto the merchant.","words":[["H6213","She maketh",0,10],["H5466","fine linen",11,21],["H4376","and selleth",23,34],["H5414","it; and delivereth",35,53],["H2289","girdles",54,61],["H3669","unto the merchant",62,79]]},"31:25":{"text":"Strength and honour are her clothing; and she shall rejoice in time to come.","words":[["H5797","Strength",0,8],["H1926","and honour",9,19],["H3830","are her clothing",20,36],["H7832","and she shall rejoice",38,59],["H3117","in time",60,67],["H0314","to come",68,75]]},"31:26":{"text":"She openeth her mouth with wisdom; and in her tongue is the law of kindness.","words":[["H6605","She openeth",0,11],["H6310","her mouth",12,21],["H2451","with wisdom",22,33],["H3956","and in her tongue",35,52],["H8451","is the law",53,63],["H2617","of kindness",64,75]]},"31:27":{"text":"She looketh well to the ways of her household, and eateth not the bread of idleness.","words":[["H6822","She looketh well",0,16],["H1979","to the ways",17,28],["H1979","to the ways",17,28],["H1004","of her household",29,45],["H0398","and eateth",47,57],["H3899","not the bread",58,71],["H6104","of idleness",72,83]]},"31:28":{"text":"Her children arise up, and call her blessed; her husband also, and he praiseth her.","words":[["H1121","Her children",0,12],["H6965","arise up",13,21],["H0833","and call her blessed",23,43],["H1167","her husband",45,56],["H1984","also, and he praiseth",57,78]]},"31:29":{"text":"Many daughters have done virtuously, but thou excellest them all.","words":[["H7227","Many",0,4],["H1323","daughters",5,14],["H6213","have done",15,24],["H2428","virtuously",25,35],["H5927","but thou excellest",37,55]]},"31:30":{"text":"Favour is deceitful, and beauty is vain: but a woman that feareth the LORD, she shall be praised.","words":[["H2580","Favour",0,6],["H8267","is deceitful",7,19],["H3308","and beauty",21,31],["H1892","is vain",32,39],["H0802","but a woman",41,52],["H3373","that feareth",53,65],["H3068","the LORD",66,74],["H1984","she shall be praised",76,96]]},"31:31":{"text":"Give her of the fruit of her hands; and let her own works praise her in the gates.","words":[["H5414","Give",0,4],["H6529","her of the fruit",5,21],["H3027","of her hands",22,34],["H4639","and let her own works",36,57],["H1984","praise",58,64],["H8179","her in the gates",65,81]]}}};
